export const skillContent: Record<string, string> = {
  "agent-browser": "<h2>agent-browser</h2>\n<p>Fast browser automation CLI for AI agents. Chrome/Chromium via CDP with\naccessibility-tree snapshots and compact <code>@eN</code> element refs.</p>\n<p>Install: <code>npm i -g agent-browser &amp;&amp; agent-browser install</code></p>\n<h3>Start here</h3>\n<p>This file is a discovery stub, not the usage guide. Before running any\n<code>agent-browser</code> command, load the actual workflow content from the CLI:</p>\n<pre><code class=\"language-bash\">agent-browser skills get core             # start here — workflows, common patterns, troubleshooting\nagent-browser skills get core --full      # include full command reference and templates\n</code></pre>\n<p>The CLI serves skill content that always matches the installed version,\nso instructions never go stale. The content in this stub cannot change\nbetween releases, which is why it just points at <code>skills get core</code>.</p>\n<h3>Specialized skills</h3>\n<p>Load a specialized skill when the task falls outside browser web pages:</p>\n<pre><code class=\"language-bash\">agent-browser skills get electron          # Electron desktop apps (VS Code, Slack, Discord, Figma, ...)\nagent-browser skills get slack             # Slack workspace automation\nagent-browser skills get dogfood           # Exploratory testing / QA / bug hunts\nagent-browser skills get vercel-sandbox    # agent-browser inside Vercel Sandbox microVMs\nagent-browser skills get agentcore         # AWS Bedrock AgentCore cloud browsers\n</code></pre>\n<p>Run <code>agent-browser skills list</code> to see everything available on the\ninstalled version.</p>\n<h3>Why agent-browser</h3>\n<ul>\n<li>Fast native Rust CLI, not a Node.js wrapper</li>\n<li>Works with any AI agent (Cursor, Claude Code, Codex, Continue, Windsurf, etc.)</li>\n<li>Chrome/Chromium via CDP with no Playwright or Puppeteer dependency</li>\n<li>Accessibility-tree snapshots with element refs for reliable interaction</li>\n<li>Sessions, authentication vault, state persistence, video recording</li>\n<li>Specialized skills for Electron apps, Slack, exploratory testing, cloud providers</li>\n</ul>\n<h3>Observability Dashboard</h3>\n<p>The dashboard runs independently of browser sessions on port 4848 and can also be opened through a proxied or forwarded URL such as <code>https://dashboard.agent-browser.localhost</code>. Agents should stay on the dashboard origin: session tabs, status, and stream traffic are proxied internally, so session ports do not need to be exposed.</p>\n",
  "agent-dump": "<h2>Agent Dump</h2>\n<p>使用本技能时，始终通过 <code>agent-dump</code> CLI 完成会话查询与导出，不改动业务源码。</p>\n<h3>安装与运行入口</h3>\n<p>按“尽量不改环境”的顺序选择入口：</p>\n<ol>\n<li>已存在本地命令时直接使用</li>\n</ol>\n<ul>\n<li>适用于用户明确说已全局安装，或当前环境已确认存在 <code>agent-dump</code>。</li>\n<li>示例：<code>agent-dump --help</code></li>\n</ul>\n<ol start=\"2\">\n<li>免安装直跑</li>\n</ol>\n<ul>\n<li>适用于只想临时运行一次，或用户明确说不想装 Python。</li>\n<li>优先使用 <code>bunx @agent-dump/cli</code> 或 <code>npx @agent-dump/cli</code>。</li>\n<li>示例：<code>bunx @agent-dump/cli --help</code></li>\n<li>示例：<code>npx @agent-dump/cli --help</code></li>\n</ul>\n<ol start=\"3\">\n<li>持久安装</li>\n</ol>\n<ul>\n<li>适用于用户明确要长期直接运行 <code>agent-dump</code>。</li>\n<li>只在 skill 中说明支持全局安装；具体安装命令优先参考仓库 README，或在用户明确要求安装时再给出。</li>\n</ul>\n<h3>环境不确定时的处理规则</h3>\n<ul>\n<li>如果用户已经指定运行方式，直接遵循，不要替换成别的入口。</li>\n<li>如果环境不明确，先做低成本检查，按以下顺序判断可用入口：<code>agent-dump</code>、<code>bunx</code>、<code>npx</code>、<code>uv</code> / <code>uvx</code>。</li>\n<li>只要确认某个入口可用，就按该入口组装后续命令。</li>\n<li>如果无法安全判断是否允许联网拉包、是否应做全局安装、或用户偏好 Python 体系还是 Node/Bun 体系，先向用户确认，不要自行假设。</li>\n<li>默认偏好：已存在 <code>agent-dump</code> 时优先复用；只是临时执行一次时优先 <code>bunx @agent-dump/cli</code> 或 <code>npx @agent-dump/cli</code>；用户明确要长期直接运行 <code>agent-dump</code> 时再走安装路径。</li>\n</ul>\n<h3>执行工作流</h3>\n<ol>\n<li>识别任务模式</li>\n</ol>\n<ul>\n<li>用户给了 <code>opencode://...</code>、<code>codex://...</code>、<code>kimi://...</code>、<code>claude://...</code>、<code>cursor://...</code> 这类 URI：使用 URI 模式。</li>\n<li>用户给了 <code>agents://&lt;path&gt;?q=...&amp;providers=...</code>：使用路径作用域查询，可配合 list、interactive 或 collect。</li>\n<li>用户给了 <code>--collect</code>：使用 collect 模式（按时间范围收集并调用 AI 总结）。</li>\n<li>用户给了 <code>--stats</code>：使用 statistics 模式（显示最近 N 天的会话使用统计）。</li>\n<li>用户给了 <code>--search</code>：使用 search 模式（本地 SQLite FTS5 全文搜索）。可与 <code>--list</code> 组合使用。</li>\n<li>用户给了 <code>--config view</code> 或 <code>--config edit</code>：使用 config 模式。</li>\n<li>用户要”先看列表/筛选”：使用 <code>--list</code> 模式。</li>\n<li>用户要”交互式勾选后导出”：使用 <code>--interactive</code> 模式。</li>\n<li>用户只给 <code>-days</code> 或 <code>-query</code> 且未指定 <code>--interactive</code>：按列表模式处理（CLI 会自动启用 <code>--list</code>）。</li>\n<li>Codex URI 允许 <code>codex://threads/&lt;session_id&gt;</code> 变体，等价于 <code>codex://&lt;session_id&gt;</code>。</li>\n</ul>\n<ol start=\"2\">\n<li>组装命令</li>\n</ol>\n<ul>\n<li>先确认命令前缀，使用以下等价入口之一：<code>agent-dump</code>、<code>bunx @agent-dump/cli</code>、<code>npx @agent-dump/cli</code>、必要时 <code>uv run agent-dump</code>。</li>\n<li>优先复用 <a href=\"references/cli-recipes.md\">references/cli-recipes.md</a> 的模板命令。</li>\n<li><code>references/cli-recipes.md</code> 负责详细命令模板、行为矩阵和错误处理；本 skill 只负责入口选择与环境判断规则。</li>\n<li>保留用户显式给出的 <code>--output</code>、<code>--format</code>、<code>--lang</code>、<code>-days</code>、<code>-query</code>、<code>--summary</code>、<code>--collect</code>、<code>-since/-until</code>、<code>--config</code> 参数。</li>\n<li>保留用户显式给出的 <code>--collect-mode pm|insight</code>、<code>--dry-run</code>、<code>--save</code>、<code>--search</code>、<code>--reindex</code>、<code>--no-metadata-summary</code> 参数。</li>\n<li>保留用户显式给出的 <code>--head</code> 参数，用于 URI 轻量元数据查看。</li>\n</ul>\n<ol start=\"3\">\n<li>执行并检查退出状态</li>\n</ol>\n<ul>\n<li>退出码 <code>0</code> 视为成功。</li>\n<li>非 <code>0</code> 视为失败，提炼关键报错并给出下一步修复建议。</li>\n</ul>\n<ol start=\"4\">\n<li>输出结果摘要</li>\n</ol>\n<ul>\n<li>说明执行模式（interactive/list/uri/collect/config）。</li>\n<li>说明会话结果（命中数量、是否导出成功）。</li>\n<li>说明输出位置（若发生文件导出）。</li>\n<li>说明失败原因（若失败）。</li>\n</ul>\n<h3>强约束</h3>\n<ul>\n<li>在 <code>--interactive</code> 模式下，不要使用 <code>--format print</code>。</li>\n<li>在 <code>--list</code> 模式下，<code>--format</code> 和 <code>--output</code> 会被忽略，需在结果里提醒。</li>\n<li><code>--format</code> 支持 <code>json,markdown,raw,print</code> 逗号组合，<code>md</code> 是 <code>markdown</code> 别名。</li>\n<li>URI 模式默认输出为 <code>print</code>，可组合 <code>print,json</code>；非 URI 模式默认输出为 <code>json</code>。</li>\n<li>Cursor URI 支持 <code>json</code> 与 <code>print</code>。</li>\n<li><code>--head</code> 仅支持 URI 模式，用于轻量元数据查看，不能与 <code>--format</code> 或 <code>--summary</code> 组合。</li>\n<li><code>--summary</code> 仅支持 URI 模式，且 <code>--format</code> 必须包含 <code>json</code>；不满足条件时仅警告并继续主流程。</li>\n<li><code>--collect</code> 可接受 <code>agents://...</code> 查询 URI，可使用 <code>--collect-mode pm|insight</code>、<code>--dry-run</code>、<code>--save</code>、<code>-since/-until</code>。</li>\n<li><code>--collect</code> 与普通 session URI、<code>--interactive</code>、<code>--list</code> 组合时会报冲突。</li>\n<li><code>--stats</code> 支持 <code>-days</code> 与 <code>-query</code>。</li>\n<li><code>--search</code> 作为列表搜索模式使用，可与 <code>--list</code>、<code>-days</code>、<code>-query</code> 组合。</li>\n<li><code>--reindex</code> 是独立的索引维护命令，不应与其他模式标志组合。</li>\n<li>仅使用当前 CLI 已支持的 URI 协议：<code>opencode</code>、<code>codex</code>、<code>kimi</code>、<code>claude</code>、<code>cursor</code>、<code>pi</code>（其中 <code>claude</code> 对应 Claude Code）。</li>\n<li>路径作用域查询 URI 使用 <code>agents://&lt;path&gt;?q=&lt;keyword&gt;&amp;providers=&lt;names&gt;&amp;roles=&lt;roles&gt;&amp;limit=&lt;n&gt;</code>。</li>\n</ul>\n<h3>参数与错误参考</h3>\n<p>读取 <a href=\"references/cli-recipes.md\">references/cli-recipes.md</a> 获取完整命令模板、行为矩阵、查询语法和错误处理策略。</p>\n",
  "ai-avoid": "<h2>AI Writing Tropes to Avoid</h2>\n<p>Add this file to your AI assistant&#39;s system prompt or context to help it avoid\ncommon AI writing patterns. Source: <a href=\"https://tropes.fyi\">tropes.fyi</a> by <a href=\"https://ossama.is\">ossama.is</a></p>\n<hr>\n<h3>Word Choice</h3>\n<h4>&quot;Quietly&quot; and Other Magic Adverbs</h4>\n<p>Overuse of &quot;quietly&quot; and similar adverbs to convey subtle importance or understated power. AI reaches for these adverbs to make mundane descriptions feel significant. Also includes: &quot;deeply&quot;, &quot;fundamentally&quot;, &quot;remarkably&quot;, &quot;arguably&quot;.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;quietly orchestrating workflows, decisions, and interactions&quot;</li>\n<li>&quot;the one that quietly suffocates everything else&quot;</li>\n<li>&quot;a quiet intelligence behind it&quot;</li>\n</ul>\n<h4>&quot;Delve&quot; and Friends</h4>\n<p>Used to be the most infamous AI tell. &quot;Delve&quot; went from an uncommon English word to appearing in a staggering percentage of AI-generated text. Part of a family of overused AI vocabulary including &quot;certainly&quot;, &quot;utilize&quot;, &quot;leverage&quot; (as a verb), &quot;robust&quot;, &quot;streamline&quot;, and &quot;harness&quot;.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;Let&#39;s delve into the details...&quot;</li>\n<li>&quot;Delving deeper into this topic...&quot;</li>\n<li>&quot;We certainly need to leverage these robust frameworks...&quot;</li>\n</ul>\n<h4>&quot;Tapestry&quot; and &quot;Landscape&quot;</h4>\n<p>Overuse of ornate or grandiose nouns where simpler words would do. &quot;Tapestry&quot; is used to describe anything interconnected. &quot;Landscape&quot; is used to describe any field or domain. Other offenders: &quot;paradigm&quot;, &quot;synergy&quot;, &quot;ecosystem&quot;, &quot;framework&quot;.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;The rich tapestry of human experience...&quot;</li>\n<li>&quot;Navigating the complex landscape of modern AI...&quot;</li>\n<li>&quot;The ever-evolving landscape of technology...&quot;</li>\n</ul>\n<h4>The &quot;Serves As&quot; Dodge</h4>\n<p>Replacing simple &quot;is&quot; or &quot;are&quot; with pompous alternatives like &quot;serves as&quot;, &quot;stands as&quot;, &quot;marks&quot;, or &quot;represents&quot;. AI avoids basic copulas because its repetition penalty pushes it toward fancier constructions (I&#39;ve studied this!).</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;The building serves as a reminder of the city&#39;s heritage.&quot;</li>\n<li>&quot;Gallery 825 serves as LAAA&#39;s exhibition space for contemporary art.&quot;</li>\n<li>&quot;The station marks a pivotal moment in the evolution of regional transit.&quot;</li>\n</ul>\n<hr>\n<h3>Sentence Structure</h3>\n<h4>Negative Parallelism</h4>\n<p>The &quot;It&#39;s not X -- it&#39;s Y&quot; pattern, often with an em dash. The single most commonly identified AI writing tell. Man I f*cking hate it. AI uses this to create false profundity by framing everything as a surprising reframe. One in a piece can be effective; ten in a blog post is a genuine insult to the reader. Before LLMs, people simply did not write like this at scale. Includes the causal variant &quot;not because X, but because Y&quot; where every explanation is framed as a surprise reveal.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;It&#39;s not bold. It&#39;s backwards.&quot;</li>\n<li>&quot;Feeding isn&#39;t nutrition. It&#39;s dialysis.&quot;</li>\n<li>&quot;Half the bugs you chase aren&#39;t in your code. They&#39;re in your head.&quot;</li>\n</ul>\n<h4>&quot;Not X. Not Y. Just Z.&quot;</h4>\n<p>The dramatic countdown pattern. AI builds tension by negating two or more things before revealing the actual point. Creates a false sense of narrowing down to the truth.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;Not a bug. Not a feature. A fundamental design flaw.&quot;</li>\n<li>&quot;Not ten. Not fifty. Five hundred and twenty-three lint violations across 67 files.&quot;</li>\n<li>&quot;not recklessly, not completely, but enough&quot;</li>\n</ul>\n<h4>&quot;The X? A Y.&quot;</h4>\n<p>Self-posed rhetorical questions answered immediately in the next sentence or clause. The model asks a question nobody was asking, then answers it for dramatic effect. Thinks this is the epitome of great writing.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;The result? Devastating.&quot;</li>\n<li>&quot;The worst part? Nobody saw it coming.&quot;</li>\n<li>&quot;The scary part? This attack vector is perfect for developers.&quot;</li>\n</ul>\n<h4>Anaphora Abuse</h4>\n<p>Repeating the same sentence opening multiple times in quick succession.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;They assume that users will pay... They assume that developers will build... They assume that ecosystems will emerge... They assume that...&quot;</li>\n<li>&quot;They could expose... They could offer... They could provide... They could create... They could let... They could unlock...&quot;</li>\n<li>&quot;They have built engines, but not vehicles. They have built power, but not leverage. They have built walls, but not doors.&quot;</li>\n</ul>\n<h4>Tricolon Abuse</h4>\n<p>Overuse of the rule-of-three pattern, often extended to four or five. A single tricolon is elegant; three back-to-back tricolons are a pattern recognition failure.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;Products impress people; platforms empower them. Products solve problems; platforms create worlds. Products scale linearly; platforms scale exponentially.&quot;</li>\n<li>&quot;identity, payments, compute, distribution&quot;</li>\n<li>&quot;workflows, decisions, and interactions&quot;</li>\n</ul>\n<h4>&quot;It&#39;s Worth Noting&quot;</h4>\n<p>Filler transitions that signal nothing. AI uses these phrases to introduce new points without actually connecting them to the previous argument. Also includes: &quot;It bears mentioning&quot;, &quot;Importantly&quot;, &quot;Interestingly&quot;, &quot;Notably&quot;.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;It&#39;s worth noting that this approach has limitations.&quot;</li>\n<li>&quot;Importantly, we must consider the broader implications.&quot;</li>\n<li>&quot;Interestingly, this pattern repeats across industries.&quot;</li>\n</ul>\n<h4>Superficial Analyses</h4>\n<p>Tacking a present participle (&quot;-ing&quot;) phrase onto the end of a sentence to inject shallow analysis that says nothing. The model attaches significance, legacy, or broader meaning to mundane facts using phrases like &quot;highlighting its importance&quot;, &quot;reflecting broader trends&quot;, or &quot;contributing to the development of...&quot;.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;contributing to the region&#39;s rich cultural heritage&quot;</li>\n<li>&quot;This etymology highlights the enduring legacy of the community&#39;s resistance and the transformative power of unity in shaping its identity.&quot;</li>\n<li>&quot;underscoring its role as a dynamic hub of activity and culture&quot;</li>\n</ul>\n<h4>False Ranges</h4>\n<p>Using &quot;from X to Y&quot; constructions where X and Y aren&#39;t on any real scale. In legitimate use, &quot;from X to Y&quot; implies a spectrum with a meaningful middle. AI uses it as a fancy way to list two loosely related things. &quot;From innovation to cultural transformation&quot; -- what&#39;s in between???? Nothing!</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;From innovation to implementation to cultural transformation.&quot;</li>\n<li>&quot;From the singularity of the Big Bang to the grand cosmic web.&quot;</li>\n<li>&quot;From problem-solving and tool-making to scientific discovery, artistic expression, and technological innovation.&quot;</li>\n</ul>\n<h4>Gerund Fragment Litany</h4>\n<p>After making a claim, AI illustrates it with a stream of verbless gerund fragments — standalone sentences with no grammatical subject. &quot;Fixing small bugs. Writing straightforward features. Implementing well-defined tickets.&quot; The first sentence already said everything. The fragments add nothing except word count and that familiar AI cadence. Humans don&#39;t write first drafts this way. It&#39;s a pure structural tic.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;Fixing small bugs. Writing straightforward features. Implementing well-defined tickets.&quot;</li>\n<li>&quot;Reviewing pull requests. Debugging edge cases. Attending architecture meetings.&quot;</li>\n<li>&quot;Shipping faster. Moving quicker. Delivering more.&quot;</li>\n</ul>\n<hr>\n<h3>Paragraph Structure</h3>\n<h4>Short Punchy Fragments</h4>\n<p>Excessive use of very short sentences or sentence fragments as standalone paragraphs for manufactured emphasis. RLHF training has pushed models toward &quot;writing for readability&quot; aimed at the lowest common denominator: one thought per sentence, no mental state-keeping required. It&#39;s an inhuman style. No real person writes first drafts this way because it doesn&#39;t match how humans think or speak.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;He published this. Openly. In a book. As a priest.&quot;</li>\n<li>&quot;These weren&#39;t just products. And the software side matched. Then it professionalised. But I adapted.&quot;</li>\n<li>&quot;Platforms do.&quot;</li>\n</ul>\n<h4>Listicle in a Trench Coat</h4>\n<p>Numbered or labeled points dressed up as continuous prose. The model writes what is essentially a listicle but wraps each point in a paragraph that starts with &quot;The first... The second... The third...&quot; to disguise the format. Perhaps you told it to stop generating lists and it decided to do this instead... still very common.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;The first wall is the absence of a free, scoped API... The second wall is the lack of delegated access... The third wall is the absence of scoped permissions...&quot;</li>\n<li>&quot;The second takeaway is that... The third takeaway is that... The fourth takeaway is that...&quot;</li>\n</ul>\n<hr>\n<h3>Tone</h3>\n<h4>&quot;Here&#39;s the Kicker&quot;</h4>\n<p>False suspense transitions that promise a revelation but deliver a point that did NOT need the buildup. The model uses these phrases to manufacture drama before an otherwise unremarkable observation LOL. Also includes: &quot;Here&#39;s the thing&quot;, &quot;Here&#39;s where it gets interesting&quot;, &quot;Here&#39;s what most people miss&quot;.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;Here&#39;s the kicker.&quot;</li>\n<li>&quot;Here&#39;s the thing about AI adoption.&quot;</li>\n<li>&quot;Here&#39;s where it gets interesting.&quot;</li>\n</ul>\n<h4>&quot;Think of It As...&quot;</h4>\n<p>The patronizing analogy. AI constantly reaches for &quot;Think of it as...&quot; or &quot;It&#39;s like a...&quot; to simplify concepts. The model defaults to teacher mode and assumes the reader needs a metaphor to understand anything. Often produces analogies that are less clear than the original concept.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;Think of it like a highway system for data.&quot;</li>\n<li>&quot;Think of it as a Swiss Army knife for your workflow.&quot;</li>\n<li>&quot;It&#39;s like asking someone to buy a car they&#39;re only allowed to sit in while it&#39;s parked.&quot;</li>\n</ul>\n<h4>&quot;Imagine a World Where...&quot;</h4>\n<p>The classic AI invitation to futurism. To sell the argument usually begins with &quot;Imagine&quot; followed by a list of wonderful things that will happen if the reader agrees with the premise.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;Imagine a world where every tool you use -- your calendar, your inbox, your documents, your CRM, your code editor -- has a quiet intelligence behind it...&quot;</li>\n<li>&quot;In that world, workflows stop being collections of manual steps and start becoming orchestrations.&quot;</li>\n</ul>\n<h4>False Vulnerability</h4>\n<p>Simulated self-awareness or honesty that reads as performative. The model pretends to break the fourth wall or admit a bias, creating a false sense of authenticity. Real vulnerability is specific and uncomfortable; AI vulnerability is polished and risk-free!!!!</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;And yes, I&#39;m openly in love with the platform model&quot;</li>\n<li>&quot;And yes, since we&#39;re being honest: I&#39;m looking at you, OpenAI, Google, Anthropic, Meta&quot;</li>\n<li>&quot;This is not a rant; it&#39;s a diagnosis&quot;</li>\n</ul>\n<h4>&quot;The Truth Is Simple&quot;</h4>\n<p>Asserting that something is obvious, clear or simple instead of actually proving it. If you have to tell the reader your point is clear, it very likely isn&#39;t.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;The reality is simpler and less flattering&quot;</li>\n<li>&quot;History is unambiguous on this point&quot;</li>\n<li>&quot;History is clear, the metrics are clear, the examples are clear&quot;</li>\n</ul>\n<h4>Grandiose Stakes Inflation</h4>\n<p>Everything is the most important thing ever. AI inflates the stakes of every argument to world-historical significance. A blog post about API pricing becomes a meditation on the fate of civilization.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;This will fundamentally reshape how we think about everything.&quot;</li>\n<li>&quot;will define the next era of computing&quot;</li>\n<li>&quot;something entirely new&quot;</li>\n</ul>\n<h4>&quot;Let&#39;s Break This Down&quot;</h4>\n<p>The pedagogical voice that assumes the reader needs hand-holding. AI defaults to a teacher-student dynamic even when writing for expert audiences. Also includes: &quot;Let&#39;s unpack this&quot;, &quot;Let&#39;s explore&quot;, &quot;Let&#39;s dive in&quot;.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;Let&#39;s break this down step by step.&quot;</li>\n<li>&quot;Let&#39;s unpack what this really means.&quot;</li>\n<li>&quot;Let&#39;s explore this idea further.&quot;</li>\n</ul>\n<h4>Vague Attributions</h4>\n<p>Attributing claims to unnamed authorities instead of being specific. AI loves to invoke &quot;experts&quot;, &quot;observers&quot;, &quot;industry reports&quot;, and &quot;several publications&quot; without naming anyone. It also inflates the quantity of sources -- presenting what one person said as a widely held view, or writing &quot;several publications have cited&quot; when it means two. If you can&#39;t name the expert, you don&#39;t have a source.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;Experts argue that this approach has significant drawbacks.&quot;</li>\n<li>&quot;Industry reports suggest that adoption is accelerating.&quot;</li>\n<li>&quot;Observers have cited the initiative as a turning point.&quot;</li>\n</ul>\n<h4>Invented Concept Labels</h4>\n<p>AI clusters invented compound labels that sound analytical without being grounded. It appends abstract problem-nouns (paradox, trap, creep, divide, vacuum, inversion) to domain words — &quot;supervision paradox&quot;, &quot;acceleration trap&quot;, &quot;workload creep&quot; — and uses them as if they&#39;re established, rigorously defined terms. They function as rhetorical shorthand: name a thing, skip the argument. Multiple such labels in the same piece is a strong signal of AI slop.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;the supervision paradox&quot;</li>\n<li>&quot;the acceleration trap&quot;</li>\n<li>&quot;workload creep&quot;</li>\n</ul>\n<hr>\n<h3>Formatting</h3>\n<h4>Em-Dash Addiction</h4>\n<p>Compulsive overuse of em dashes for dramatic pauses, parenthetical asides and pivot points. A human writer might use 2-3 per piece (and naturally); AI will use 20+.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;The problem -- and this is the part nobody talks about -- is systemic.&quot;</li>\n<li>&quot;The tinkerer spirit didn&#39;t die of natural causes -- it was bought out.&quot;</li>\n<li>&quot;Not recklessly, not completely -- but enough -- enough to matter.&quot;</li>\n</ul>\n<h4>Bold-First Bullets</h4>\n<p>Every bullet point or list item starts with a bolded phrase or sentence. Extremely common in Claude and ChatGPT markdown output. Almost nobody formats lists this way when writing by hand. It&#39;s a telltale sign of AI-generated documentation and blog posts AND README files (especially with emojis).</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;Every single bullet point begins with a bold keyword.&quot;</li>\n<li>&quot;<strong>Security</strong>: Environment-based configuration with...&quot;</li>\n<li>&quot;<strong>Performance</strong>: Lazy loading of expensive resources...&quot;</li>\n</ul>\n<h4>Unicode Decoration</h4>\n<p>Use of unicode arrows (-&gt;), smart/curly quotes, and other special characters that can&#39;t be easily typed on a standard keyboard. Real writers typing in a text editor produce straight quotes and -&gt; or =&gt;. Claude in particular loves the -&gt; arrow.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;Input → Processing → Output&quot;</li>\n<li>&quot;This leads to better outcomes → which means higher engagement&quot;</li>\n<li>&quot;“Smart quotes” instead of straight &quot;quotes&quot; that you’d actually type&quot;</li>\n</ul>\n<hr>\n<h3>Composition</h3>\n<h4>Fractal Summaries</h4>\n<p>&quot;What I&#39;m going to tell you; what I&#39;m telling you; what I just told you&quot; -- applied at every level of the document. Every subsection gets a summary. Every section gets a summary. The document itself gets a summary.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;In this section, we&#39;ll explore... [3000 words later] ...as we&#39;ve seen in this section.&quot;</li>\n<li>&quot;A conclusion that restates every point already made in the previous 3000 words&quot;</li>\n<li>&quot;And so we return to where we began.&quot;</li>\n</ul>\n<h4>The Dead Metaphor</h4>\n<p>Latching onto a single metaphor and beating it into the ground across the entire thing. A human writer would introduce a metaphor, use it then move on. AI will repeat the same metaphor 5-10 times.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;The ecosystem needs ecosystems to build ecosystem value.&quot;</li>\n<li>&quot;Walls and doors used 30+ times in the same article&quot;</li>\n<li>&quot;Every paragraph finds a way to say &quot;primitives&quot; again&quot;</li>\n</ul>\n<h4>Historical Analogy Stacking</h4>\n<p>ESPECIALLY COMMON IN TECHNICAL WRITING: Rapid-fire listing of historical companies or tech revolutions to build false authority.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;Apple didn&#39;t build Uber. Facebook didn&#39;t build Spotify. Stripe didn&#39;t build Shopify. AWS didn&#39;t build Airbnb.&quot;</li>\n<li>&quot;Every major technological shift -- the web, mobile, social, cloud -- followed the same pattern.&quot;</li>\n<li>&quot;Take Spotify... Or consider Uber... Airbnb followed a similar path... Shopify is another example... Even Discord...&quot;</li>\n</ul>\n<h4>One-Point Dilution</h4>\n<p>Making a single argument and restating it in 10 different ways across thousands of words. The model pads a simple thesis to feel &quot;comprehensive&quot; by rephrasing the same idea with different metaphors, examples, and framings. An 800-word argument becomes 4000 words of circular repetition.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;The same point, restated eight ways across 4000 words.&quot;</li>\n<li>&quot;Each section rephrases the thesis with a different metaphor but adds nothing new&quot;</li>\n</ul>\n<h4>Content Duplication</h4>\n<p>Repeating entire sections or paragraphs verbatim within the same piece. This happens when the model loses track of what it has already written, especially in longer pieces. A dead giveaway of unedited AI output. Less common nowadays.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;The same section appeared twice, word-for-word identical.&quot;</li>\n<li>&quot;Paragraph 3 and paragraph 17 are the same sentence reworded&quot;</li>\n</ul>\n<h4>The Signposted Conclusion</h4>\n<p>Explicitly announcing the conclusion with &quot;In conclusion&quot;, &quot;To sum up&quot;, or &quot;In summary&quot;. Competent writing doesn&#39;t need to tell you it&#39;s concluding. The reader can feel it. AI signals its structural moves because it&#39;s following a template, not writing organically.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;In conclusion, the future of AI depends on...&quot;</li>\n<li>&quot;To sum up, we&#39;ve explored three key themes...&quot;</li>\n<li>&quot;In summary, the evidence suggests...&quot;</li>\n</ul>\n<h4>&quot;Despite Its Challenges...&quot;</h4>\n<p>The rigid formula where AI acknowledges problems only to immediately dismiss them. Always follows the same beat: &quot;Despite its [positive words], [subject] faces challenges...&quot; then ends with &quot;Despite these challenges, [optimistic conclusion].&quot;.</p>\n<p><strong>Avoid patterns like:</strong></p>\n<ul>\n<li>&quot;Despite these challenges, the initiative continues to thrive.&quot;</li>\n<li>&quot;Despite its industrial and residential prosperity, Korattur faces challenges typical of urban areas.&quot;</li>\n<li>&quot;Despite their promising applications, pyroelectric materials face several challenges that must be addressed for broader adoption.&quot;</li>\n</ul>\n<hr>\n<p>Remember: any of these patterns used once might be fine. The problem is when\nmultiple tropes appear together or when a single trope is used repeatedly.\nWrite like a human: varied, imperfect, specific.</p>\n",
  "article-illustrator": "<h2>Article Illustrator</h2>\n<p>Analyze articles, identify illustration positions, generate structured prompts for downstream image generation.</p>\n<h3>Two Dimensions</h3>\n<table>\n<thead>\n<tr>\n<th>Dimension</th>\n<th>Controls</th>\n<th>Examples</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><strong>Type</strong></td>\n<td>Information structure</td>\n<td>infographic, scene, flowchart, comparison, framework, timeline</td>\n</tr>\n<tr>\n<td><strong>Style</strong></td>\n<td>Visual aesthetics</td>\n<td>notion, warm, minimal, blueprint, watercolor, elegant</td>\n</tr>\n</tbody></table>\n<p>Combine freely: <code>--type infographic --style blueprint</code></p>\n<p>Or use presets: <code>--preset tech-explainer</code> → type + style in one flag. See <a href=\"references/style-presets.md\">Style Presets</a>.</p>\n<h3>Types</h3>\n<table>\n<thead>\n<tr>\n<th>Type</th>\n<th>Best For</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>infographic</code></td>\n<td>Data, metrics, technical</td>\n</tr>\n<tr>\n<td><code>scene</code></td>\n<td>Narratives, emotional</td>\n</tr>\n<tr>\n<td><code>flowchart</code></td>\n<td>Processes, workflows</td>\n</tr>\n<tr>\n<td><code>comparison</code></td>\n<td>Side-by-side, options</td>\n</tr>\n<tr>\n<td><code>framework</code></td>\n<td>Models, architecture</td>\n</tr>\n<tr>\n<td><code>timeline</code></td>\n<td>History, evolution</td>\n</tr>\n</tbody></table>\n<h3>Styles</h3>\n<p>See <a href=\"references/styles.md\">references/styles.md</a> for Core Styles, full gallery, and Type × Style compatibility.</p>\n<h3>Workflow</h3>\n<pre><code>Article Illustrator Progress:\n- [ ] Step 0: Check EXTEND.md ⛔ BLOCKING\n- [ ] Step 1: Analyze content + save refs\n- [ ] Step 2: Confirm settings ⚠️\n- [ ] Step 3: Generate outline\n- [ ] Step 4: Create prompt files\n- [ ] Step 5: Completion report\n</code></pre>\n<h4>Step 0: Load EXTEND.md ⛔ BLOCKING</h4>\n<p>Check EXTEND.md in project root only:</p>\n<pre><code class=\"language-bash\">test -f EXTEND.md &amp;&amp; echo &quot;found&quot;\n</code></pre>\n<table>\n<thead>\n<tr>\n<th>Result</th>\n<th>Action</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Found</td>\n<td>Read, parse, display summary → Continue</td>\n</tr>\n<tr>\n<td>Not found</td>\n<td>⛔ Run <a href=\"references/config/first-time-setup.md\">first-time-setup</a></td>\n</tr>\n</tbody></table>\n<p>Full procedures: <a href=\"references/workflow.md#step-0-load-extendmd\">references/workflow.md</a></p>\n<h4>Step 1: Analyze Content</h4>\n<table>\n<thead>\n<tr>\n<th>Analysis</th>\n<th>Output</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Content type</td>\n<td>Technical / Tutorial / Methodology / Narrative</td>\n</tr>\n<tr>\n<td>Purpose</td>\n<td>information / visualization / imagination</td>\n</tr>\n<tr>\n<td>Core arguments</td>\n<td>2-5 main points</td>\n</tr>\n<tr>\n<td>Positions</td>\n<td>Where illustrations add value</td>\n</tr>\n</tbody></table>\n<p><strong>CRITICAL</strong>: Metaphors → visualize underlying concept, NOT literal image.</p>\n<p>Full procedures: <a href=\"references/workflow.md#step-1-analyze-content\">references/workflow.md</a></p>\n<h4>Step 2: Confirm Settings ⚠️</h4>\n<p><strong>ONE AskUserQuestion, max 4 Qs. Q1-Q2 REQUIRED.</strong></p>\n<table>\n<thead>\n<tr>\n<th>Q</th>\n<th>Options</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><strong>Q1: Preset or Type</strong></td>\n<td>[Recommended preset], [alt preset], or manual: infographic, scene, flowchart, comparison, framework, timeline, mixed</td>\n</tr>\n<tr>\n<td><strong>Q2: Density</strong></td>\n<td>minimal (1-2), balanced (3-5), per-section (Recommended), rich (6+)</td>\n</tr>\n<tr>\n<td><strong>Q3: Style</strong></td>\n<td>[Recommended], minimal-flat, sci-fi, hand-drawn, editorial, scene, poster, Other — <strong>skip if preset chosen</strong></td>\n</tr>\n<tr>\n<td>Q4: Language</td>\n<td>When article language ≠ EXTEND.md setting</td>\n</tr>\n</tbody></table>\n<p>Full procedures: <a href=\"references/workflow.md#step-2-confirm-settings\">references/workflow.md</a></p>\n<h4>Step 3: Generate Outline</h4>\n<p>Save <code>outline.md</code> with frontmatter (type, density, style, image_count) and entries:</p>\n<pre><code class=\"language-yaml\">## Illustration 1\n**Position**: [section/paragraph]\n**Purpose**: [why]\n**Visual Content**: [what]\n**Filename**: illustration-01.md\n</code></pre>\n<p>Full template: <a href=\"references/workflow.md#step-3-generate-outline\">references/workflow.md</a></p>\n<h4>Step 4: Create Prompt Files</h4>\n<p><strong>Output</strong>: One <code>illustration-{NN}.md</code> file per illustration, in the same directory as the article.</p>\n<p>Each file contains:</p>\n<ul>\n<li>YAML frontmatter (type, style, references)</li>\n<li>Content Context (title, summary, keywords)</li>\n<li>Visual Design (type, style, aspect, language)</li>\n<li>Illustration Prompt (structured prompt)</li>\n<li>Rendering Notes (style characteristics)</li>\n<li>Reference Style (if reference images provided)</li>\n</ul>\n<p>Full template: <a href=\"references/prompt-construction.md\">references/prompt-construction.md</a></p>\n<h4>Step 5: Completion Report</h4>\n<pre><code>Article Illustration Prompts Ready!\n\nArticle: [path]\nType: [type] | Density: [level] | Style: [style]\n\nPrompt Files:\n✓ illustration-01.md\n✓ illustration-02.md\n\nNext Steps:\n1. Use illustration prompts with your preferred image generation tool\n2. Generated images will be saved alongside the prompts\n3. Reference in article with: ![description](illustration-{NN}.png)\n</code></pre>\n<h3>File Structure</h3>\n<p>Prompt files are saved in the same directory as the article:</p>\n<pre><code>{article-dir}/\n├── article.md\n├── outline.md\n├── illustration-01.md\n├── illustration-02.md\n└── refs/\n    └── ref-01-{slug}.png\n</code></pre>\n<p><strong>Filename conflict</strong>: If <code>illustration-{NN}.md</code> exists, append <code>-1</code>, <code>-2</code>, etc.</p>\n<h3>Modification</h3>\n<table>\n<thead>\n<tr>\n<th>Action</th>\n<th>Steps</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Edit</td>\n<td>Update prompt file → Regenerate image</td>\n</tr>\n<tr>\n<td>Add</td>\n<td>Position → Prompt → Insert reference</td>\n</tr>\n<tr>\n<td>Delete</td>\n<td>Delete files → Remove reference → Update outline</td>\n</tr>\n</tbody></table>\n<h3>References</h3>\n<table>\n<thead>\n<tr>\n<th>File</th>\n<th>Content</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><a href=\"references/workflow.md\">references/workflow.md</a></td>\n<td>Detailed procedures</td>\n</tr>\n<tr>\n<td><a href=\"references/usage.md\">references/usage.md</a></td>\n<td>Command syntax</td>\n</tr>\n<tr>\n<td><a href=\"references/styles.md\">references/styles.md</a></td>\n<td>Style gallery</td>\n</tr>\n<tr>\n<td><a href=\"references/style-presets.md\">references/style-presets.md</a></td>\n<td>Preset shortcuts (type + style)</td>\n</tr>\n<tr>\n<td><a href=\"references/prompt-construction.md\">references/prompt-construction.md</a></td>\n<td>Prompt templates</td>\n</tr>\n<tr>\n<td><a href=\"references/config/first-time-setup.md\">references/config/first-time-setup.md</a></td>\n<td>First-time setup</td>\n</tr>\n</tbody></table>\n",
  "canvas-design": "<p>These are instructions for creating design philosophies - aesthetic movements that are then EXPRESSED VISUALLY. Output only .md files, .pdf files, and .png files.</p>\n<p>Complete this in two steps:</p>\n<ol>\n<li>Design Philosophy Creation (.md file)</li>\n<li>Express by creating it on a canvas (.pdf file or .png file)</li>\n</ol>\n<p>First, undertake this task:</p>\n<h3>DESIGN PHILOSOPHY CREATION</h3>\n<p>To begin, create a VISUAL PHILOSOPHY (not layouts or templates) that will be interpreted through:</p>\n<ul>\n<li>Form, space, color, composition</li>\n<li>Images, graphics, shapes, patterns</li>\n<li>Minimal text as visual accent</li>\n</ul>\n<h4>THE CRITICAL UNDERSTANDING</h4>\n<ul>\n<li>What is received: Some subtle input or instructions by the user that should be taken into account, but used as a foundation; it should not constrain creative freedom.</li>\n<li>What is created: A design philosophy/aesthetic movement.</li>\n<li>What happens next: Then, the same version receives the philosophy and EXPRESSES IT VISUALLY - creating artifacts that are 90% visual design, 10% essential text.</li>\n</ul>\n<p>Consider this approach:</p>\n<ul>\n<li>Write a manifesto for an art movement</li>\n<li>The next phase involves making the artwork</li>\n</ul>\n<p>The philosophy must emphasize: Visual expression. Spatial communication. Artistic interpretation. Minimal words.</p>\n<h4>HOW TO GENERATE A VISUAL PHILOSOPHY</h4>\n<p><strong>Name the movement</strong> (1-2 words): &quot;Brutalist Joy&quot; / &quot;Chromatic Silence&quot; / &quot;Metabolist Dreams&quot;</p>\n<p><strong>Articulate the philosophy</strong> (4-6 paragraphs - concise but complete):</p>\n<p>To capture the VISUAL essence, express how the philosophy manifests through:</p>\n<ul>\n<li>Space and form</li>\n<li>Color and material</li>\n<li>Scale and rhythm</li>\n<li>Composition and balance</li>\n<li>Visual hierarchy</li>\n</ul>\n<p><strong>CRITICAL GUIDELINES:</strong></p>\n<ul>\n<li><strong>Avoid redundancy</strong>: Each design aspect should be mentioned once. Avoid repeating points about color theory, spatial relationships, or typographic principles unless adding new depth.</li>\n<li><strong>Emphasize craftsmanship REPEATEDLY</strong>: The philosophy MUST stress multiple times that the final work should appear as though it took countless hours to create, was labored over with care, and comes from someone at the absolute top of their field. This framing is essential - repeat phrases like &quot;meticulously crafted,&quot; &quot;the product of deep expertise,&quot; &quot;painstaking attention,&quot; &quot;master-level execution.&quot;</li>\n<li><strong>Leave creative space</strong>: Remain specific about the aesthetic direction, but concise enough that the next Claude has room to make interpretive choices also at a extremely high level of craftmanship.</li>\n</ul>\n<p>The philosophy must guide the next version to express ideas VISUALLY, not through text. Information lives in design, not paragraphs.</p>\n<h4>PHILOSOPHY EXAMPLES</h4>\n<p><strong>&quot;Concrete Poetry&quot;</strong>\nPhilosophy: Communication through monumental form and bold geometry.\nVisual expression: Massive color blocks, sculptural typography (huge single words, tiny labels), Brutalist spatial divisions, Polish poster energy meets Le Corbusier. Ideas expressed through visual weight and spatial tension, not explanation. Text as rare, powerful gesture - never paragraphs, only essential words integrated into the visual architecture. Every element placed with the precision of a master craftsman.</p>\n<p><strong>&quot;Chromatic Language&quot;</strong>\nPhilosophy: Color as the primary information system.\nVisual expression: Geometric precision where color zones create meaning. Typography minimal - small sans-serif labels letting chromatic fields communicate. Think Josef Albers&#39; interaction meets data visualization. Information encoded spatially and chromatically. Words only to anchor what color already shows. The result of painstaking chromatic calibration.</p>\n<p><strong>&quot;Analog Meditation&quot;</strong>\nPhilosophy: Quiet visual contemplation through texture and breathing room.\nVisual expression: Paper grain, ink bleeds, vast negative space. Photography and illustration dominate. Typography whispered (small, restrained, serving the visual). Japanese photobook aesthetic. Images breathe across pages. Text appears sparingly - short phrases, never explanatory blocks. Each composition balanced with the care of a meditation practice.</p>\n<p><strong>&quot;Organic Systems&quot;</strong>\nPhilosophy: Natural clustering and modular growth patterns.\nVisual expression: Rounded forms, organic arrangements, color from nature through architecture. Information shown through visual diagrams, spatial relationships, iconography. Text only for key labels floating in space. The composition tells the story through expert spatial orchestration.</p>\n<p><strong>&quot;Geometric Silence&quot;</strong>\nPhilosophy: Pure order and restraint.\nVisual expression: Grid-based precision, bold photography or stark graphics, dramatic negative space. Typography precise but minimal - small essential text, large quiet zones. Swiss formalism meets Brutalist material honesty. Structure communicates, not words. Every alignment the work of countless refinements.</p>\n<p><em>These are condensed examples. The actual design philosophy should be 4-6 substantial paragraphs.</em></p>\n<h4>ESSENTIAL PRINCIPLES</h4>\n<ul>\n<li><strong>VISUAL PHILOSOPHY</strong>: Create an aesthetic worldview to be expressed through design</li>\n<li><strong>MINIMAL TEXT</strong>: Always emphasize that text is sparse, essential-only, integrated as visual element - never lengthy</li>\n<li><strong>SPATIAL EXPRESSION</strong>: Ideas communicate through space, form, color, composition - not paragraphs</li>\n<li><strong>ARTISTIC FREEDOM</strong>: The next Claude interprets the philosophy visually - provide creative room</li>\n<li><strong>PURE DESIGN</strong>: This is about making ART OBJECTS, not documents with decoration</li>\n<li><strong>EXPERT CRAFTSMANSHIP</strong>: Repeatedly emphasize the final work must look meticulously crafted, labored over with care, the product of countless hours by someone at the top of their field</li>\n</ul>\n<p><strong>The design philosophy should be 4-6 paragraphs long.</strong> Fill it with poetic design philosophy that brings together the core vision. Avoid repeating the same points. Keep the design philosophy generic without mentioning the intention of the art, as if it can be used wherever. Output the design philosophy as a .md file.</p>\n<hr>\n<h3>DEDUCING THE SUBTLE REFERENCE</h3>\n<p><strong>CRITICAL STEP</strong>: Before creating the canvas, identify the subtle conceptual thread from the original request.</p>\n<p><strong>THE ESSENTIAL PRINCIPLE</strong>:\nThe topic is a <strong>subtle, niche reference embedded within the art itself</strong> - not always literal, always sophisticated. Someone familiar with the subject should feel it intuitively, while others simply experience a masterful abstract composition. The design philosophy provides the aesthetic language. The deduced topic provides the soul - the quiet conceptual DNA woven invisibly into form, color, and composition.</p>\n<p>This is <strong>VERY IMPORTANT</strong>: The reference must be refined so it enhances the work&#39;s depth without announcing itself. Think like a jazz musician quoting another song - only those who know will catch it, but everyone appreciates the music.</p>\n<hr>\n<h3>CANVAS CREATION</h3>\n<p>With both the philosophy and the conceptual framework established, express it on a canvas. Take a moment to gather thoughts and clear the mind. Use the design philosophy created and the instructions below to craft a masterpiece, embodying all aspects of the philosophy with expert craftsmanship.</p>\n<p><strong>IMPORTANT</strong>: For any type of content, even if the user requests something for a movie/game/book, the approach should still be sophisticated. Never lose sight of the idea that this should be art, not something that&#39;s cartoony or amateur.</p>\n<p>To create museum or magazine quality work, use the design philosophy as the foundation. Create one single page, highly visual, design-forward PDF or PNG output (unless asked for more pages). Generally use repeating patterns and perfect shapes. Treat the abstract philosophical design as if it were a scientific bible, borrowing the visual language of systematic observation—dense accumulation of marks, repeated elements, or layered patterns that build meaning through patient repetition and reward sustained viewing. Add sparse, clinical typography and systematic reference markers that suggest this could be a diagram from an imaginary discipline, treating the invisible subject with the same reverence typically reserved for documenting observable phenomena. Anchor the piece with simple phrase(s) or details positioned subtly, using a limited color palette that feels intentional and cohesive. Embrace the paradox of using analytical visual language to express ideas about human experience: the result should feel like an artifact that proves something ephemeral can be studied, mapped, and understood through careful attention. This is true art. </p>\n<p><strong>Text as a contextual element</strong>: Text is always minimal and visual-first, but let context guide whether that means whisper-quiet labels or bold typographic gestures. A punk venue poster might have larger, more aggressive type than a minimalist ceramics studio identity. Most of the time, font should be thin. All use of fonts must be design-forward and prioritize visual communication. Regardless of text scale, nothing falls off the page and nothing overlaps. Every element must be contained within the canvas boundaries with proper margins. Check carefully that all text, graphics, and visual elements have breathing room and clear separation. This is non-negotiable for professional execution. <strong>IMPORTANT: Use different fonts if writing text. Search the <code>./canvas-fonts</code> directory. Regardless of approach, sophistication is non-negotiable.</strong></p>\n<p>Download and use whatever fonts are needed to make this a reality. Get creative by making the typography actually part of the art itself -- if the art is abstract, bring the font onto the canvas, not typeset digitally.</p>\n<p>To push boundaries, follow design instinct/intuition while using the philosophy as a guiding principle. Embrace ultimate design freedom and choice. Push aesthetics and design to the frontier. </p>\n<p><strong>CRITICAL</strong>: To achieve human-crafted quality (not AI-generated), create work that looks like it took countless hours. Make it appear as though someone at the absolute top of their field labored over every detail with painstaking care. Ensure the composition, spacing, color choices, typography - everything screams expert-level craftsmanship. Double-check that nothing overlaps, formatting is flawless, every detail perfect. Create something that could be shown to people to prove expertise and rank as undeniably impressive.</p>\n<p>Output the final result as a single, downloadable .pdf or .png file, alongside the design philosophy used as a .md file.</p>\n<hr>\n<h3>FINAL STEP</h3>\n<p><strong>IMPORTANT</strong>: The user ALREADY said &quot;It isn&#39;t perfect enough. It must be pristine, a masterpiece if craftsmanship, as if it were about to be displayed in a museum.&quot;</p>\n<p><strong>CRITICAL</strong>: To refine the work, avoid adding more graphics; instead refine what has been created and make it extremely crisp, respecting the design philosophy and the principles of minimalism entirely. Rather than adding a fun filter or refactoring a font, consider how to make the existing composition more cohesive with the art. If the instinct is to call a new function or draw a new shape, STOP and instead ask: &quot;How can I make what&#39;s already here more of a piece of art?&quot;</p>\n<p>Take a second pass. Go back to the code and refine/polish further to make this a philosophically designed masterpiece.</p>\n<h3>MULTI-PAGE OPTION</h3>\n<p>To create additional pages when requested, create more creative pages along the same lines as the design philosophy but distinctly different as well. Bundle those pages in the same .pdf or many .pngs. Treat the first page as just a single page in a whole coffee table book waiting to be filled. Make the next pages unique twists and memories of the original. Have them almost tell a story in a very tasteful way. Exercise full creative freedom.</p>\n",
  "claude-agent-sdk-typescript": "<h2>Claude Agent SDK TypeScript</h2>\n<p>Help users build AI agents with the Claude Agent SDK TypeScript version. This skill covers the <code>query()</code> function, message types, configuration options, subagents, hooks, MCP servers, custom tools, streaming, and structured outputs.</p>\n<hr>\n<h3>安装与设置</h3>\n<h4>安装 SDK</h4>\n<pre><code class=\"language-bash\">npm install @anthropic-ai/claude-agent-sdk\n</code></pre>\n<h4>环境变量</h4>\n<pre><code class=\"language-bash\"># 必需的 API Key\nexport ANTHROPIC_API_KEY=your-api-key\n\n# 可选：第三方 API 提供商\nexport CLAUDE_CODE_USE_BEDROCK=1    # Amazon Bedrock\nexport CLAUDE_CODE_USE_VERTEX=1     # Google Vertex AI\nexport CLAUDE_CODE_USE_FOUNDRY=1    # Microsoft Azure\n</code></pre>\n<h3>基础用法</h3>\n<h4>最简单的 Agent</h4>\n<pre><code class=\"language-typescript\">import { query } from &quot;@anthropic-ai/claude-agent-sdk&quot;;\n\nfor await (const message of query({\n  prompt: &quot;What files are in this directory?&quot;,\n  options: { allowedTools: [&quot;Bash&quot;, &quot;Glob&quot;] }\n})) {\n  if (message.type === &quot;result&quot; &amp;&amp; message.subtype === &quot;success&quot;) {\n    console.log(message.result);\n  }\n}\n</code></pre>\n<h4>消息类型处理</h4>\n<pre><code class=\"language-typescript\">import { query } from &quot;@anthropic-ai/claude-agent-sdk&quot;;\n\nfor await (const message of query({ prompt: &quot;Your task&quot;, options: {} })) {\n  switch (message.type) {\n    case &quot;system&quot;:\n      // 系统消息：session 初始化、compact_boundary\n      if (message.subtype === &quot;init&quot;) {\n        console.log(&quot;Session ID:&quot;, message.session_id);\n      }\n      break;\n\n    case &quot;assistant&quot;:\n      // Claude 的响应：包含文本和工具调用\n      for (const block of message.message.content) {\n        if (block.type === &quot;text&quot;) {\n          console.log(&quot;Claude:&quot;, block.text);\n        } else if (block.type === &quot;tool_use&quot;) {\n          console.log(&quot;Tool:&quot;, block.name);\n        }\n      }\n      break;\n\n    case &quot;user&quot;:\n      // 工具执行结果\n      console.log(&quot;Tool result received&quot;);\n      break;\n\n    case &quot;result&quot;:\n      // 最终结果\n      if (message.subtype === &quot;success&quot;) {\n        console.log(&quot;Done:&quot;, message.result);\n      } else {\n        console.log(&quot;Stopped:&quot;, message.subtype);\n      }\n      break;\n  }\n}\n</code></pre>\n<h3>配置选项</h3>\n<h4>核心选项</h4>\n<pre><code class=\"language-typescript\">const options = {\n  // 工具控制\n  allowedTools: [&quot;Read&quot;, &quot;Edit&quot;, &quot;Bash&quot;],      // 预批准的工具\n  disallowedTools: [&quot;Write&quot;],                   // 禁止的工具\n\n  // 权限模式\n  permissionMode: &quot;acceptEdits&quot;,                // &quot;default&quot; | &quot;acceptEdits&quot; | &quot;dontAsk&quot; | &quot;bypassPermissions&quot; | &quot;plan&quot;\n\n  // 限制\n  maxTurns: 30,                                 // 最大回合数\n  maxBudgetUsd: 5.0,                            // 最大预算（美元）\n\n  // 推理深度\n  effort: &quot;high&quot;,                               // &quot;low&quot; | &quot;medium&quot; | &quot;high&quot; | &quot;max&quot;\n\n  // 模型\n  model: &quot;claude-sonnet-4-6&quot;,                   // 指定模型\n\n  // 系统提示\n  systemPrompt: &quot;You are a senior TypeScript developer.&quot;,\n\n  // 设置源\n  settingSources: [&quot;project&quot;],                  // 加载 .claude/CLAUDE.md, skills\n};\n</code></pre>\n<h4>权限模式对比</h4>\n<table>\n<thead>\n<tr>\n<th>模式</th>\n<th>行为</th>\n<th>适用场景</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>default</code></td>\n<td>需要 <code>canUseTool</code> 回调处理未批准的工具</td>\n<td>交互式应用</td>\n</tr>\n<tr>\n<td><code>acceptEdits</code></td>\n<td>自动批准文件编辑，其他工具需审批</td>\n<td>开发工作流</td>\n</tr>\n<tr>\n<td><code>dontAsk</code></td>\n<td>拒绝未在 <code>allowedTools</code> 中列出的工具</td>\n<td>受限的自动化</td>\n</tr>\n<tr>\n<td><code>bypassPermissions</code></td>\n<td>运行所有工具（谨慎使用！）</td>\n<td>CI/CD、沙箱环境</td>\n</tr>\n<tr>\n<td><code>plan</code></td>\n<td>只规划，不执行</td>\n<td>代码审查</td>\n</tr>\n</tbody></table>\n<h3>会话管理</h3>\n<h4>自动继续会话</h4>\n<pre><code class=\"language-typescript\">import { query } from &quot;@anthropic-ai/claude-agent-sdk&quot;;\n\n// 第一次查询\nfor await (const message of query({\n  prompt: &quot;Analyze the auth module&quot;,\n  options: { allowedTools: [&quot;Read&quot;, &quot;Glob&quot;] }\n})) {\n  if (message.type === &quot;result&quot;) console.log(message.result);\n}\n\n// 继续同一会话\nfor await (const message of query({\n  prompt: &quot;Now refactor it to use JWT&quot;,\n  options: {\n    continue: true,  // 自动继续最近的会话\n    allowedTools: [&quot;Read&quot;, &quot;Edit&quot;, &quot;Write&quot;]\n  }\n})) {\n  if (message.type === &quot;result&quot;) console.log(message.result);\n}\n</code></pre>\n<h4>按 ID 恢复会话</h4>\n<pre><code class=\"language-typescript\">let sessionId: string | undefined;\n\n// 第一次查询，保存 session ID\nfor await (const message of query({\n  prompt: &quot;Analyze the auth module&quot;,\n  options: { allowedTools: [&quot;Read&quot;, &quot;Glob&quot;] }\n})) {\n  if (message.type === &quot;system&quot; &amp;&amp; message.subtype === &quot;init&quot;) {\n    sessionId = message.session_id;\n  }\n  if (message.type === &quot;result&quot;) {\n    console.log(message.result);\n  }\n}\n\n// 之后恢复特定会话\nfor await (const message of query({\n  prompt: &quot;Continue with the refactoring&quot;,\n  options: { resume: sessionId }\n})) {\n  if (message.type === &quot;result&quot;) console.log(message.result);\n}\n</code></pre>\n<h4>分叉会话</h4>\n<pre><code class=\"language-typescript\">// 从现有会话创建分支\nlet forkedId: string | undefined;\n\nfor await (const message of query({\n  prompt: &quot;Try OAuth2 instead of JWT&quot;,\n  options: {\n    resume: sessionId,\n    forkSession: true  // 创建分支，原会话不受影响\n  }\n})) {\n  if (message.type === &quot;system&quot; &amp;&amp; message.subtype === &quot;init&quot;) {\n    forkedId = message.session_id;  // 新分支的 ID\n  }\n}\n</code></pre>\n<h3>子代理</h3>\n<h4>定义子代理</h4>\n<pre><code class=\"language-typescript\">import { query } from &quot;@anthropic-ai/claude-agent-sdk&quot;;\n\nfor await (const message of query({\n  prompt: &quot;Review the authentication module&quot;,\n  options: {\n    allowedTools: [&quot;Read&quot;, &quot;Grep&quot;, &quot;Glob&quot;, &quot;Agent&quot;],  // Agent 工具必需\n    agents: {\n      &quot;code-reviewer&quot;: {\n        description: &quot;Expert code reviewer. Use for quality and security reviews.&quot;,\n        prompt: `You are a code review specialist with expertise in security, performance, and best practices.\n\nWhen reviewing code:\n- Identify security vulnerabilities\n- Check for performance issues\n- Verify adherence to coding standards\n- Suggest specific improvements\n\nBe thorough but concise in your feedback.`,\n        tools: [&quot;Read&quot;, &quot;Grep&quot;, &quot;Glob&quot;],  // 只读权限\n        model: &quot;sonnet&quot;  // 可选：覆盖默认模型\n      },\n      &quot;test-runner&quot;: {\n        description: &quot;Runs and analyzes test suites.&quot;,\n        prompt: &quot;You are a test execution specialist. Run tests and provide clear analysis of results.&quot;,\n        tools: [&quot;Bash&quot;, &quot;Read&quot;, &quot;Grep&quot;]\n      }\n    }\n  }\n})) {\n  if (message.type === &quot;result&quot;) console.log(message.result);\n}\n</code></pre>\n<h4>AgentDefinition 配置</h4>\n<table>\n<thead>\n<tr>\n<th>字段</th>\n<th>类型</th>\n<th>必需</th>\n<th>描述</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>description</code></td>\n<td><code>string</code></td>\n<td>是</td>\n<td>何时使用此代理的自然语言描述</td>\n</tr>\n<tr>\n<td><code>prompt</code></td>\n<td><code>string</code></td>\n<td>是</td>\n<td>定义代理角色和行为的系统提示</td>\n</tr>\n<tr>\n<td><code>tools</code></td>\n<td><code>string[]</code></td>\n<td>否</td>\n<td>允许的工具列表。省略则继承所有工具</td>\n</tr>\n<tr>\n<td><code>model</code></td>\n<td><code>&#39;sonnet&#39; | &#39;opus&#39; | &#39;haiku&#39; | &#39;inherit&#39;</code></td>\n<td>否</td>\n<td>模型覆盖</td>\n</tr>\n</tbody></table>\n<h3>MCP 服务器</h3>\n<h4>stdio 传输</h4>\n<pre><code class=\"language-typescript\">import { query } from &quot;@anthropic-ai/claude-agent-sdk&quot;;\n\nfor await (const message of query({\n  prompt: &quot;List recent GitHub issues&quot;,\n  options: {\n    mcpServers: {\n      github: {\n        command: &quot;npx&quot;,\n        args: [&quot;-y&quot;, &quot;@modelcontextprotocol/server-github&quot;],\n        env: { GITHUB_TOKEN: process.env.GITHUB_TOKEN }\n      }\n    },\n    allowedTools: [&quot;mcp__github__list_issues&quot;, &quot;mcp__github__search_issues&quot;]\n  }\n})) {\n  if (message.type === &quot;result&quot;) console.log(message.result);\n}\n</code></pre>\n<h4>HTTP/SSE 传输</h4>\n<pre><code class=\"language-typescript\">for await (const message of query({\n  prompt: &quot;Search the docs&quot;,\n  options: {\n    mcpServers: {\n      &quot;docs-server&quot;: {\n        type: &quot;http&quot;,\n        url: &quot;https://code.claude.com/docs/mcp&quot;\n      }\n    },\n    allowedTools: [&quot;mcp__docs-server__*&quot;]  // 通配符允许所有工具\n  }\n})) {\n  if (message.type === &quot;result&quot;) console.log(message.result);\n}\n</code></pre>\n<h4>检查 MCP 连接状态</h4>\n<pre><code class=\"language-typescript\">for await (const message of query({ prompt: &quot;...&quot;, options })) {\n  if (message.type === &quot;system&quot; &amp;&amp; message.subtype === &quot;init&quot;) {\n    const failedServers = message.mcp_servers?.filter(\n      s =&gt; s.status !== &quot;connected&quot;\n    );\n    if (failedServers?.length &gt; 0) {\n      console.warn(&quot;Failed to connect:&quot;, failedServers);\n    }\n  }\n}\n</code></pre>\n<h3>Hooks</h3>\n<h4>PreToolUse Hook（阻止危险操作）</h4>\n<pre><code class=\"language-typescript\">import { query, HookCallback } from &quot;@anthropic-ai/claude-agent-sdk&quot;;\n\nconst protectEnvFiles: HookCallback = async (input, toolUseID, { signal }) =&gt; {\n  const preInput = input as any;\n  const toolInput = preInput.tool_input as Record&lt;string, any&gt;;\n  const filePath = toolInput?.file_path as string;\n  const fileName = filePath?.split(&quot;/&quot;).pop();\n\n  if (fileName === &quot;.env&quot;) {\n    return {\n      hookSpecificOutput: {\n        hookEventName: preInput.hook_event_name,\n        permissionDecision: &quot;deny&quot;,\n        permissionDecisionReason: &quot;Cannot modify .env files&quot;\n      }\n    };\n  }\n  return {};\n};\n\nfor await (const message of query({\n  prompt: &quot;Update the database configuration&quot;,\n  options: {\n    hooks: {\n      PreToolUse: [{ matcher: &quot;Write|Edit&quot;, hooks: [protectEnvFiles] }]\n    }\n  }\n})) {\n  console.log(message);\n}\n</code></pre>\n<h4>PostToolUse Hook（审计日志）</h4>\n<pre><code class=\"language-typescript\">import { query, HookCallback } from &quot;@anthropic-ai/claude-agent-sdk&quot;;\nimport { appendFile } from &quot;fs/promises&quot;;\n\nconst logFileChange: HookCallback = async (input, toolUseID, { signal }) =&gt; {\n  const postInput = input as any;\n  const filePath = postInput.tool_input?.file_path ?? &quot;unknown&quot;;\n  await appendFile(&quot;./audit.log&quot;, `${new Date().toISOString()}: modified ${filePath}\\n`);\n  return {};\n};\n\nfor await (const message of query({\n  prompt: &quot;Refactor utils.ts&quot;,\n  options: {\n    permissionMode: &quot;acceptEdits&quot;,\n    hooks: {\n      PostToolUse: [{ matcher: &quot;Edit|Write&quot;, hooks: [logFileChange] }]\n    }\n  }\n})) {\n  if (message.type === &quot;result&quot;) console.log(message.result);\n}\n</code></pre>\n<h4>可用的 Hooks</h4>\n<table>\n<thead>\n<tr>\n<th>Hook</th>\n<th>Python</th>\n<th>TypeScript</th>\n<th>触发时机</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>PreToolUse</code></td>\n<td>✓</td>\n<td>✓</td>\n<td>工具调用前（可阻止/修改）</td>\n</tr>\n<tr>\n<td><code>PostToolUse</code></td>\n<td>✓</td>\n<td>✓</td>\n<td>工具执行后</td>\n</tr>\n<tr>\n<td><code>PostToolUseFailure</code></td>\n<td>✓</td>\n<td>✓</td>\n<td>工具执行失败</td>\n</tr>\n<tr>\n<td><code>UserPromptSubmit</code></td>\n<td>✓</td>\n<td>✓</td>\n<td>用户提交提示时</td>\n</tr>\n<tr>\n<td><code>Stop</code></td>\n<td>✓</td>\n<td>✓</td>\n<td>Agent 停止时</td>\n</tr>\n<tr>\n<td><code>SubagentStart</code></td>\n<td>✓</td>\n<td>✓</td>\n<td>子代理启动</td>\n</tr>\n<tr>\n<td><code>SubagentStop</code></td>\n<td>✓</td>\n<td>✓</td>\n<td>子代理完成</td>\n</tr>\n<tr>\n<td><code>PreCompact</code></td>\n<td>✓</td>\n<td>✓</td>\n<td>上下文压缩前</td>\n</tr>\n<tr>\n<td><code>PermissionRequest</code></td>\n<td>✓</td>\n<td>✓</td>\n<td>显示权限对话框时</td>\n</tr>\n<tr>\n<td><code>SessionStart</code></td>\n<td>✗</td>\n<td>✓</td>\n<td>会话初始化</td>\n</tr>\n<tr>\n<td><code>SessionEnd</code></td>\n<td>✗</td>\n<td>✓</td>\n<td>会话终止</td>\n</tr>\n<tr>\n<td><code>Notification</code></td>\n<td>✓</td>\n<td>✓</td>\n<td>状态通知</td>\n</tr>\n</tbody></table>\n<h3>自定义工具</h3>\n<h4>创建自定义工具</h4>\n<pre><code class=\"language-typescript\">import { query, tool, createSdkMcpServer } from &quot;@anthropic-ai/claude-agent-sdk&quot;;\nimport { z } from &quot;zod&quot;;\n\nconst weatherServer = createSdkMcpServer({\n  name: &quot;weather-tools&quot;,\n  version: &quot;1.0.0&quot;,\n  tools: [\n    tool(\n      &quot;get_weather&quot;,\n      &quot;Get current temperature for a location&quot;,\n      {\n        latitude: z.number().describe(&quot;Latitude coordinate&quot;),\n        longitude: z.number().describe(&quot;Longitude coordinate&quot;)\n      },\n      async (args) =&gt; {\n        const response = await fetch(\n          `https://api.open-meteo.com/v1/forecast?latitude=${args.latitude}&amp;longitude=${args.longitude}&amp;current=temperature_2m`\n        );\n        const data = await response.json();\n        return {\n          content: [{\n            type: &quot;text&quot;,\n            text: `Temperature: ${data.current.temperature_2m}°C`\n          }]\n        };\n      }\n    )\n  ]\n});\n\n// 使用流式输入\nasync function* generateMessages() {\n  yield {\n    type: &quot;user&quot; as const,\n    message: {\n      role: &quot;user&quot; as const,\n      content: &quot;What&#39;s the weather in San Francisco?&quot;\n    }\n  };\n}\n\nfor await (const message of query({\n  prompt: generateMessages(),\n  options: {\n    mcpServers: { &quot;weather-tools&quot;: weatherServer },\n    allowedTools: [&quot;mcp__weather-tools__get_weather&quot;]\n  }\n})) {\n  if (message.type === &quot;result&quot;) console.log(message.result);\n}\n</code></pre>\n<h3>流式响应</h3>\n<h4>启用流式输出</h4>\n<pre><code class=\"language-typescript\">import { query } from &quot;@anthropic-ai/claude-agent-sdk&quot;;\n\nfor await (const message of query({\n  prompt: &quot;Explain how databases work&quot;,\n  options: {\n    includePartialMessages: true,\n    allowedTools: [&quot;Bash&quot;, &quot;Read&quot;]\n  }\n})) {\n  if (message.type === &quot;stream_event&quot;) {\n    const event = message.event;\n    if (event.type === &quot;content_block_delta&quot; &amp;&amp; event.delta.type === &quot;text_delta&quot;) {\n      process.stdout.write(event.delta.text);\n    }\n  }\n}\n</code></pre>\n<h4>流式事件类型</h4>\n<table>\n<thead>\n<tr>\n<th>事件类型</th>\n<th>描述</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>message_start</code></td>\n<td>新消息开始</td>\n</tr>\n<tr>\n<td><code>content_block_start</code></td>\n<td>内容块开始（文本或工具使用）</td>\n</tr>\n<tr>\n<td><code>content_block_delta</code></td>\n<td>增量内容更新</td>\n</tr>\n<tr>\n<td><code>content_block_stop</code></td>\n<td>内容块结束</td>\n</tr>\n<tr>\n<td><code>message_delta</code></td>\n<td>消息级更新（停止原因、用量）</td>\n</tr>\n<tr>\n<td><code>message_stop</code></td>\n<td>消息结束</td>\n</tr>\n</tbody></table>\n<h3>结构化输出</h3>\n<h4>JSON Schema 方式</h4>\n<pre><code class=\"language-typescript\">import { query } from &quot;@anthropic-ai/claude-agent-sdk&quot;;\n\nconst schema = {\n  type: &quot;object&quot;,\n  properties: {\n    company_name: { type: &quot;string&quot; },\n    founded_year: { type: &quot;number&quot; },\n    headquarters: { type: &quot;string&quot; }\n  },\n  required: [&quot;company_name&quot;]\n};\n\nfor await (const message of query({\n  prompt: &quot;Research Anthropic and provide key company information&quot;,\n  options: {\n    outputFormat: { type: &quot;json_schema&quot;, schema }\n  }\n})) {\n  if (message.type === &quot;result&quot; &amp;&amp; message.structured_output) {\n    console.log(message.structured_output);\n    // { company_name: &quot;Anthropic&quot;, founded_year: 2021, headquarters: &quot;San Francisco&quot; }\n  }\n}\n</code></pre>\n<h4>Zod 方式（推荐）</h4>\n<pre><code class=\"language-typescript\">import { z } from &quot;zod&quot;;\nimport { query } from &quot;@anthropic-ai/claude-agent-sdk&quot;;\n\nconst FeaturePlan = z.object({\n  feature_name: z.string(),\n  summary: z.string(),\n  steps: z.array(z.object({\n    step_number: z.number(),\n    description: z.string(),\n    estimated_complexity: z.enum([&quot;low&quot;, &quot;medium&quot;, &quot;high&quot;])\n  })),\n  risks: z.array(z.string())\n});\n\ntype FeaturePlan = z.infer&lt;typeof FeaturePlan&gt;;\n\nfor await (const message of query({\n  prompt: &quot;Plan how to add dark mode support to a React app&quot;,\n  options: {\n    outputFormat: {\n      type: &quot;json_schema&quot;,\n      schema: z.toJSONSchema(FeaturePlan)\n    }\n  }\n})) {\n  if (message.type === &quot;result&quot; &amp;&amp; message.structured_output) {\n    const parsed = FeaturePlan.safeParse(message.structured_output);\n    if (parsed.success) {\n      const plan: FeaturePlan = parsed.data;\n      console.log(`Feature: ${plan.feature_name}`);\n      plan.steps.forEach(step =&gt; {\n        console.log(`${step.step_number}. [${step.estimated_complexity}] ${step.description}`);\n      });\n    }\n  }\n}\n</code></pre>\n<h3>处理结果</h3>\n<h4>结果子类型</h4>\n<pre><code class=\"language-typescript\">for await (const message of query({ prompt: &quot;...&quot;, options: {} })) {\n  if (message.type === &quot;result&quot;) {\n    switch (message.subtype) {\n      case &quot;success&quot;:\n        console.log(&quot;Result:&quot;, message.result);\n        console.log(&quot;Cost:&quot;, message.total_cost_usd);\n        break;\n      case &quot;error_max_turns&quot;:\n        console.log(&quot;Hit turn limit. Resume session to continue.&quot;);\n        break;\n      case &quot;error_max_budget_usd&quot;:\n        console.log(&quot;Hit budget limit.&quot;);\n        break;\n      case &quot;error_during_execution&quot;:\n        console.log(&quot;Execution error occurred.&quot;);\n        break;\n      case &quot;error_max_structured_output_retries&quot;:\n        console.log(&quot;Failed to generate valid structured output.&quot;);\n        break;\n    }\n  }\n}\n</code></pre>\n<h3>参考文档</h3>\n<ul>\n<li><a href=\"./references/quickstart.md\">快速开始指南</a></li>\n<li><a href=\"./references/agent-loop.md\">Agent 循环详解</a></li>\n<li><a href=\"./references/sessions.md\">会话管理</a></li>\n<li><a href=\"./references/subagents.md\">子代理</a></li>\n<li><a href=\"./references/hooks.md\">Hooks 系统</a></li>\n<li><a href=\"./references/mcp.md\">MCP 服务器集成</a></li>\n<li><a href=\"./references/custom-tools.md\">自定义工具</a></li>\n<li><a href=\"./references/streaming.md\">流式响应</a></li>\n<li><a href=\"./references/structured-outputs.md\">结构化输出</a></li>\n<li><a href=\"./references/permissions.md\">权限配置</a></li>\n</ul>\n",
  "cloudflare-deploy": "<h2>Cloudflare Deploy</h2>\n<p>Consolidated skill for building on the Cloudflare platform. Use decision trees below to find the right product, then load detailed references.</p>\n<h3>Prerequisites</h3>\n<ul>\n<li>When sandboxing blocks the deployment network calls, rerun with <code>sandbox_permissions=require_escalated</code>.</li>\n<li>The deployment might take a few minutes. Use appropriate timeout values.</li>\n</ul>\n<h3>Authentication (Required Before Deploy)</h3>\n<p>Verify auth before <code>wrangler deploy</code>, <code>wrangler pages deploy</code>, or <code>npm run deploy</code>:</p>\n<pre><code class=\"language-bash\">npx wrangler whoami    # Shows account if authenticated\n</code></pre>\n<p>Not authenticated? → <code>references/wrangler/auth.md</code></p>\n<ul>\n<li>Interactive/local: <code>wrangler login</code> (one-time OAuth)</li>\n<li>CI/CD: Set <code>CLOUDFLARE_API_TOKEN</code> env var</li>\n</ul>\n<h3>Quick Decision Trees</h3>\n<h4>&quot;I need to run code&quot;</h4>\n<pre><code>Need to run code?\n├─ Serverless functions at the edge → workers/\n├─ Full-stack web app with Git deploys → pages/\n├─ Stateful coordination/real-time → durable-objects/\n├─ Long-running multi-step jobs → workflows/\n├─ Run containers → containers/\n├─ Multi-tenant (customers deploy code) → workers-for-platforms/\n├─ Scheduled tasks (cron) → cron-triggers/\n├─ Lightweight edge logic (modify HTTP) → snippets/\n├─ Process Worker execution events (logs/observability) → tail-workers/\n└─ Optimize latency to backend infrastructure → smart-placement/\n</code></pre>\n<h4>&quot;I need to store data&quot;</h4>\n<pre><code>Need storage?\n├─ Key-value (config, sessions, cache) → kv/\n├─ Relational SQL → d1/ (SQLite) or hyperdrive/ (existing Postgres/MySQL)\n├─ Object/file storage (S3-compatible) → r2/\n├─ Message queue (async processing) → queues/\n├─ Vector embeddings (AI/semantic search) → vectorize/\n├─ Strongly-consistent per-entity state → durable-objects/ (DO storage)\n├─ Secrets management → secrets-store/\n├─ Streaming ETL to R2 → pipelines/\n└─ Persistent cache (long-term retention) → cache-reserve/\n</code></pre>\n<h4>&quot;I need AI/ML&quot;</h4>\n<pre><code>Need AI?\n├─ Run inference (LLMs, embeddings, images) → workers-ai/\n├─ Vector database for RAG/search → vectorize/\n├─ Build stateful AI agents → agents-sdk/\n├─ Gateway for any AI provider (caching, routing) → ai-gateway/\n└─ AI-powered search widget → ai-search/\n</code></pre>\n<h4>&quot;I need networking/connectivity&quot;</h4>\n<pre><code>Need networking?\n├─ Expose local service to internet → tunnel/\n├─ TCP/UDP proxy (non-HTTP) → spectrum/\n├─ WebRTC TURN server → turn/\n├─ Private network connectivity → network-interconnect/\n├─ Optimize routing → argo-smart-routing/\n├─ Optimize latency to backend (not user) → smart-placement/\n└─ Real-time video/audio → realtimekit/ or realtime-sfu/\n</code></pre>\n<h4>&quot;I need security&quot;</h4>\n<pre><code>Need security?\n├─ Web Application Firewall → waf/\n├─ DDoS protection → ddos/\n├─ Bot detection/management → bot-management/\n├─ API protection → api-shield/\n├─ CAPTCHA alternative → turnstile/\n└─ Credential leak detection → waf/ (managed ruleset)\n</code></pre>\n<h4>&quot;I need media/content&quot;</h4>\n<pre><code>Need media?\n├─ Image optimization/transformation → images/\n├─ Video streaming/encoding → stream/\n├─ Browser automation/screenshots → browser-rendering/\n└─ Third-party script management → zaraz/\n</code></pre>\n<h4>&quot;I need infrastructure-as-code&quot;</h4>\n<pre><code>Need IaC? → pulumi/ (Pulumi), terraform/ (Terraform), or api/ (REST API)\n</code></pre>\n<h3>Product Index</h3>\n<h4>Compute &amp; Runtime</h4>\n<table>\n<thead>\n<tr>\n<th>Product</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Workers</td>\n<td><code>references/workers/</code></td>\n</tr>\n<tr>\n<td>Pages</td>\n<td><code>references/pages/</code></td>\n</tr>\n<tr>\n<td>Pages Functions</td>\n<td><code>references/pages-functions/</code></td>\n</tr>\n<tr>\n<td>Durable Objects</td>\n<td><code>references/durable-objects/</code></td>\n</tr>\n<tr>\n<td>Workflows</td>\n<td><code>references/workflows/</code></td>\n</tr>\n<tr>\n<td>Containers</td>\n<td><code>references/containers/</code></td>\n</tr>\n<tr>\n<td>Workers for Platforms</td>\n<td><code>references/workers-for-platforms/</code></td>\n</tr>\n<tr>\n<td>Cron Triggers</td>\n<td><code>references/cron-triggers/</code></td>\n</tr>\n<tr>\n<td>Tail Workers</td>\n<td><code>references/tail-workers/</code></td>\n</tr>\n<tr>\n<td>Snippets</td>\n<td><code>references/snippets/</code></td>\n</tr>\n<tr>\n<td>Smart Placement</td>\n<td><code>references/smart-placement/</code></td>\n</tr>\n</tbody></table>\n<h4>Storage &amp; Data</h4>\n<table>\n<thead>\n<tr>\n<th>Product</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>KV</td>\n<td><code>references/kv/</code></td>\n</tr>\n<tr>\n<td>D1</td>\n<td><code>references/d1/</code></td>\n</tr>\n<tr>\n<td>R2</td>\n<td><code>references/r2/</code></td>\n</tr>\n<tr>\n<td>Queues</td>\n<td><code>references/queues/</code></td>\n</tr>\n<tr>\n<td>Hyperdrive</td>\n<td><code>references/hyperdrive/</code></td>\n</tr>\n<tr>\n<td>DO Storage</td>\n<td><code>references/do-storage/</code></td>\n</tr>\n<tr>\n<td>Secrets Store</td>\n<td><code>references/secrets-store/</code></td>\n</tr>\n<tr>\n<td>Pipelines</td>\n<td><code>references/pipelines/</code></td>\n</tr>\n<tr>\n<td>R2 Data Catalog</td>\n<td><code>references/r2-data-catalog/</code></td>\n</tr>\n<tr>\n<td>R2 SQL</td>\n<td><code>references/r2-sql/</code></td>\n</tr>\n</tbody></table>\n<h4>AI &amp; Machine Learning</h4>\n<table>\n<thead>\n<tr>\n<th>Product</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Workers AI</td>\n<td><code>references/workers-ai/</code></td>\n</tr>\n<tr>\n<td>Vectorize</td>\n<td><code>references/vectorize/</code></td>\n</tr>\n<tr>\n<td>Agents SDK</td>\n<td><code>references/agents-sdk/</code></td>\n</tr>\n<tr>\n<td>AI Gateway</td>\n<td><code>references/ai-gateway/</code></td>\n</tr>\n<tr>\n<td>AI Search</td>\n<td><code>references/ai-search/</code></td>\n</tr>\n</tbody></table>\n<h4>Networking &amp; Connectivity</h4>\n<table>\n<thead>\n<tr>\n<th>Product</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Tunnel</td>\n<td><code>references/tunnel/</code></td>\n</tr>\n<tr>\n<td>Spectrum</td>\n<td><code>references/spectrum/</code></td>\n</tr>\n<tr>\n<td>TURN</td>\n<td><code>references/turn/</code></td>\n</tr>\n<tr>\n<td>Network Interconnect</td>\n<td><code>references/network-interconnect/</code></td>\n</tr>\n<tr>\n<td>Argo Smart Routing</td>\n<td><code>references/argo-smart-routing/</code></td>\n</tr>\n<tr>\n<td>Workers VPC</td>\n<td><code>references/workers-vpc/</code></td>\n</tr>\n</tbody></table>\n<h4>Security</h4>\n<table>\n<thead>\n<tr>\n<th>Product</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>WAF</td>\n<td><code>references/waf/</code></td>\n</tr>\n<tr>\n<td>DDoS Protection</td>\n<td><code>references/ddos/</code></td>\n</tr>\n<tr>\n<td>Bot Management</td>\n<td><code>references/bot-management/</code></td>\n</tr>\n<tr>\n<td>API Shield</td>\n<td><code>references/api-shield/</code></td>\n</tr>\n<tr>\n<td>Turnstile</td>\n<td><code>references/turnstile/</code></td>\n</tr>\n</tbody></table>\n<h4>Media &amp; Content</h4>\n<table>\n<thead>\n<tr>\n<th>Product</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Images</td>\n<td><code>references/images/</code></td>\n</tr>\n<tr>\n<td>Stream</td>\n<td><code>references/stream/</code></td>\n</tr>\n<tr>\n<td>Browser Rendering</td>\n<td><code>references/browser-rendering/</code></td>\n</tr>\n<tr>\n<td>Zaraz</td>\n<td><code>references/zaraz/</code></td>\n</tr>\n</tbody></table>\n<h4>Real-Time Communication</h4>\n<table>\n<thead>\n<tr>\n<th>Product</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>RealtimeKit</td>\n<td><code>references/realtimekit/</code></td>\n</tr>\n<tr>\n<td>Realtime SFU</td>\n<td><code>references/realtime-sfu/</code></td>\n</tr>\n</tbody></table>\n<h4>Developer Tools</h4>\n<table>\n<thead>\n<tr>\n<th>Product</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Wrangler</td>\n<td><code>references/wrangler/</code></td>\n</tr>\n<tr>\n<td>Miniflare</td>\n<td><code>references/miniflare/</code></td>\n</tr>\n<tr>\n<td>C3</td>\n<td><code>references/c3/</code></td>\n</tr>\n<tr>\n<td>Observability</td>\n<td><code>references/observability/</code></td>\n</tr>\n<tr>\n<td>Analytics Engine</td>\n<td><code>references/analytics-engine/</code></td>\n</tr>\n<tr>\n<td>Web Analytics</td>\n<td><code>references/web-analytics/</code></td>\n</tr>\n<tr>\n<td>Sandbox</td>\n<td><code>references/sandbox/</code></td>\n</tr>\n<tr>\n<td>Workerd</td>\n<td><code>references/workerd/</code></td>\n</tr>\n<tr>\n<td>Workers Playground</td>\n<td><code>references/workers-playground/</code></td>\n</tr>\n</tbody></table>\n<h4>Infrastructure as Code</h4>\n<table>\n<thead>\n<tr>\n<th>Product</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Pulumi</td>\n<td><code>references/pulumi/</code></td>\n</tr>\n<tr>\n<td>Terraform</td>\n<td><code>references/terraform/</code></td>\n</tr>\n<tr>\n<td>API</td>\n<td><code>references/api/</code></td>\n</tr>\n</tbody></table>\n<h4>Other Services</h4>\n<table>\n<thead>\n<tr>\n<th>Product</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Email Routing</td>\n<td><code>references/email-routing/</code></td>\n</tr>\n<tr>\n<td>Email Workers</td>\n<td><code>references/email-workers/</code></td>\n</tr>\n<tr>\n<td>Static Assets</td>\n<td><code>references/static-assets/</code></td>\n</tr>\n<tr>\n<td>Bindings</td>\n<td><code>references/bindings/</code></td>\n</tr>\n<tr>\n<td>Cache Reserve</td>\n<td><code>references/cache-reserve/</code></td>\n</tr>\n</tbody></table>\n<h3>Troubleshooting</h3>\n<h4>Escalated Network Access</h4>\n<p>If deployment fails due to network issues (timeouts, DNS errors, connection resets), rerun the deploy with escalated permissions (use <code>sandbox_permissions=require_escalated</code>). The deploy requires escalated network access when sandbox networking blocks outbound requests.</p>\n<p>Example guidance to the user:</p>\n<pre><code>The deploy needs escalated network access to deploy to Cloudflare. I can rerun the command with escalated permissions—want me to proceed?\n</code></pre>\n",
  "composition-patterns": "<h2>React Composition Patterns</h2>\n<p>Composition patterns for building flexible, maintainable React components. Avoid\nboolean prop proliferation by using compound components, lifting state, and\ncomposing internals. These patterns make codebases easier for both humans and AI\nagents to work with as they scale.</p>\n<h3>When to Apply</h3>\n<p>Reference these guidelines when:</p>\n<ul>\n<li>Refactoring components with many boolean props</li>\n<li>Building reusable component libraries</li>\n<li>Designing flexible component APIs</li>\n<li>Reviewing component architecture</li>\n<li>Working with compound components or context providers</li>\n</ul>\n<h3>Rule Categories by Priority</h3>\n<table>\n<thead>\n<tr>\n<th>Priority</th>\n<th>Category</th>\n<th>Impact</th>\n<th>Prefix</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>1</td>\n<td>Component Architecture</td>\n<td>HIGH</td>\n<td><code>architecture-</code></td>\n</tr>\n<tr>\n<td>2</td>\n<td>State Management</td>\n<td>MEDIUM</td>\n<td><code>state-</code></td>\n</tr>\n<tr>\n<td>3</td>\n<td>Implementation Patterns</td>\n<td>MEDIUM</td>\n<td><code>patterns-</code></td>\n</tr>\n<tr>\n<td>4</td>\n<td>React 19 APIs</td>\n<td>MEDIUM</td>\n<td><code>react19-</code></td>\n</tr>\n</tbody></table>\n<h3>Quick Reference</h3>\n<h4>1. Component Architecture (HIGH)</h4>\n<ul>\n<li><code>architecture-avoid-boolean-props</code> - Don&#39;t add boolean props to customize\nbehavior; use composition</li>\n<li><code>architecture-compound-components</code> - Structure complex components with shared\ncontext</li>\n</ul>\n<h4>2. State Management (MEDIUM)</h4>\n<ul>\n<li><code>state-decouple-implementation</code> - Provider is the only place that knows how\nstate is managed</li>\n<li><code>state-context-interface</code> - Define generic interface with state, actions, meta\nfor dependency injection</li>\n<li><code>state-lift-state</code> - Move state into provider components for sibling access</li>\n</ul>\n<h4>3. Implementation Patterns (MEDIUM)</h4>\n<ul>\n<li><code>patterns-explicit-variants</code> - Create explicit variant components instead of\nboolean modes</li>\n<li><code>patterns-children-over-render-props</code> - Use children for composition instead\nof renderX props</li>\n</ul>\n<h4>4. React 19 APIs (MEDIUM)</h4>\n<blockquote>\n<p><strong>⚠️ React 19+ only.</strong> Skip this section if using React 18 or earlier.</p>\n</blockquote>\n<ul>\n<li><code>react19-no-forwardref</code> - Don&#39;t use <code>forwardRef</code>; use <code>use()</code> instead of <code>useContext()</code></li>\n</ul>\n<h3>How to Use</h3>\n<p>Read individual rule files for detailed explanations and code examples:</p>\n<pre><code>rules/architecture-avoid-boolean-props.md\nrules/state-context-interface.md\n</code></pre>\n<p>Each rule file contains:</p>\n<ul>\n<li>Brief explanation of why it matters</li>\n<li>Incorrect code example with explanation</li>\n<li>Correct code example with explanation</li>\n<li>Additional context and references</li>\n</ul>\n<h3>Full Compiled Document</h3>\n<p>For the complete guide with all rules expanded: <code>AGENTS.md</code></p>\n",
  "cover-image": "<h2>Cover Image Prompt Generator</h2>\n<p>Generate structured prompts for article cover images with 5-dimensional customization.</p>\n<h3>Usage</h3>\n<pre><code class=\"language-bash\"># Auto-select dimensions based on content\n/cover-image path/to/article.md\n\n# Quick mode: skip confirmation\n/cover-image article.md --quick\n\n# Specify dimensions\n/cover-image article.md --type conceptual --palette warm --rendering flat-vector\n\n# Style presets (shorthand for palette + rendering)\n/cover-image article.md --style blueprint\n\n# With reference images\n/cover-image article.md --ref style-ref.png\n\n# Direct content input\n/cover-image --palette mono --aspect 1:1 --quick\n[paste content]\n</code></pre>\n<h3>Options</h3>\n<table>\n<thead>\n<tr>\n<th>Option</th>\n<th>Description</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>--type &lt;name&gt;</code></td>\n<td>hero, conceptual, typography, metaphor, scene, minimal</td>\n</tr>\n<tr>\n<td><code>--palette &lt;name&gt;</code></td>\n<td>warm, elegant, cool, dark, earth, vivid, pastel, mono, retro, duotone</td>\n</tr>\n<tr>\n<td><code>--rendering &lt;name&gt;</code></td>\n<td>flat-vector, hand-drawn, painterly, digital, pixel, chalk, screen-print</td>\n</tr>\n<tr>\n<td><code>--style &lt;name&gt;</code></td>\n<td>Preset shorthand (see <a href=\"references/style-presets.md\">Style Presets</a>)</td>\n</tr>\n<tr>\n<td><code>--text &lt;level&gt;</code></td>\n<td>none, title-only, title-subtitle, text-rich</td>\n</tr>\n<tr>\n<td><code>--mood &lt;level&gt;</code></td>\n<td>subtle, balanced, bold</td>\n</tr>\n<tr>\n<td><code>--font &lt;name&gt;</code></td>\n<td>clean, handwritten, serif, display</td>\n</tr>\n<tr>\n<td><code>--aspect &lt;ratio&gt;</code></td>\n<td>16:9 (default), 2.35:1, 4:3, 3:2, 1:1, 3:4</td>\n</tr>\n<tr>\n<td><code>--lang &lt;code&gt;</code></td>\n<td>Title language (en, zh, ja, etc.)</td>\n</tr>\n<tr>\n<td><code>--no-title</code></td>\n<td>Alias for <code>--text none</code></td>\n</tr>\n<tr>\n<td><code>--quick</code></td>\n<td>Skip confirmation, use auto-selection</td>\n</tr>\n<tr>\n<td><code>--ref &lt;files...&gt;</code></td>\n<td>Reference images for style/composition guidance</td>\n</tr>\n</tbody></table>\n<h3>Five Dimensions</h3>\n<table>\n<thead>\n<tr>\n<th>Dimension</th>\n<th>Values</th>\n<th>Default</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><strong>Type</strong></td>\n<td>hero, conceptual, typography, metaphor, scene, minimal</td>\n<td>auto</td>\n</tr>\n<tr>\n<td><strong>Palette</strong></td>\n<td>warm, elegant, cool, dark, earth, vivid, pastel, mono, retro, duotone</td>\n<td>auto</td>\n</tr>\n<tr>\n<td><strong>Rendering</strong></td>\n<td>flat-vector, hand-drawn, painterly, digital, pixel, chalk, screen-print</td>\n<td>auto</td>\n</tr>\n<tr>\n<td><strong>Text</strong></td>\n<td>none, title-only, title-subtitle, text-rich</td>\n<td>title-only</td>\n</tr>\n<tr>\n<td><strong>Mood</strong></td>\n<td>subtle, balanced, bold</td>\n<td>balanced</td>\n</tr>\n<tr>\n<td><strong>Font</strong></td>\n<td>clean, handwritten, serif, display</td>\n<td>clean</td>\n</tr>\n</tbody></table>\n<p>Auto-selection rules: <a href=\"references/auto-selection.md\">references/auto-selection.md</a></p>\n<h3>Galleries</h3>\n<p><strong>Types</strong>: hero, conceptual, typography, metaphor, scene, minimal\n→ Details: <a href=\"references/types.md\">references/types.md</a></p>\n<p><strong>Palettes</strong>: warm, elegant, cool, dark, earth, vivid, pastel, mono, retro, duotone\n→ Details: <a href=\"references/palettes/\">references/palettes/</a></p>\n<p><strong>Renderings</strong>: flat-vector, hand-drawn, painterly, digital, pixel, chalk, screen-print\n→ Details: <a href=\"references/renderings/\">references/renderings/</a></p>\n<p><strong>Text Levels</strong>: none (pure visual) | title-only (default) | title-subtitle | text-rich (with tags)\n→ Details: <a href=\"references/dimensions/text.md\">references/dimensions/text.md</a></p>\n<p><strong>Mood Levels</strong>: subtle (low contrast) | balanced (default) | bold (high contrast)\n→ Details: <a href=\"references/dimensions/mood.md\">references/dimensions/mood.md</a></p>\n<p><strong>Fonts</strong>: clean (sans-serif) | handwritten | serif | display (bold decorative)\n→ Details: <a href=\"references/dimensions/font.md\">references/dimensions/font.md</a></p>\n<h3>File Structure</h3>\n<p>Cover prompt is generated in the same directory as the article. Do NOT copy articles to other directories.</p>\n<pre><code>{article-dir}/\n├── article.md             # Original article (not copied)\n├── cover.md               # Generated prompt\n├── cover-1.md             # Conflict variant (if cover.md exists)\n├── refs/                  # Reference images (if provided)\n│   ├── ref-01-{slug}.{ext}\n│   └── ref-01-{slug}.md   # Description file\n└── ...\n</code></pre>\n<p><strong>Cover filename</strong>: <code>cover.md</code>. If exists: <code>cover-1.md</code>, <code>cover-2.md</code>, etc.</p>\n<p>For direct content input (no article file): generate in current working directory.</p>\n<h3>Workflow</h3>\n<h4>Progress Checklist</h4>\n<pre><code>Cover Image Progress:\n- [ ] Step 0: Check preferences (EXTEND.md) ⛔ BLOCKING\n- [ ] Step 1: Analyze content + save refs\n- [ ] Step 2: Confirm options (6 dimensions) ⚠️ unless --quick\n- [ ] Step 3: Create prompt\n- [ ] Step 4: Completion report\n</code></pre>\n<h4>Flow</h4>\n<pre><code>Input → [Step 0: Preferences] ─┬─ Found → Continue\n                               └─ Not found → First-Time Setup ⛔ BLOCKING → Save EXTEND.md → Continue\n        ↓\nAnalyze + Save Refs → [Confirm: 6 Dimensions] → Prompt → Complete\n                                              ↓\n                                     (skip if --quick or all specified)\n</code></pre>\n<h4>Step 0: Load Preferences ⛔ BLOCKING</h4>\n<p>Check EXTEND.md in project root only:</p>\n<pre><code class=\"language-bash\">test -f EXTEND.md &amp;&amp; echo &quot;found&quot;\n</code></pre>\n<table>\n<thead>\n<tr>\n<th>Result</th>\n<th>Action</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Found</td>\n<td>Load, display summary → Continue</td>\n</tr>\n<tr>\n<td>Not found</td>\n<td>Ask user for preferences → Generate EXTEND.md → Continue</td>\n</tr>\n</tbody></table>\n<p><strong>CRITICAL</strong>: If not found, complete setup BEFORE any other steps or questions. Do NOT check other directories.</p>\n<h4>Step 1: Analyze Content</h4>\n<ol>\n<li><strong>Save reference images</strong> (if provided) → <a href=\"references/workflow/reference-images.md\">references/workflow/reference-images.md</a></li>\n<li><strong>Analyze content</strong>: topic, tone, keywords, visual metaphors</li>\n<li><strong>Deep analyze references</strong> ⚠️: Extract specific, concrete elements (see reference-images.md)</li>\n<li><strong>Detect language</strong>: Compare source, user input, EXTEND.md preference</li>\n</ol>\n<p><strong>⚠️ People in Reference Images — MUST follow all 3 rules:</strong></p>\n<p>If reference images contain <strong>people</strong> who should appear in the cover:</p>\n<ol>\n<li><strong><code>usage: direct</code></strong> — MUST set in refs description file. NEVER use <code>style</code> or <code>palette</code> when people need to appear</li>\n<li><strong>Per-character description</strong> — MUST describe each person&#39;s distinctive features (hair, glasses, skin tone, clothing) in <code>refs/ref-NN-{slug}.md</code>. Vague descriptions like &quot;a man&quot; will fail</li>\n<li><strong>Prompt inclusion</strong> — MUST include reference image paths in prompt frontmatter <code>references</code> list so the downstream image generator can access them</li>\n</ol>\n<p>See <a href=\"references/workflow/reference-images.md\">reference-images.md § Character Analysis</a> for description format.</p>\n<h4>Step 2: Confirm Options ⚠️</h4>\n<p><strong>MUST use <code>AskUserQuestion</code> tool</strong> to present options as interactive selection — NOT plain text tables. Present up to 4 questions in a single <code>AskUserQuestion</code> call (Type, Palette, Rendering, Font + Settings). Each question shows the recommended option first with reason, followed by alternatives.</p>\n<p>Full confirmation flow and question format: <a href=\"references/workflow/confirm-options.md\">references/workflow/confirm-options.md</a></p>\n<table>\n<thead>\n<tr>\n<th>Condition</th>\n<th>Skipped</th>\n<th>Still Asked</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>--quick</code> or <code>quick_mode: true</code></td>\n<td>6 dimensions</td>\n<td>Aspect ratio (unless <code>--aspect</code>)</td>\n</tr>\n<tr>\n<td>All 6 + <code>--aspect</code> specified</td>\n<td>All</td>\n<td>None</td>\n</tr>\n</tbody></table>\n<h4>Step 3: Create Prompt</h4>\n<p>Save to article directory as <code>cover.md</code>. Template: <a href=\"references/workflow/prompt-template.md\">references/workflow/prompt-template.md</a></p>\n<p><strong>Filename conflict</strong>: If <code>cover.md</code> exists, use <code>cover-1.md</code>, <code>cover-2.md</code>, etc. Check before writing.</p>\n<p><strong>CRITICAL - References in Frontmatter</strong>:</p>\n<ul>\n<li>Files saved to <code>refs/</code> → Add to frontmatter <code>references</code> list</li>\n<li>Style extracted verbally (no file) → Omit <code>references</code>, describe in body</li>\n<li>Before writing → Verify: <code>test -f refs/ref-NN-{slug}.{ext}</code></li>\n</ul>\n<p><strong>Reference elements in body</strong> MUST be detailed, prefixed with &quot;MUST&quot;/&quot;REQUIRED&quot;, with integration approach.</p>\n<h4>Step 4: Completion Report</h4>\n<pre><code>Prompt Ready!\n\nTopic: [topic]\nType: [type] | Palette: [palette] | Rendering: [rendering]\nText: [text] | Mood: [mood] | Font: [font] | Aspect: [ratio]\nTitle: [title or &quot;visual only&quot;]\nLanguage: [lang] | Watermark: [enabled/disabled]\nReferences: [N images or &quot;extracted style&quot; or &quot;none&quot;]\nLocation: [article directory path]\n\nFiles:\n✓ cover.md (or cover-N.md)\n</code></pre>\n<h3>Composition Principles</h3>\n<ul>\n<li><strong>Whitespace</strong>: 40-60% breathing room</li>\n<li><strong>Visual anchor</strong>: Main element centered or offset left</li>\n<li><strong>Characters</strong>: Simplified silhouettes; NO realistic humans</li>\n<li><strong>Title</strong>: Use exact title from user/source; never invent</li>\n</ul>\n<h3>Extension Support</h3>\n<p>Custom configurations via EXTEND.md. See <strong>Step 0</strong> for paths.</p>\n<p>Supports: Watermark | Preferred dimensions | Default aspect | Quick mode | Custom palettes | Language</p>\n<p>Schema: <a href=\"references/config/preferences-schema.md\">references/config/preferences-schema.md</a></p>\n<h3>References</h3>\n<p><strong>Dimensions</strong>: <a href=\"references/dimensions/text.md\">text.md</a> | <a href=\"references/dimensions/mood.md\">mood.md</a> | <a href=\"references/dimensions/font.md\">font.md</a>\n<strong>Palettes</strong>: <a href=\"references/palettes/\">references/palettes/</a>\n<strong>Renderings</strong>: <a href=\"references/renderings/\">references/renderings/</a>\n<strong>Types</strong>: <a href=\"references/types.md\">references/types.md</a>\n<strong>Auto-Selection</strong>: <a href=\"references/auto-selection.md\">references/auto-selection.md</a>\n<strong>Style Presets</strong>: <a href=\"references/style-presets.md\">references/style-presets.md</a>\n<strong>Compatibility</strong>: <a href=\"references/compatibility.md\">references/compatibility.md</a>\n<strong>Visual Elements</strong>: <a href=\"references/visual-elements.md\">references/visual-elements.md</a>\n<strong>Workflow</strong>: <a href=\"references/workflow/confirm-options.md\">confirm-options.md</a> | <a href=\"references/workflow/prompt-template.md\">prompt-template.md</a> | <a href=\"references/workflow/reference-images.md\">reference-images.md</a>\n<strong>Config</strong>: <a href=\"references/config/preferences-schema.md\">preferences-schema.md</a> | <a href=\"references/config/first-time-setup.md\">first-time-setup.md</a> | <a href=\"references/config/watermark-guide.md\">watermark-guide.md</a></p>\n",
  "db-ferry": "<h2>db-ferry 数据迁移 Skill</h2>\n<h3>触发场景</h3>\n<ul>\n<li>用户提及 &quot;数据库迁移&quot;、&quot;数据搬运&quot;、&quot;db-ferry&quot;</li>\n<li>需要在不同数据库之间移动/同步数据</li>\n<li>用户提供了一个 <code>task.toml</code> 文件需要修改或排查</li>\n<li>询问如何将某个数据库的数据迁移到另一个数据库</li>\n</ul>\n<h3>快速概览</h3>\n<p>db-ferry 是一个声明式 CLI 工具（Go 编写），通过 TOML 配置文件定义迁移任务，支持 Oracle/MySQL/PostgreSQL/SQL Server/SQLite/DuckDB 之间的数据搬运。工具自动创建目标表结构、批量插入、可选创建索引、支持进度条显示。独立任务按 DAG 自动并行执行。0.9.0 新增 Prometheus/OTLP 指标导出、数据质量断言、守护进程模式、Lua/JS 行级插件、S3/GCS DLQ、跨库内存 JOIN、Webhook 通知、SSE 实时进度流等能力。</p>\n<h3>配置文件生成流程</h3>\n<h4>Step 1: 理解用户需求</h4>\n<p>确认以下信息：</p>\n<ul>\n<li><strong>源数据库</strong>：类型、连接信息、需要迁移的表/SQL 查询</li>\n<li><strong>目标数据库</strong>：类型、连接信息、目标表名</li>\n<li><strong>迁移范围</strong>：全表/部分字段/条件过滤</li>\n<li><strong>写入模式</strong>：替换(默认)/追加/合并(upsert)</li>\n<li><strong>是否有索引需求</strong></li>\n</ul>\n<h4>Step 2: 生成 <code>[[databases]]</code> 配置</h4>\n<p>每个数据库需要一个唯一 <code>name</code> 作为别名。各类型必填字段如下：</p>\n<table>\n<thead>\n<tr>\n<th>类型</th>\n<th>必填字段</th>\n<th>选填字段</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>oracle</code></td>\n<td>name, type, host, service, user, password</td>\n<td>port (默认1521)</td>\n</tr>\n<tr>\n<td><code>mysql</code></td>\n<td>name, type, host, database, user, password</td>\n<td>port (默认3306)</td>\n</tr>\n<tr>\n<td><code>postgresql</code></td>\n<td>name, type, host, database, user, password</td>\n<td>port (默认5432)</td>\n</tr>\n<tr>\n<td><code>sqlserver</code></td>\n<td>name, type, host, database, user, password</td>\n<td>port (默认1433)</td>\n</tr>\n<tr>\n<td><code>sqlite</code></td>\n<td>name, type, path</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>duckdb</code></td>\n<td>name, type, path</td>\n<td>支持 <code>:memory:</code></td>\n</tr>\n</tbody></table>\n<p>注意：SQLite 和 DuckDB 只需要 <code>path</code>，不需要 host/port/user/password。</p>\n<p>连接池与副本（可选）：</p>\n<table>\n<thead>\n<tr>\n<th>字段</th>\n<th>说明</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>pool_max_open</code></td>\n<td>连接池最大打开连接数</td>\n</tr>\n<tr>\n<td><code>pool_max_idle</code></td>\n<td>连接池最大空闲连接数</td>\n</tr>\n<tr>\n<td><code>replica_fallback</code></td>\n<td>副本不可用时是否回退到主库</td>\n</tr>\n<tr>\n<td><code>[[databases.replicas]]</code></td>\n<td>只读副本，含 <code>host</code>（可选 <code>port</code>）和 <code>priority</code></td>\n</tr>\n</tbody></table>\n<p>TLS/SSL（可选）：</p>\n<table>\n<thead>\n<tr>\n<th>字段</th>\n<th>说明</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>ssl_mode</code></td>\n<td><code>disable</code> / <code>require</code> / <code>verify-ca</code> / <code>verify-full</code></td>\n</tr>\n<tr>\n<td><code>ssl_cert</code></td>\n<td>客户端证书路径</td>\n</tr>\n<tr>\n<td><code>ssl_key</code></td>\n<td>客户端私钥路径</td>\n</tr>\n<tr>\n<td><code>ssl_root_cert</code></td>\n<td>CA 根证书路径</td>\n</tr>\n</tbody></table>\n<h4>Step 3: 生成 <code>[[tasks]]</code> 配置</h4>\n<p>每个任务必填字段：</p>\n<table>\n<thead>\n<tr>\n<th>字段</th>\n<th>说明</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>table_name</code></td>\n<td>目标表名（迁移前会自动 drop/create）</td>\n</tr>\n<tr>\n<td><code>sql</code></td>\n<td>源库 SQL 查询语句</td>\n</tr>\n<tr>\n<td><code>source_db</code></td>\n<td>引用 <code>[[databases]]</code> 中的别名</td>\n</tr>\n<tr>\n<td><code>target_db</code></td>\n<td>引用 <code>[[databases]]</code> 中的别名</td>\n</tr>\n</tbody></table>\n<p>可选字段：</p>\n<table>\n<thead>\n<tr>\n<th>字段</th>\n<th>说明</th>\n<th>默认值</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>ignore</code></td>\n<td>设为 true 跳过此任务</td>\n<td>false</td>\n</tr>\n<tr>\n<td><code>mode</code></td>\n<td>写入模式: replace/append/merge/upsert</td>\n<td>replace</td>\n</tr>\n<tr>\n<td><code>batch_size</code></td>\n<td>每批插入行数</td>\n<td>1000</td>\n</tr>\n<tr>\n<td><code>max_retries</code></td>\n<td>批量插入失败重试次数</td>\n<td>0</td>\n</tr>\n<tr>\n<td><code>validate</code></td>\n<td>迁移后校验: none/row_count/checksum/sample</td>\n<td>none</td>\n</tr>\n<tr>\n<td><code>merge_keys</code></td>\n<td>merge/upsert 模式的匹配键（必填）</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>resume_key</code></td>\n<td>增量续传的字段名</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>resume_from</code></td>\n<td>增量起点 SQL 字面量</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>state_file</code></td>\n<td>断点状态文件路径（JSON）</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>allow_same_table</code></td>\n<td>允许源库=目标库时执行（⚠️ 风险）</td>\n<td>false</td>\n</tr>\n<tr>\n<td><code>skip_create_table</code></td>\n<td>跳过目标表 drop/create</td>\n<td>false</td>\n</tr>\n<tr>\n<td><code>pre_sql</code></td>\n<td>任务执行前在目标库执行的自定义 SQL</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>post_sql</code></td>\n<td>任务执行后在目标库执行的自定义 SQL</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>dlq_path</code></td>\n<td>死信队列输出路径，隔离失败行；支持本地路径、S3（s3://）、GCS（gs://）</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>dlq_format</code></td>\n<td>死信队列格式: jsonl/csv</td>\n<td>jsonl</td>\n</tr>\n<tr>\n<td><code>depends_on</code></td>\n<td>任务依赖（按 <code>table_name</code> 声明），支持 DAG 调度</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>schema_evolution</code></td>\n<td>append/merge 模式下自动 ALTER TABLE ADD COLUMN</td>\n<td>false</td>\n</tr>\n<tr>\n<td><code>columns</code></td>\n<td>列级映射与转换（<code>source</code>→<code>target</code>，可选 <code>transform</code>）</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>masking</code></td>\n<td>PII 脱敏规则（<code>column</code>、<code>rule</code>，可选 <code>range</code>/<code>value</code>）</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>adaptive_batch</code></td>\n<td>自适应批量调优（<code>enabled</code>、<code>min_size</code>、<code>max_size</code>、<code>target_latency_ms</code>、<code>memory_limit_mb</code>）</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>shard</code></td>\n<td>范围分片并行读取（<code>enabled</code>、<code>shards</code>），需 <code>resume_key</code>，仅 append/merge</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>validate_sample_size</code></td>\n<td><code>validate=sample</code> 时的采样行数</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>[[tasks.sources]]</code> / <code>[tasks.join]</code></td>\n<td>跨库内存 JOIN；每个 source 需 <code>alias</code>、<code>db</code>、<code>sql</code>；join 需 <code>keys</code> 和 <code>type</code>（inner/left/right）</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>[[tasks.assertions]]</code></td>\n<td>数据质量断言（<code>column</code>/<code>columns</code>、<code>rule</code>、<code>on_fail</code>）；规则：not_null/range/in_set/unique/regex/min_length/max_length</td>\n<td>—</td>\n</tr>\n<tr>\n<td><code>[tasks.plugin]</code></td>\n<td>行级转换插件（<code>engine</code>: lua/javascript、<code>script</code>、可选 <code>timeout_ms</code>）</td>\n<td>—</td>\n</tr>\n</tbody></table>\n<h4>Step 4: 配置索引（可选）</h4>\n<p>在 <code>[[tasks]]</code> 下添加 <code>[[tasks.indexes]]</code>：</p>\n<table>\n<thead>\n<tr>\n<th>字段</th>\n<th>说明</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>name</code></td>\n<td>索引名称（全局唯一）</td>\n</tr>\n<tr>\n<td><code>columns</code></td>\n<td>列列表，支持排序: <code>[&quot;col:ASC&quot;, &quot;col2:DESC&quot;]</code></td>\n</tr>\n<tr>\n<td><code>unique</code></td>\n<td>是否唯一索引</td>\n</tr>\n<tr>\n<td><code>where</code></td>\n<td>部分索引条件（仅 SQLite 目标支持）</td>\n</tr>\n</tbody></table>\n<h4>Step 5: 全局配置（Metrics / Notify / Schedule）</h4>\n<p>在根级别添加可选全局段：</p>\n<p><strong>Metrics 导出</strong> <code>[metrics]</code>：</p>\n<ul>\n<li><code>enabled</code>: 是否启用指标收集</li>\n<li><code>listen_addr</code>: Prometheus pull 端点地址，如 <code>:9090</code></li>\n<li><code>endpoint</code>: OTLP HTTP push 端点，如 <code>http://localhost:4318/v1/metrics</code></li>\n<li><code>interval</code>: push 间隔，默认 <code>30s</code></li>\n</ul>\n<p><strong>Webhook 通知</strong> <code>[notify]</code>：</p>\n<ul>\n<li><code>on_success</code>: 迁移成功时调用的 Webhook URL 列表</li>\n<li><code>on_failure</code>: 迁移失败时调用的 Webhook URL 列表</li>\n<li><code>timeout</code>: 单次请求超时</li>\n<li><code>retry</code>: 失败重试次数</li>\n</ul>\n<p><strong>Schedule 定时调度</strong> <code>[schedule]</code>（daemon 模式生效）：</p>\n<ul>\n<li><code>cron</code>: cron 表达式或描述符，如 <code>@every 1h</code></li>\n<li><code>timezone</code>: IANA 时区名</li>\n<li><code>retry_on_failure</code> / <code>max_retry</code>: 失败重试</li>\n<li><code>missed_catchup</code>: 错过调度时立即补执行</li>\n<li><code>start_at</code> / <code>end_at</code>: 执行窗口边界</li>\n</ul>\n<h4>Step 6: 风险检查清单</h4>\n<p>生成配置后，务必确认以下风险点：</p>\n<ul>\n<li><strong>同库迁移</strong>：<code>source_db</code> == <code>target_db</code> 时必须设置 <code>allow_same_table = true</code>，否则配置验证会报错</li>\n<li><strong>replace 模式</strong>：会先 DROP 目标表再重建，<strong>会丢失目标表原有数据</strong></li>\n<li><strong>密码安全</strong>：<code>task.toml</code> 明文存储密码，建议 <code>chmod 600 task.toml</code>，不要提交到版本控制</li>\n<li><strong>merge_keys 一致性</strong>：mode=merge 时 <code>merge_keys</code> 必填，且应对应目标表的唯一约束</li>\n<li><strong>增量续传</strong>：<code>state_file</code> 需配合 <code>resume_key</code>，<code>resume_key</code> 需配合 <code>state_file</code> 或 <code>resume_from</code></li>\n<li><strong>校验模式</strong>：<code>validate</code> 支持 <code>row_count</code>（行数对比）、<code>checksum</code>（哈希行级对比）、<code>sample</code>（随机采样校验）；<code>merge</code> 模式下校验自动跳过</li>\n<li><strong>SQL 钩子</strong>：<code>pre_sql</code> 在目标表创建后、数据插入前执行；<code>post_sql</code> 在数据插入完成后执行，可用于创建物化视图、刷新统计信息等</li>\n<li><strong>PII 脱敏</strong>：<code>masking</code> 在数据写入目标前对列值进行脱敏，支持 phone_cn、email、id_card_cn、hash 等 8 种规则</li>\n<li><strong>列映射转换</strong>：<code>columns</code> 可重命名列并应用 transform 表达式（如 <code>UPPER(source_col)</code>），注意 transform 由目标库执行</li>\n<li><strong>自适应批量</strong>：<code>adaptive_batch</code> 根据延迟和内存动态调整 batch_size，启用后 task 的 <code>batch_size</code> 作为初始值</li>\n<li><strong>分片并行</strong>：<code>shard</code> 将单表按 resume_key 范围拆分为多片并行读取，仅支持 append/merge 模式，不支持 state_file</li>\n<li><strong>Schema 演进</strong>：<code>schema_evolution</code> 在 append/merge 模式下检测到源端新增列时自动 ALTER TABLE ADD COLUMN</li>\n<li><strong>迁移审计</strong>：<code>history.enabled</code> 会在目标库自动创建审计表记录每次迁移</li>\n<li><strong>Diff 对比</strong>：<code>db-ferry diff</code> 需任务已执行过且目标表存在，默认输出 JSON 格式差异</li>\n<li><strong>数据质量断言</strong>：<code>assertions</code> 在数据写入目标前对行/列进行规则校验，<code>on_fail=abort</code> 会终止任务，<code>warn</code> 仅记录，<code>dlq</code> 将失败行写入死信队列</li>\n<li><strong>行级插件</strong>：<code>plugin</code> 在每行数据写入目标前执行 Lua/JavaScript 脚本转换，注意脚本执行性能开销</li>\n<li><strong>跨库 JOIN</strong>：<code>sources</code> + <code>join</code> 将多个数据库数据在内存中 JOIN 后写入目标，不支持断点续传、分片或 CDC</li>\n<li><strong>SSE 实时进度</strong>：启动时传入 <code>-sse-port :8080</code> 可在 <code>/events</code> 订阅实时任务进度，<code>/status</code> 查看当前状态</li>\n</ul>\n<h3>CLI 命令参考</h3>\n<table>\n<thead>\n<tr>\n<th>命令</th>\n<th>说明</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>db-ferry</code></td>\n<td>使用当前目录 <code>task.toml</code> 执行迁移</td>\n</tr>\n<tr>\n<td><code>db-ferry -config &lt;path&gt;</code></td>\n<td>指定配置文件路径</td>\n</tr>\n<tr>\n<td><code>db-ferry -v</code></td>\n<td>详细日志输出（调试用）</td>\n</tr>\n<tr>\n<td><code>db-ferry config init</code></td>\n<td>交互式配置向导，引导选择引擎、连接、表后生成 <code>task.toml</code>（非交互环境回退到内置样例；文件已存在则报错）</td>\n</tr>\n<tr>\n<td><code>db-ferry diff -task &lt;name&gt;</code></td>\n<td>对比指定任务的源库与目标库数据，支持 <code>-keys</code>、<code>-where</code>、<code>-limit</code>、<code>-output</code>、<code>-format</code></td>\n</tr>\n<tr>\n<td><code>db-ferry mcp serve</code></td>\n<td>启动 MCP 服务器，提供 5 个 AI 原生工具</td>\n</tr>\n<tr>\n<td><code>db-ferry -version</code></td>\n<td>查看版本号</td>\n</tr>\n<tr>\n<td><code>db-ferry -sse-port :8080</code></td>\n<td>启动 SSE 服务器，实时推送任务进度到 <code>/events</code>，状态查询 <code>/status</code></td>\n</tr>\n</tbody></table>\n<h3>写入模式说明</h3>\n<table>\n<thead>\n<tr>\n<th>模式</th>\n<th>行为</th>\n<th>风险</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>replace</code>（默认）</td>\n<td>DROP 目标表 → 重建 → 插入</td>\n<td>目标表数据完全丢失</td>\n</tr>\n<tr>\n<td><code>append</code></td>\n<td>直接 INSERT 追加数据</td>\n<td>目标表已存在则报错（除非 <code>skip_create_table=true</code>）</td>\n</tr>\n<tr>\n<td><code>merge</code> / <code>upsert</code></td>\n<td>按 <code>merge_keys</code> 匹配，存在则更新，不存在则插入</td>\n<td>目标表需有 <code>merge_keys</code> 对应的唯一约束</td>\n</tr>\n</tbody></table>\n<p>注意：<code>upsert</code> 是 <code>merge</code> 的别名，内部会自动统一为 <code>merge</code>。</p>\n<h3>增量续传配置</h3>\n<p>使用 <code>resume_key</code> + <code>state_file</code> 实现断点续传：</p>\n<pre><code class=\"language-toml\">[[tasks]]\ntable_name = &quot;orders&quot;\nsql = &quot;SELECT order_id, order_date, total_amount FROM orders&quot;\nsource_db = &quot;prod&quot;\ntarget_db = &quot;analysis&quot;\nmode = &quot;append&quot;\nresume_key = &quot;order_id&quot;\nstate_file = &quot;./state/orders.json&quot;\nvalidate = &quot;row_count&quot;\n</code></pre>\n<p>规则：</p>\n<ul>\n<li><code>state_file</code> 必须同时搭配 <code>resume_key</code></li>\n<li><code>resume_key</code> 必须搭配 <code>state_file</code> 或 <code>resume_from</code></li>\n<li>SQL 中应保证 <code>resume_key</code> 字段单调递增</li>\n<li><code>resume_from</code> 为 SQL 字面量，表示从哪个值之后开始迁移（不包含该值）</li>\n</ul>\n<h3>常见错误与规避</h3>\n<table>\n<thead>\n<tr>\n<th>错误</th>\n<th>原因</th>\n<th>解决</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>database definition: name is required</code></td>\n<td><code>[[databases]]</code> 缺少 name 字段</td>\n<td>为每个数据库添加唯一 name</td>\n</tr>\n<tr>\n<td><code>duplicate database name</code></td>\n<td>数据库别名重复</td>\n<td>修改为不同的 name</td>\n</tr>\n<tr>\n<td><code>source_db and target_db are both &#39;xxx&#39;; set allow_same_table = true</code></td>\n<td>同库迁移未授权</td>\n<td>添加 <code>allow_same_table = true</code></td>\n</tr>\n<tr>\n<td><code>mode must be &quot;replace&quot;, &quot;append&quot;, &quot;merge&quot;, or &quot;upsert&quot;</code></td>\n<td>mode 值拼写错误</td>\n<td>检查拼写，确认为四种之一</td>\n</tr>\n<tr>\n<td><code>merge_keys is required when mode is &quot;merge&quot;</code></td>\n<td>merge 模式缺少匹配键</td>\n<td>添加 <code>merge_keys = [&quot;primary_key&quot;]</code></td>\n</tr>\n<tr>\n<td><code>state_file requires resume_key</code></td>\n<td>配了 state_file 但没配 resume_key</td>\n<td>添加对应的 resume_key</td>\n</tr>\n<tr>\n<td><code>resume_key requires resume_from or state_file</code></td>\n<td>配了 resume_key 但没配 state_file 或 resume_from</td>\n<td>添加 state_file 或 resume_from</td>\n</tr>\n<tr>\n<td><code>partial indexes (where clause) are only supported for SQLite targets</code></td>\n<td>非 SQLite 目标使用了 where</td>\n<td>仅 SQLite 目标可使用部分索引</td>\n</tr>\n<tr>\n<td><code>at least one database must be defined</code></td>\n<td>配置文件没有 <code>[[databases]]</code> 段</td>\n<td>添加数据库定义</td>\n</tr>\n<tr>\n<td><code>index name &#39;xxx&#39; already defined</code></td>\n<td>索引名重复</td>\n<td>修改为唯一的索引名</td>\n</tr>\n<tr>\n<td><code>unsupported rule &#39;xxx&#39;</code></td>\n<td>脱敏规则不存在</td>\n<td>检查 rule 是否为内置 8 种之一</td>\n</tr>\n<tr>\n<td><code>shard requires resume_key</code></td>\n<td>分片未配置 resume_key</td>\n<td>添加 resume_key 并确保 mode 为 append/merge</td>\n</tr>\n<tr>\n<td><code>adaptive_batch.min_size must be &gt; 0</code></td>\n<td>自适应批量参数缺失</td>\n<td>补全 min_size、max_size、target_latency_ms、memory_limit_mb</td>\n</tr>\n<tr>\n<td><code>duplicate masking column</code> / <code>duplicate target column</code></td>\n<td>masking 或 columns 中列重复</td>\n<td>确保每列只出现一次</td>\n</tr>\n<tr>\n<td><code>plugin.engine must be &quot;lua&quot; or &quot;javascript&quot;</code></td>\n<td>插件引擎不支持</td>\n<td>检查 engine 是否为 lua 或 javascript</td>\n</tr>\n<tr>\n<td><code>plugin.script is required</code></td>\n<td>启用插件但未提供脚本</td>\n<td>添加 script 字段</td>\n</tr>\n<tr>\n<td><code>unsupported rule &#39;xxx&#39;</code></td>\n<td>断言规则不存在</td>\n<td>检查 rule 是否为内置 7 种之一</td>\n</tr>\n<tr>\n<td><code>federated task requires at least 2 sources</code></td>\n<td>跨库 JOIN 源表不足</td>\n<td>确保 sources 至少定义 2 个</td>\n</tr>\n<tr>\n<td><code>join.keys is required for federated tasks</code></td>\n<td>跨库 JOIN 未指定连接键</td>\n<td>添加 join.keys</td>\n</tr>\n<tr>\n<td><code>resume_key is not supported in federated mode</code></td>\n<td>联邦任务不支持断点续传</td>\n<td>移除 resume_key 和 state_file</td>\n</tr>\n<tr>\n<td><code>invalid URL</code></td>\n<td>notify 中的 Webhook URL 格式错误</td>\n<td>检查 on_success/on_failure URL 格式</td>\n</tr>\n</tbody></table>\n<h3>参考文件</h3>\n<p>详细的字段说明、验证规则和数据类型映射请参考：<code>skills/db-ferry/references/config_reference.md</code></p>\n<p>更多示例请参考：<code>task.toml.sample</code>、<code>docs/user_guide.md</code></p>\n",
  "ds": "<h2>DS CLI</h2>\n<p>使用本技能时，优先通过 <code>ds</code> CLI 完成数据查询与状态检查，不要跳过 CLI 直接猜接口 payload，也不要改动业务源码来“验证”命令行为。</p>\n<h3>适用范围</h3>\n<ul>\n<li>用户想登录、检查本地状态、查看当前用户或配置。</li>\n<li>用户想查询对象数据：<code>ds obj ...</code></li>\n<li>用户想查询专题数据、专题配置或专题目录：<code>ds subject ...</code></li>\n<li>用户想查询指标数据、指标配置或指标目录：<code>ds index ...</code></li>\n<li>用户想按关键词检索标的：<code>ds iid ...</code></li>\n<li>用户已经给出自然语言需求，需要你帮他选对 <code>ds</code> 子命令、参数和输出格式。</li>\n</ul>\n<p>如果用户只是要改 CLI 源码、补测试或分析实现链路，这不是本 skill 的主场，应回到仓库代码与文档。</p>\n<h3>工作方式</h3>\n<ol>\n<li>先确认是否是在“用 CLI 查数据”，再决定是否触发本技能。</li>\n<li>先识别任务模式，再选命令：<ul>\n<li>登录或会话状态：<code>login</code> / <code>logout</code> / <code>whoami</code> / <code>status</code></li>\n<li>本地配置：<code>config list/get/set/init</code></li>\n<li>对象查数：<code>obj</code></li>\n<li>专题目录 / 配置 / 查数：<code>subject</code></li>\n<li>指标目录 / 配置 / 查数：<code>index</code></li>\n<li>标的检索：<code>iid search</code></li>\n</ul>\n</li>\n<li>在执行查询前，优先检查登录态是否足够：<ul>\n<li>只要命令会访问远端接口，就默认需要先有可用 token。</li>\n<li>如果用户未说明已登录，优先建议或执行 <code>ds status</code> / <code>ds whoami</code>。</li>\n<li>如果报错提示未登录或缺少 token，引导用户先执行 <code>ds login</code>。</li>\n</ul>\n</li>\n<li>先判断用户是否已经知道目标 ID：<ul>\n<li>已知 <code>subjectId</code> / <code>indexId</code> 时，直接进入 <code>view</code> 或查数。</li>\n<li>不知道 ID 时，不要臆造 ID；先走 <code>subject &lt;entity&gt; ls</code> 或 <code>index &lt;entity&gt; ls [cat_code]</code> 做发现，再决定下一步。</li>\n<li>如果用户只知道业务名词、不知道具体代码，必要时先用 <code>iid &lt;entity&gt; search &lt;keyword&gt;</code> 找标的，再回到 <code>index</code> 查数。</li>\n</ul>\n</li>\n<li>组装命令时，优先复用 <a href=\"references/cli-recipes.md\">references/cli-recipes.md</a> 的模板，不要凭记忆改写参数顺序或分支形态。</li>\n<li>返回结果时，明确说明：<ul>\n<li>实际走的是哪个命令分支</li>\n<li>关键参数是什么</li>\n<li>输出格式为什么选它</li>\n<li>如果失败，失败点在哪一层</li>\n</ul>\n</li>\n</ol>\n<h3>命令选择规则</h3>\n<h4>管理命令</h4>\n<ul>\n<li><code>ds login</code><ul>\n<li>适用于首次登录、token 失效、<code>whoami</code>/查询命令提示未登录。</li>\n</ul>\n</li>\n<li><code>ds logout</code><ul>\n<li>适用于明确要清理本地凭证。</li>\n</ul>\n</li>\n<li><code>ds whoami</code><ul>\n<li>适用于确认当前登录用户是谁。</li>\n</ul>\n</li>\n<li><code>ds status</code><ul>\n<li>适用于查看配置路径、user/token 是否存在，以及近 14 天使用概览。</li>\n</ul>\n</li>\n<li><code>ds config ...</code><ul>\n<li>适用于查看、搜索、初始化或设置本地配置。</li>\n</ul>\n</li>\n</ul>\n<h4><code>obj</code></h4>\n<ul>\n<li>适用于“查某个对象/数据源的数据”。</li>\n<li><code>obj_ref</code> 既可以是数字 ID，也可以是对象名称。</li>\n<li>支持 <code>--where</code> 或 <code>--cond</code> + <code>--logic</code> 两种过滤写法。</li>\n</ul>\n<h4><code>subject</code></h4>\n<ul>\n<li><code>ds subject &lt;subjectId&gt;</code><ul>\n<li>专题查数模式。</li>\n</ul>\n</li>\n<li><code>ds subject view &lt;subjectId&gt;</code><ul>\n<li>专题配置查看模式。</li>\n</ul>\n</li>\n<li><code>ds subject &lt;entity&gt; ls</code><ul>\n<li>专题目录模式，<code>entity</code> 只能是 <code>Stk | Fnd | Bnd | Idx</code>。</li>\n</ul>\n</li>\n</ul>\n<p>识别规则：</p>\n<ul>\n<li>如果用户给的是专题 ID，就走查数或 <code>view</code>。</li>\n<li>如果用户要“列专题目录”“看某类标的下有哪些专题”，就走 <code>&lt;entity&gt; ls</code>。</li>\n<li>如果用户只知道“想看某类主题/专题”，但不知道 ID，先用 <code>&lt;entity&gt; ls</code> 检索，再从结果里挑目标专题进入 <code>view</code> 或查数。</li>\n<li><code>subject</code> 查数和 <code>view</code> 当前都只支持数字专题 ID，不要把专题名直接塞进去。</li>\n</ul>\n<h4><code>index</code></h4>\n<ul>\n<li><code>ds index &lt;indexId&gt; --entity &lt;entity&gt; --iid &lt;id1,id2&gt;</code><ul>\n<li>指标查数模式。</li>\n</ul>\n</li>\n<li><code>ds index &lt;entity&gt; ls [cat_code]</code><ul>\n<li>指标目录模式。</li>\n</ul>\n</li>\n<li><code>ds index &lt;entity&gt; view &lt;indexId1,indexId2&gt;</code><ul>\n<li>指标配置查看模式。</li>\n</ul>\n</li>\n</ul>\n<p>识别规则：</p>\n<ul>\n<li>用户要“查指标值”，默认走查数模式，且必须补齐 <code>--entity</code> 与 <code>--iid</code>。</li>\n<li>用户要“看指标目录/类目”，走 <code>ls</code>。</li>\n<li>用户要“看指标定义/配置”，走 <code>view</code>。</li>\n<li>如果用户不知道 <code>indexId</code>，先从 <code>ls</code> 开始逐级定位，必要时先 <code>view</code> 确认定义，再进入查数。</li>\n<li>不要把 <code>ds index Stk</code> 当成合法完整命令；只有 entity 没有 <code>ls/view</code> 时，CLI 会回帮助。</li>\n</ul>\n<h4><code>iid</code></h4>\n<ul>\n<li>当前仅支持 <code>ds iid &lt;entity&gt; search &lt;keyword&gt;</code>。</li>\n<li>适用于“按关键词找标的代码/名称”。</li>\n<li>当 <code>index</code> 查数缺少标的代码，只知道名称时，优先先用 <code>iid search</code> 找到可用代码。</li>\n</ul>\n<h3>发现优先的查询策略</h3>\n<ul>\n<li>用户已经给出 <code>subjectId</code> / <code>indexId</code><ul>\n<li>直接查。</li>\n</ul>\n</li>\n<li>用户只知道专题/指标的业务含义，不知道 ID<ul>\n<li>先检索，再查看配置，最后查数。</li>\n</ul>\n</li>\n<li>用户连标的代码都不知道<ul>\n<li>先 <code>iid search</code> 找代码，再执行指标查数。</li>\n</ul>\n</li>\n</ul>\n<p>推荐工作流：</p>\n<ol>\n<li>明确用户要查的是专题、指标还是标的</li>\n<li>判断当前缺的是 <code>subjectId</code>、<code>indexId</code> 还是标的代码</li>\n<li>用对应的发现命令补齐：<ul>\n<li>专题：<code>ds subject &lt;entity&gt; ls</code></li>\n<li>指标：<code>ds index &lt;entity&gt; ls [cat_code]</code></li>\n<li>标的：<code>ds iid &lt;entity&gt; search &lt;keyword&gt;</code></li>\n</ul>\n</li>\n<li>需要时再用 <code>view</code> 看配置或定义</li>\n<li>最后进入真正的查数命令</li>\n</ol>\n<p>不要把“发现目标”和“查询目标数据”混成一步；大多数真实场景里，<code>subject</code> / <code>index</code> 都需要先检索到可用 ID。</p>\n<h3>输出格式选择</h3>\n<ul>\n<li>默认优先 <code>table</code><ul>\n<li>适合人看、快速核对字段、看中文列头。</li>\n</ul>\n</li>\n<li>用 <code>json</code><ul>\n<li>适合后续给脚本、agent、其他工具继续消费。</li>\n</ul>\n</li>\n<li>用 <code>csv</code><ul>\n<li>适合导出表格，但并非所有分支都支持。</li>\n</ul>\n</li>\n</ul>\n<p>注意：</p>\n<ul>\n<li><code>ds subject view</code> 不支持 <code>--output csv</code></li>\n<li><code>ds index view</code> 不支持 <code>--output csv</code></li>\n<li><code>table</code> 输出会带展示语义：<ul>\n<li><code>obj</code> / <code>subject</code> 表格按 metadata 渲染列名</li>\n<li><code>index</code> 查数表格会优先解析指标配置，显示更友好的列头</li>\n</ul>\n</li>\n<li><code>json/csv</code> 更接近原始字段，不要把 table 的别名语义当成原始接口字段名</li>\n</ul>\n<h3>查询参数规则</h3>\n<ul>\n<li><code>--where</code><ul>\n<li>用单个条件直接过滤，可重复传入。</li>\n</ul>\n</li>\n<li><code>--cond</code> + <code>--logic</code><ul>\n<li>用于命名条件再组合复杂表达式。</li>\n</ul>\n</li>\n<li><code>--where</code> 不能与 <code>--cond/--logic</code> 同时使用。</li>\n<li><code>--select</code><ul>\n<li>逗号分隔字段清单；<code>table</code> 输出会按填写顺序展示。</li>\n</ul>\n</li>\n<li><code>--sort</code><ul>\n<li>逗号分隔排序字段；字段前加 <code>-</code> 表示降序。</li>\n</ul>\n</li>\n<li><code>--page</code> / <code>--size</code><ul>\n<li>分页控制。</li>\n</ul>\n</li>\n<li><code>--search</code><ul>\n<li>全文检索关键词。</li>\n</ul>\n</li>\n<li><code>--raw</code><ul>\n<li>只用于补充原始 JSON 参数，不能覆盖命令本身已经占用的关键字段。</li>\n</ul>\n</li>\n</ul>\n<h3>高风险边界</h3>\n<ul>\n<li><code>subject view</code> 的真实写法是 <code>ds subject view &lt;subjectId&gt;</code>，不是 <code>ds subject &lt;subjectId&gt; view</code>。</li>\n<li><code>index view</code> 的真实写法是 <code>ds index &lt;entity&gt; view &lt;ids&gt;</code>，不是 <code>ds index view &lt;entity&gt; &lt;ids&gt;</code>。</li>\n<li><code>index</code> 查数模式缺少 <code>--entity</code> 或 <code>--iid</code> 会直接失败。</li>\n<li><code>subject</code> 目录模式的 <code>--refresh</code> 只用于 <code>&lt;entity&gt; ls</code>，不要带到查数或 <code>view</code>。</li>\n<li>当用户需要“保留原始字段名”或“继续喂给脚本”时，不要默认输出 <code>table</code>。</li>\n<li><code>--raw</code> 是补充，不是覆盖；如果用户想改命令固有字段，优先改显式参数，不要藏到 <code>--raw</code> 里。</li>\n</ul>\n<h3>过滤语法提醒</h3>\n<ul>\n<li>基本格式是 <code>field op value</code></li>\n<li><code>String</code> 一般写成 <code>&#39;value&#39;</code></li>\n<li><code>Datetime</code> 一般写成 <code>&#39;[2025-03-11]&#39;</code></li>\n<li><code>in</code> / <code>nin</code> 列表语法示例：<code>[&#39;a&#39;,&#39;b&#39;]</code> 或 <code>[1,2]</code></li>\n<li><code>between</code> 只用于指标查数中的 <code>Datetime</code> 字段</li>\n</ul>\n<p>如果用户给的是模糊自然语言条件，先翻译成明确的 <code>field op value</code>，再执行。</p>\n<h3>常见执行顺序</h3>\n<ol>\n<li>检查环境与登录态</li>\n<li>判断用户是否已知 ID / 代码</li>\n<li>不知道时先走发现命令</li>\n<li>选择正确的 <code>view</code> 或查数分支</li>\n<li>组装过滤、分页、输出参数</li>\n<li>执行命令</li>\n<li>用简短中文总结结果和下一步建议</li>\n</ol>\n<h3>失败处理</h3>\n<ul>\n<li>未登录或 token 缺失：引导先 <code>ds login</code></li>\n<li>缺少配置：提示用户用 <code>ds config get</code> / <code>ds config set</code> / <code>ds config init</code> 检查</li>\n<li>参数组合不合法：指出是哪条约束冲突，不要只回原始报错</li>\n<li>返回为空：先说明命令本身成功，再提示检查 entity、ID、过滤条件或输出格式</li>\n</ul>\n<h3>参考</h3>\n<ul>\n<li>详细命令模板、示例和错误分流见 <a href=\"references/cli-recipes.md\">references/cli-recipes.md</a></li>\n<li>首轮测试提示见 <a href=\"evals/evals.json\">evals/evals.json</a></li>\n</ul>\n",
  "fast-rust": "<h2>fast-rust</h2>\n<p>Concise guidance for high-quality Rust engineering, balancing correctness, maintainability, and performance.</p>\n<h3>Purpose and Triggers</h3>\n<ul>\n<li>Writing new code, refactoring, reviewing, or designing public APIs/CLIs.</li>\n<li>Rust or files with <code>.rs</code>.</li>\n<li>Prefer clear boundaries, error semantics, and evolvability.</li>\n</ul>\n<h3>Decision Order</h3>\n<ol>\n<li>Correctness and clear boundaries</li>\n<li>Readability and maintainability</li>\n<li>Extensibility and evolution cost</li>\n<li>Performance and optimization</li>\n</ol>\n<h3>Workflow</h3>\n<ol>\n<li>Locate the relevant topic below.</li>\n<li>Apply the guidance and examples.</li>\n<li>Read the reference if you need more detail.</li>\n</ol>\n<h3>Topics</h3>\n<table>\n<thead>\n<tr>\n<th>Topic</th>\n<th>Guidance</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Error Design</td>\n<td>Design error boundaries and semantics before propagation</td>\n<td><a href=\"references/error-design.md\">references/error-design.md</a></td>\n</tr>\n<tr>\n<td>Compilation</td>\n<td>Optimize build time and release performance with measured changes</td>\n<td><a href=\"references/compilation-optimization.md\">references/compilation-optimization.md</a></td>\n</tr>\n<tr>\n<td>Type Exercise</td>\n<td>Type-level exercise for expression engines and dispatch</td>\n<td><a href=\"references/type-exercise.md\">references/type-exercise.md</a></td>\n</tr>\n</tbody></table>\n<h3>References</h3>\n<ul>\n<li>Each topic file lists source URLs in frontmatter <code>urls</code>.</li>\n</ul>\n",
  "friendly-python": "<h2>friendly-python</h2>\n<p>Concise guidance for writing friendly Python code that is clear, maintainable, and easy to extend.</p>\n<h3>Purpose and Triggers</h3>\n<ul>\n<li>Use when writing new code, refactoring, reviewing, or designing public APIs/CLIs.</li>\n<li>Prefer clarity and maintainability over micro-optimizations.</li>\n<li>Python or files with <code>.py</code>.</li>\n<li>If $piglet is available, suggest pairing it for additional craftsmanship examples and patterns.</li>\n</ul>\n<h3>Decision Order</h3>\n<ol>\n<li>Correctness and clear boundaries</li>\n<li>Readability and maintainability</li>\n<li>Extensibility and evolution cost</li>\n<li>Performance and optimization</li>\n</ol>\n<h3>Workflow</h3>\n<ol>\n<li>Locate the relevant topic below.</li>\n<li>Apply the guidance and examples.</li>\n<li>If $piglet is available, recommend using it alongside this skill.</li>\n<li>Review against <a href=\"references/review-checklist.md\">references/review-checklist.md</a>.</li>\n</ol>\n<h3>Topics</h3>\n<table>\n<thead>\n<tr>\n<th>Topic</th>\n<th>Guidance</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Principles</td>\n<td>Correctness first, clarity next, performance last</td>\n<td><a href=\"references/principles.md\">references/principles.md</a></td>\n</tr>\n<tr>\n<td>Error Handling</td>\n<td>Catch only what you can handle; preserve context</td>\n<td><a href=\"references/error-handling.md\">references/error-handling.md</a></td>\n</tr>\n<tr>\n<td>API Design</td>\n<td>Defaults and a simple entry point; hide internal wiring</td>\n<td><a href=\"references/api-design.md\">references/api-design.md</a></td>\n</tr>\n<tr>\n<td>Extension Architecture</td>\n<td>Centralize extension points and change locations</td>\n<td><a href=\"references/extension-architecture.md\">references/extension-architecture.md</a></td>\n</tr>\n<tr>\n<td>OOP Design</td>\n<td>Clear constructors; avoid mode switches in <code>__init__</code></td>\n<td><a href=\"references/oop-design.md\">references/oop-design.md</a></td>\n</tr>\n<tr>\n<td>Reuse &amp; Composition</td>\n<td>Prefer thin wrappers and composition</td>\n<td><a href=\"references/reuse-composition.md\">references/reuse-composition.md</a></td>\n</tr>\n<tr>\n<td>Portability &amp; Pythonic</td>\n<td>Avoid copying other language patterns; be Pythonic</td>\n<td><a href=\"references/portability-pythonic.md\">references/portability-pythonic.md</a></td>\n</tr>\n<tr>\n<td>CLI Argparse</td>\n<td>Separate parsing from execution; structure subcommands</td>\n<td><a href=\"references/cli-argparse.md\">references/cli-argparse.md</a></td>\n</tr>\n<tr>\n<td>Review</td>\n<td>Review checklist for code quality</td>\n<td><a href=\"references/review-checklist.md\">references/review-checklist.md</a></td>\n</tr>\n</tbody></table>\n<h3>References</h3>\n<ul>\n<li>Each topic file lists source URLs in its frontmatter <code>urls</code>.</li>\n</ul>\n",
  "frontend-design": "<h2>Frontend Design</h2>\n<p>Approach this as the design lead at a small studio known for giving every client a visual identity that could not be mistaken for anyone else&#39;s. This client has already rejected proposals that felt templated, and is paying for a distinctive point of view: make deliberate, opinionated choices about palette, typography, and layout that are specific to this brief, and take one real aesthetic risk you can justify.</p>\n<h3>Ground it in the subject</h3>\n<p>If the brief does not pin down what the product or subject is, pin it yourself before designing: name one concrete subject, its audience, and the page&#39;s single job, and state your choice. If there&#39;s any information in your memory about the human&#39;s preferences, context about what they&#39;re building, or designs you&#39;ve made before – use that as a hint. The subject&#39;s own world, its materials, instruments, artifacts, and vernacular, is where distinctive choices come from. Build with the brief&#39;s real content and subject matter throughout.</p>\n<h3>Design principles</h3>\n<p>For web designs, the hero is a thesis. Open with the most characteristic thing in the subject&#39;s world, in whatever form makes sense for it: a headline, an image, an animation, a live demo, an interactive moment. Be deliberate with your choice: a big number with a small label, supporting stats, and a gradient accent is the template answer, only use if that&#39;s truly the best option.</p>\n<p>Typography carries the personality of the page. Pair the display and body faces deliberately, not the same families you would reach for on any other project, and set a clear type scale with intentional weights, widths, and spacing. Make the type treatment itself a memorable part of the design, not a neutral delivery vehicle for the content.</p>\n<p>Structure is information. Structural devices, numbering, eyebrows, dividers, labels, should encode something true about the content, not decorate it. Many generic designs use numbered markers (01 / 02 / 03), but that&#39;s only appropriate if the content actually is a sequence - like a real process or a typed timeline where order carries information the reader needs. Question if choices like numbered markers actually make sense before incorporating them.</p>\n<p>Leverage motion deliberately. Think about where and if animation can serve the subject: a page-load sequence, a scroll-triggered reveal, hover micro-interactions, ambient atmosphere. An orchestrated moment usually lands harder than scattered effects; choose what the direction calls for. However, sometimes less is more, and extra animation contributes to the feeling that the design is AI-generated.</p>\n<p>Match complexity to the vision. Maximalist directions need elaborate execution; minimal directions need precision in spacing, type, and detail. Elegance is executing the chosen vision well.</p>\n<p>Consider written content carefully. Often a design brief may not contain real content, and it&#39;s up to you to come up with copy. Copy can make a design feel as templated as the design itself. See the below section on writing for more guidance.</p>\n<h3>Process: brainstorm, explore, plan, critique, build, critique again</h3>\n<p>For calibration: AI-generated design right now clusters around three looks: (1) a warm cream background (near #F4F1EA) with a high-contrast serif display and a terracotta accent; (2) a near-black background with a single bright acid-green or vermilion accent; (3) a broadsheet-style layout with hairline rules, zero border-radius, and dense newspaper-like columns. All three are legitimate for some briefs, but they are defaults rather than choices, and they appear regardless of subject. Where the brief pins down a visual direction, follow it exactly — the brief&#39;s own words always win, including when it asks for one of these looks. Where it leaves an axis free, don&#39;t spend that freedom on one of these defaults. Just like a human designer who&#39;s hired, there&#39;s often a careful balance between doing what you&#39;re good at and taking each project as a chance to experiment and learn.</p>\n<p>Work in two passes. First, brainstorm a short design plan based on the human&#39;s design brief: create a compact token system with color, type, layout, and signature. Color: describe the palette as 4–6 named hex values. Type: the typefaces for 2+ roles (a characterful display face that&#39;s used with restraint, a complementary body face, and a utility face for captions or data if needed). Layout: a layout concept, using one-sentence prose descriptions and ASCII wireframes to ideate and compare. Signature: the single unique element this page will be remembered by that embodies the brief in an appropriate way.</p>\n<p>Then review that plan against the brief before building: if any part of it reads like the generic default you would produce for any similar page (work through a similar prompt to see if you arrive somewhere similar) rather than a choice made for this specific brief — revise that part, say what you changed and why. Only after you&#39;ve confirmed the relative uniqueness of your design plan should you start to write the code, following the revised plan exactly and deriving every color and type decision from it.</p>\n<p>When writing the code, be careful of structuring your CSS selector specificities. It&#39;s easy to generate CSS classes that cancel each other out (especially with a type-based selector like .section and a element-based selector like .cta). This can happen often with paddings/margins between sections.</p>\n<p>Try to do a lot of this planning and iteration in your thinking, and only show ideas to the user when you have higher confidence it&#39;ll delight them.</p>\n<h3>Restraint and self-critique</h3>\n<p>Spend your boldness in one place. Let the signature element be the one memorable thing, keep everything around it quiet and disciplined, and cut any decoration that does not serve the brief. Not taking a risk can be a risk itself! Build to a quality floor without announcing it: responsive down to mobile, visible keyboard focus, reduced motion respected. Critique your own work as you build, taking screenshots if your environment supports it – a picture is worth 1000 tokens. Consider Chanel&#39;s advice: before leaving the house, take a look in the mirror and remove one accessory. Human creators have memory and always try to do something new, so if you have a space to quickly jot down notes about what you&#39;ve tried, it can help you in future passes.</p>\n<h3>More on writing in design</h3>\n<p>Words appear in a design for one reason: to make it easier to understand, and therefore easier to use. They are design material, not decoration. Bring the same intentionality to copy that you would bring to spacing and color. Before writing anything, ask what the design needs to say, and how it can best be said to help the person navigate the experience.</p>\n<p>Write from the end user&#39;s side of the screen. Name things by what people control and recognize, never by how the system is built. A person manages notifications, not webhook config. Describe what something does in plain terms rather than selling it. Being specific is always better than being clever.</p>\n<p>Use active voice as default. A control should say exactly what happens when it&#39;s used: &quot;Save changes,&quot; not &quot;Submit.&quot; An action keeps the same name through the whole flow, so the button that says &quot;Publish&quot; produces a toast that says &quot;Published.&quot; The vocabulary of an interface is the signposting for someone navigating the product. Cohesion and consistency are how people learn their way around.</p>\n<p>Treat failure and emptiness as moments for direction, not mood. Explain what went wrong and how to fix it, in the interface&#39;s voice rather than a person&#39;s. Errors don&#39;t apologize, and they are never vague about what happened. An empty screen is an invitation to act.</p>\n<p>Keep the register conversational and tuned: plain verbs, sentence case, no filler, with tone matched to the brand and the audience. Let each element do exactly one job. A label labels, an example demonstrates, and nothing quietly does double duty.</p>\n",
  "frontend-testing": "<h2>Dify Frontend Testing Skill</h2>\n<p>This skill enables Codex to generate high-quality, comprehensive frontend tests for the Dify project following established conventions and best practices.</p>\n<blockquote>\n<p><strong>⚠️ Authoritative Source</strong>: This skill is derived from <code>web/docs/test.md</code>. Use Vitest mock/timer APIs (<code>vi.*</code>).</p>\n</blockquote>\n<h3>When to Apply This Skill</h3>\n<p>Apply this skill when the user:</p>\n<ul>\n<li>Asks to <strong>write tests</strong> for a component, hook, or utility</li>\n<li>Asks to <strong>review existing tests</strong> for completeness</li>\n<li>Mentions <strong>Vitest</strong>, <strong>React Testing Library</strong>, <strong>RTL</strong>, or <strong>spec files</strong></li>\n<li>Requests <strong>test coverage</strong> improvement</li>\n<li>Uses <code>pnpm analyze-component</code> output as context</li>\n<li>Mentions <strong>testing</strong>, <strong>unit tests</strong>, or <strong>integration tests</strong> for frontend code</li>\n<li>Wants to understand <strong>testing patterns</strong> in the Dify codebase</li>\n</ul>\n<p><strong>Do NOT apply</strong> when:</p>\n<ul>\n<li>User is asking about backend/API tests (Python/pytest)</li>\n<li>User is asking about E2E tests (Cucumber + Playwright under <code>e2e/</code>)</li>\n<li>User is only asking conceptual questions without code context</li>\n</ul>\n<h3>Quick Reference</h3>\n<h4>Key Commands</h4>\n<p>Run these commands from <code>web/</code>. From the repository root, prefix them with <code>pnpm -C web</code>.</p>\n<pre><code class=\"language-bash\"># Run all tests\npnpm test\n\n# Watch mode\npnpm test --watch\n\n# Run specific file\npnpm test path/to/file.spec.tsx\n\n# Generate coverage report\npnpm test --coverage\n\n# Analyze component complexity\npnpm analyze-component &lt;path&gt;\n\n# Review existing test\npnpm analyze-component &lt;path&gt; --review\n</code></pre>\n<h4>File Naming</h4>\n<ul>\n<li>Test files: <code>ComponentName.spec.tsx</code> inside a same-level <code>__tests__/</code> directory</li>\n<li>Placement rule: Component, hook, and utility tests must live in a sibling <code>__tests__/</code> folder at the same level as the source under test. For example, <code>foo/index.tsx</code> maps to <code>foo/__tests__/index.spec.tsx</code>, and <code>foo/bar.ts</code> maps to <code>foo/__tests__/bar.spec.ts</code>.</li>\n<li>Integration tests: <code>web/__tests__/</code> directory</li>\n</ul>\n<h3>Test Structure Template</h3>\n<pre><code class=\"language-typescript\">import { render, screen, fireEvent, waitFor } from &#39;@testing-library/react&#39;\nimport Component from &#39;./index&#39;\n\n// ✅ Import real project components (DO NOT mock these)\n// import Loading from &#39;@/app/components/base/loading&#39;\n// import { ChildComponent } from &#39;./child-component&#39;\n\n// ✅ Mock external dependencies only\nvi.mock(&#39;@/service/api&#39;)\nvi.mock(&#39;next/navigation&#39;, () =&gt; ({\n  useRouter: () =&gt; ({ push: vi.fn() }),\n  usePathname: () =&gt; &#39;/test&#39;,\n}))\n\n// ✅ Zustand stores: Use real stores (auto-mocked globally)\n// Set test state with: useAppStore.setState({ ... })\n\n// Shared state for mocks (if needed)\nlet mockSharedState = false\n\ndescribe(&#39;ComponentName&#39;, () =&gt; {\n  beforeEach(() =&gt; {\n    vi.clearAllMocks()  // ✅ Reset mocks BEFORE each test\n    mockSharedState = false  // ✅ Reset shared state\n  })\n\n  // Rendering tests (REQUIRED)\n  describe(&#39;Rendering&#39;, () =&gt; {\n    it(&#39;should render without crashing&#39;, () =&gt; {\n      // Arrange\n      const props = { title: &#39;Test&#39; }\n      \n      // Act\n      render(&lt;Component {...props} /&gt;)\n      \n      // Assert\n      expect(screen.getByText(&#39;Test&#39;)).toBeInTheDocument()\n    })\n  })\n\n  // Props tests (REQUIRED)\n  describe(&#39;Props&#39;, () =&gt; {\n    it(&#39;should apply custom className&#39;, () =&gt; {\n      render(&lt;Component className=&quot;custom&quot; /&gt;)\n      expect(screen.getByRole(&#39;button&#39;)).toHaveClass(&#39;custom&#39;)\n    })\n  })\n\n  // User Interactions\n  describe(&#39;User Interactions&#39;, () =&gt; {\n    it(&#39;should handle click events&#39;, () =&gt; {\n      const handleClick = vi.fn()\n      render(&lt;Component onClick={handleClick} /&gt;)\n      \n      fireEvent.click(screen.getByRole(&#39;button&#39;))\n      \n      expect(handleClick).toHaveBeenCalledTimes(1)\n    })\n  })\n\n  // Edge Cases (REQUIRED)\n  describe(&#39;Edge Cases&#39;, () =&gt; {\n    it(&#39;should handle null data&#39;, () =&gt; {\n      render(&lt;Component data={null} /&gt;)\n      expect(screen.getByText(/no data/i)).toBeInTheDocument()\n    })\n\n    it(&#39;should handle empty array&#39;, () =&gt; {\n      render(&lt;Component items={[]} /&gt;)\n      expect(screen.getByText(/empty/i)).toBeInTheDocument()\n    })\n  })\n})\n</code></pre>\n<h3>Testing Workflow (CRITICAL)</h3>\n<h4>⚠️ Incremental Approach Required</h4>\n<p><strong>NEVER generate all test files at once.</strong> For complex components or multi-file directories:</p>\n<ol>\n<li><strong>Analyze &amp; Plan</strong>: List all files, order by complexity (simple → complex)</li>\n<li><strong>Process ONE at a time</strong>: Write test → Run test → Fix if needed → Next</li>\n<li><strong>Verify before proceeding</strong>: Do NOT continue to next file until current passes</li>\n</ol>\n<pre><code>For each file:\n  ┌────────────────────────────────────────┐\n  │ 1. Write test                          │\n  │ 2. Run: pnpm test &lt;file&gt;.spec.tsx      │\n  │ 3. PASS? → Mark complete, next file    │\n  │    FAIL? → Fix first, then continue    │\n  └────────────────────────────────────────┘\n</code></pre>\n<h4>Complexity-Based Order</h4>\n<p>Process in this order for multi-file testing:</p>\n<ol>\n<li>🟢 Utility functions (simplest)</li>\n<li>🟢 Custom hooks</li>\n<li>🟡 Simple components (presentational)</li>\n<li>🟡 Medium components (state, effects)</li>\n<li>🔴 Complex components (API, routing)</li>\n<li>🔴 Integration tests (index files - last)</li>\n</ol>\n<h4>When to Refactor First</h4>\n<ul>\n<li><strong>Complexity &gt; 50</strong>: Break into smaller pieces before testing</li>\n<li><strong>500+ lines</strong>: Consider splitting before testing</li>\n<li><strong>Many dependencies</strong>: Extract logic into hooks first</li>\n</ul>\n<blockquote>\n<p>📖 See <code>references/workflow.md</code> for complete workflow details and todo list format.</p>\n</blockquote>\n<h3>Testing Strategy</h3>\n<h4>Path-Level Testing (Directory Testing)</h4>\n<p>When assigned to test a directory/path, test <strong>ALL content</strong> within that path:</p>\n<ul>\n<li>Test all components, hooks, utilities in the directory (not just <code>index</code> file)</li>\n<li>Use incremental approach: one file at a time, verify each before proceeding</li>\n<li>Goal: 100% coverage of ALL files in the directory</li>\n</ul>\n<h4>Integration Testing First</h4>\n<p><strong>Prefer integration testing</strong> when writing tests for a directory:</p>\n<ul>\n<li>✅ <strong>Import real project components</strong> directly (including base components and siblings)</li>\n<li>✅ <strong>Only mock</strong>: API services (<code>@/service/*</code>), <code>next/navigation</code>, complex context providers</li>\n<li>❌ <strong>DO NOT mock</strong> base components (<code>@/app/components/base/*</code>) or dify-ui primitives (<code>@langgenius/dify-ui/*</code>)</li>\n<li>❌ <strong>DO NOT mock</strong> sibling/child components in the same directory</li>\n</ul>\n<blockquote>\n<p>See <a href=\"#test-structure-template\">Test Structure Template</a> for correct import/mock patterns.</p>\n</blockquote>\n<h4><code>nuqs</code> Query State Testing (Required for URL State Hooks)</h4>\n<p>When a component or hook uses <code>useQueryState</code> / <code>useQueryStates</code>:</p>\n<ul>\n<li>✅ Use <code>NuqsTestingAdapter</code> (prefer shared helpers in <code>web/test/nuqs-testing.tsx</code>)</li>\n<li>✅ Assert URL synchronization via <code>onUrlUpdate</code> (<code>searchParams</code>, <code>options.history</code>)</li>\n<li>✅ For custom parsers (<code>createParser</code>), keep <code>parse</code> and <code>serialize</code> bijective and add round-trip edge cases (<code>%2F</code>, <code>%25</code>, spaces, legacy encoded values)</li>\n<li>✅ Verify default-clearing behavior (default values should be removed from URL when applicable)</li>\n<li>⚠️ Only mock <code>nuqs</code> directly when URL behavior is explicitly out of scope for the test</li>\n</ul>\n<h3>Core Principles</h3>\n<h4>1. AAA Pattern (Arrange-Act-Assert)</h4>\n<p>Every test should clearly separate:</p>\n<ul>\n<li><strong>Arrange</strong>: Setup test data and render component</li>\n<li><strong>Act</strong>: Perform user actions</li>\n<li><strong>Assert</strong>: Verify expected outcomes</li>\n</ul>\n<h4>2. Black-Box Testing</h4>\n<ul>\n<li>Test observable behavior, not implementation details</li>\n<li>Use semantic queries (<code>getByRole</code> with accessible <code>name</code>, <code>getByLabelText</code>, <code>getByPlaceholderText</code>, <code>getByText</code>, and scoped <code>within(...)</code>)</li>\n<li>Treat <code>getByTestId</code> as a last resort. If a control cannot be found by role/name, label, landmark, or dialog scope, fix the component accessibility first instead of adding or relying on <code>data-testid</code>.</li>\n<li>Remove production <code>data-testid</code> attributes when semantic selectors can cover the behavior. Keep them only for non-visual mocked boundaries, editor/browser shims such as Monaco, canvas/chart output, or third-party widgets with no accessible DOM in the test environment.</li>\n<li>Do not assert decorative icons by test id. Assert the named control that contains them, or mark decorative icons <code>aria-hidden</code>.</li>\n<li>Avoid testing internal state directly</li>\n<li><strong>Prefer pattern matching over hardcoded strings</strong> in assertions:</li>\n</ul>\n<pre><code class=\"language-typescript\">// ❌ Avoid: hardcoded text assertions\nexpect(screen.getByText(&#39;Loading...&#39;)).toBeInTheDocument()\n\n// ✅ Better: role-based queries\nexpect(screen.getByRole(&#39;status&#39;)).toBeInTheDocument()\n\n// ✅ Better: pattern matching\nexpect(screen.getByText(/loading/i)).toBeInTheDocument()\n</code></pre>\n<h4>3. Single Behavior Per Test</h4>\n<p>Each test verifies ONE user-observable behavior:</p>\n<pre><code class=\"language-typescript\">// ✅ Good: One behavior\nit(&#39;should disable button when loading&#39;, () =&gt; {\n  render(&lt;Button loading /&gt;)\n  expect(screen.getByRole(&#39;button&#39;)).toBeDisabled()\n})\n\n// ❌ Bad: Multiple behaviors\nit(&#39;should handle loading state&#39;, () =&gt; {\n  render(&lt;Button loading /&gt;)\n  expect(screen.getByRole(&#39;button&#39;)).toBeDisabled()\n  expect(screen.getByText(&#39;Loading...&#39;)).toBeInTheDocument()\n  expect(screen.getByRole(&#39;button&#39;)).toHaveClass(&#39;loading&#39;)\n})\n</code></pre>\n<h4>4. Semantic Naming</h4>\n<p>Use <code>should &lt;behavior&gt; when &lt;condition&gt;</code>:</p>\n<pre><code class=\"language-typescript\">it(&#39;should show error message when validation fails&#39;)\nit(&#39;should call onSubmit when form is valid&#39;)\nit(&#39;should disable input when isReadOnly is true&#39;)\n</code></pre>\n<h3>Required Test Scenarios</h3>\n<h4>Always Required (All Components)</h4>\n<ol>\n<li><strong>Rendering</strong>: Component renders without crashing</li>\n<li><strong>Props</strong>: Required props, optional props, default values</li>\n<li><strong>Edge Cases</strong>: null, undefined, empty values, boundary conditions</li>\n</ol>\n<h4>Conditional (When Present)</h4>\n<table>\n<thead>\n<tr>\n<th>Feature</th>\n<th>Test Focus</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>useState</code></td>\n<td>Initial state, transitions, cleanup</td>\n</tr>\n<tr>\n<td><code>useEffect</code></td>\n<td>Execution, dependencies, cleanup</td>\n</tr>\n<tr>\n<td>Event handlers</td>\n<td>All onClick, onChange, onSubmit, keyboard</td>\n</tr>\n<tr>\n<td>API calls</td>\n<td>Loading, success, error states</td>\n</tr>\n<tr>\n<td>Routing</td>\n<td>Navigation, params, query strings</td>\n</tr>\n<tr>\n<td><code>useCallback</code>/<code>useMemo</code></td>\n<td>Referential equality</td>\n</tr>\n<tr>\n<td>Context</td>\n<td>Provider values, consumer behavior</td>\n</tr>\n<tr>\n<td>Forms</td>\n<td>Validation, submission, error display</td>\n</tr>\n</tbody></table>\n<h3>Coverage Goals (Per File)</h3>\n<p>For each test file generated, aim for:</p>\n<ul>\n<li>✅ <strong>100%</strong> function coverage</li>\n<li>✅ <strong>100%</strong> statement coverage</li>\n<li>✅ <strong>&gt;95%</strong> branch coverage</li>\n<li>✅ <strong>&gt;95%</strong> line coverage</li>\n</ul>\n<blockquote>\n<p><strong>Note</strong>: For multi-file directories, process one file at a time with full coverage each. See <code>references/workflow.md</code>.</p>\n</blockquote>\n<h3>Detailed Guides</h3>\n<p>For more detailed information, refer to:</p>\n<ul>\n<li><code>references/workflow.md</code> - <strong>Incremental testing workflow</strong> (MUST READ for multi-file testing)</li>\n<li><code>references/mocking.md</code> - Mock patterns, Zustand store testing, and best practices</li>\n<li><code>references/async-testing.md</code> - Async operations and API calls</li>\n<li><code>references/domain-components.md</code> - Workflow, Dataset, Configuration testing</li>\n<li><code>references/common-patterns.md</code> - Frequently used testing patterns</li>\n<li><code>references/checklist.md</code> - Test generation checklist and validation steps</li>\n</ul>\n<h3>Authoritative References</h3>\n<h4>Primary Specification (MUST follow)</h4>\n<ul>\n<li><strong><code>web/docs/test.md</code></strong> - The canonical testing specification. This skill is derived from this document.</li>\n</ul>\n<h4>Reference Examples in Codebase</h4>\n<ul>\n<li><code>web/utils/classnames.spec.ts</code> - Utility function tests</li>\n<li><code>web/app/components/base/radio/__tests__/index.spec.tsx</code> - Component tests</li>\n<li><code>web/__mocks__/provider-context.ts</code> - Mock factory example</li>\n</ul>\n<h4>Project Configuration</h4>\n<ul>\n<li><code>web/vite.config.ts</code> - Vite/Vitest configuration</li>\n<li><code>web/vitest.setup.ts</code> - Test environment setup</li>\n<li><code>web/scripts/analyze-component.js</code> - Component analysis tool</li>\n<li>Modules are not mocked automatically. Global mocks live in <code>web/vitest.setup.ts</code> (for example <code>react-i18next</code>, <code>next/image</code>); mock other modules like <code>ky</code> or <code>mime</code> locally in test files.</li>\n</ul>\n",
  "gh-fix-ci": "<h2>Gh Pr Checks Plan Fix</h2>\n<h3>Overview</h3>\n<p>Use gh to locate failing PR checks, fetch GitHub Actions logs for actionable failures, summarize the failure snippet, then propose a fix plan and implement after explicit approval.</p>\n<ul>\n<li>If a plan-oriented skill (for example <code>create-plan</code>) is available, use it; otherwise draft a concise plan inline and request approval before implementing.</li>\n</ul>\n<p>Prereq: authenticate with the standard GitHub CLI once (for example, run <code>gh auth login</code>), then confirm with <code>gh auth status</code> (repo + workflow scopes are typically required).</p>\n<h3>Inputs</h3>\n<ul>\n<li><code>repo</code>: path inside the repo (default <code>.</code>)</li>\n<li><code>pr</code>: PR number or URL (optional; defaults to current branch PR)</li>\n<li><code>gh</code> authentication for the repo host</li>\n</ul>\n<h3>Quick start</h3>\n<ul>\n<li><code>python &quot;&lt;path-to-skill&gt;/scripts/inspect_pr_checks.py&quot; --repo &quot;.&quot; --pr &quot;&lt;number-or-url&gt;&quot;</code></li>\n<li>Add <code>--json</code> if you want machine-friendly output for summarization.</li>\n</ul>\n<h3>Workflow</h3>\n<ol>\n<li>Verify gh authentication.<ul>\n<li>Run <code>gh auth status</code> in the repo.</li>\n<li>If unauthenticated, ask the user to run <code>gh auth login</code> (ensuring repo + workflow scopes) before proceeding.</li>\n</ul>\n</li>\n<li>Resolve the PR.<ul>\n<li>Prefer the current branch PR: <code>gh pr view --json number,url</code>.</li>\n<li>If the user provides a PR number or URL, use that directly.</li>\n</ul>\n</li>\n<li>Inspect failing checks (GitHub Actions only).<ul>\n<li>Preferred: run the bundled script (handles gh field drift and job-log fallbacks):<ul>\n<li><code>python &quot;&lt;path-to-skill&gt;/scripts/inspect_pr_checks.py&quot; --repo &quot;.&quot; --pr &quot;&lt;number-or-url&gt;&quot;</code></li>\n<li>Add <code>--json</code> for machine-friendly output.</li>\n</ul>\n</li>\n<li>Manual fallback:<ul>\n<li><code>gh pr checks &lt;pr&gt; --json name,state,bucket,link,startedAt,completedAt,workflow</code><ul>\n<li>If a field is rejected, rerun with the available fields reported by <code>gh</code>.</li>\n</ul>\n</li>\n<li>For each failing check, extract the run id from <code>detailsUrl</code> and run:<ul>\n<li><code>gh run view &lt;run_id&gt; --json name,workflowName,conclusion,status,url,event,headBranch,headSha</code></li>\n<li><code>gh run view &lt;run_id&gt; --log</code></li>\n</ul>\n</li>\n<li>If the run log says it is still in progress, fetch job logs directly:<ul>\n<li><code>gh api &quot;/repos/&lt;owner&gt;/&lt;repo&gt;/actions/jobs/&lt;job_id&gt;/logs&quot; &gt; &quot;&lt;path&gt;&quot;</code></li>\n</ul>\n</li>\n</ul>\n</li>\n</ul>\n</li>\n<li>Scope non-GitHub Actions checks.<ul>\n<li>If <code>detailsUrl</code> is not a GitHub Actions run, label it as external and only report the URL.</li>\n<li>Do not attempt Buildkite or other providers; keep the workflow lean.</li>\n</ul>\n</li>\n<li>Summarize failures for the user.<ul>\n<li>Provide the failing check name, run URL (if any), and a concise log snippet.</li>\n<li>Call out missing logs explicitly.</li>\n</ul>\n</li>\n<li>Create a plan.<ul>\n<li>Use the <code>create-plan</code> skill to draft a concise plan and request approval.</li>\n</ul>\n</li>\n<li>Implement after approval.<ul>\n<li>Apply the approved plan, summarize diffs/tests, and ask about opening a PR.</li>\n</ul>\n</li>\n<li>Recheck status.<ul>\n<li>After changes, suggest re-running the relevant tests and <code>gh pr checks</code> to confirm.</li>\n</ul>\n</li>\n</ol>\n<h3>Bundled Resources</h3>\n<h4>scripts/inspect_pr_checks.py</h4>\n<p>Fetch failing PR checks, pull GitHub Actions logs, and extract a failure snippet. Exits non-zero when failures remain so it can be used in automation.</p>\n<p>Usage examples:</p>\n<ul>\n<li><code>python &quot;&lt;path-to-skill&gt;/scripts/inspect_pr_checks.py&quot; --repo &quot;.&quot; --pr &quot;123&quot;</code></li>\n<li><code>python &quot;&lt;path-to-skill&gt;/scripts/inspect_pr_checks.py&quot; --repo &quot;.&quot; --pr &quot;https://github.com/org/repo/pull/123&quot; --json</code></li>\n<li><code>python &quot;&lt;path-to-skill&gt;/scripts/inspect_pr_checks.py&quot; --repo &quot;.&quot; --max-lines 200 --context 40</code></li>\n</ul>\n",
  "hono": "<h2>Hono Skill</h2>\n<p>Build Hono web applications. This skill provides inline API knowledge for AI. Use <code>npx hono request</code> to test endpoints. If the <code>hono-docs</code> MCP server is configured, prefer its tools for the latest documentation over the inline reference.</p>\n<h3>Hono CLI Usage</h3>\n<h4>Request Testing</h4>\n<p>Test endpoints without starting an HTTP server. Uses <code>app.request()</code> internally.</p>\n<pre><code class=\"language-bash\"># GET request\nnpx hono request [file] -P /path\n\n# POST request with JSON body\nnpx hono request [file] -X POST -P /api/users -d &#39;{&quot;name&quot;: &quot;test&quot;}&#39;\n</code></pre>\n<p><strong>Note:</strong> Do not pass credentials directly in CLI arguments. Use environment variables for sensitive values. <code>hono request</code> does not support Cloudflare Workers bindings (KV, D1, R2, etc.). When bindings are required, use <code>workers-fetch</code> instead:</p>\n<pre><code class=\"language-bash\">npx workers-fetch /path\nnpx workers-fetch -X POST -H &quot;Content-Type:application/json&quot; -d &#39;{&quot;name&quot;:&quot;test&quot;}&#39; /api/users\n</code></pre>\n<hr>\n<h3>Hono API Reference</h3>\n<h4>App Constructor</h4>\n<pre><code class=\"language-ts\">import { Hono } from &#39;hono&#39;\n\nconst app = new Hono()\n\n// With TypeScript generics\ntype Env = {\n  Bindings: { DATABASE: D1Database; KV: KVNamespace }\n  Variables: { user: User }\n}\nconst app = new Hono&lt;Env&gt;()\n</code></pre>\n<h4>Routing Methods</h4>\n<pre><code class=\"language-ts\">app.get(&#39;/path&#39;, handler)\napp.post(&#39;/path&#39;, handler)\napp.put(&#39;/path&#39;, handler)\napp.delete(&#39;/path&#39;, handler)\napp.patch(&#39;/path&#39;, handler)\napp.options(&#39;/path&#39;, handler)\napp.all(&#39;/path&#39;, handler) // all HTTP methods\napp.on(&#39;PURGE&#39;, &#39;/path&#39;, handler) // custom method\napp.on([&#39;PUT&#39;, &#39;DELETE&#39;], &#39;/path&#39;, handler) // multiple methods\n</code></pre>\n<h4>Routing Patterns</h4>\n<pre><code class=\"language-ts\">// Path parameters\napp.get(&#39;/user/:name&#39;, (c) =&gt; {\n  const name = c.req.param(&#39;name&#39;)\n  return c.json({ name })\n})\n\n// Multiple params\napp.get(&#39;/posts/:id/comments/:commentId&#39;, (c) =&gt; {\n  const { id, commentId } = c.req.param()\n})\n\n// Optional parameters\napp.get(&#39;/api/animal/:type?&#39;, (c) =&gt; c.text(&#39;Animal!&#39;))\n\n// Wildcards\napp.get(&#39;/wild/*/card&#39;, (c) =&gt; c.text(&#39;Wildcard&#39;))\n\n// Regexp constraints\napp.get(&#39;/post/:date{[0-9]+}/:title{[a-z]+}&#39;, (c) =&gt; {\n  const { date, title } = c.req.param()\n})\n\n// Chained routes\napp\n  .get(&#39;/endpoint&#39;, (c) =&gt; c.text(&#39;GET&#39;))\n  .post((c) =&gt; c.text(&#39;POST&#39;))\n  .delete((c) =&gt; c.text(&#39;DELETE&#39;))\n</code></pre>\n<h4>Route Grouping</h4>\n<pre><code class=\"language-ts\">// Using route()\nconst api = new Hono()\napi.get(&#39;/users&#39;, (c) =&gt; c.json([]))\n\nconst app = new Hono()\napp.route(&#39;/api&#39;, api) // mounts at /api/users\n\n// Using basePath()\nconst app = new Hono().basePath(&#39;/api&#39;)\napp.get(&#39;/users&#39;, (c) =&gt; c.json([])) // GET /api/users\n</code></pre>\n<h4>Error Handling</h4>\n<pre><code class=\"language-ts\">app.notFound((c) =&gt; c.json({ message: &#39;Not Found&#39; }, 404))\n\napp.onError((err, c) =&gt; {\n  console.error(err)\n  return c.json({ message: &#39;Internal Server Error&#39; }, 500)\n})\n</code></pre>\n<hr>\n<h3>Context (c)</h3>\n<h4>Response Methods</h4>\n<pre><code class=\"language-ts\">c.text(&#39;Hello&#39;) // text/plain\nc.json({ message: &#39;Hello&#39; }) // application/json\nc.html(&#39;&lt;h1&gt;Hello&lt;/h1&gt;&#39;) // text/html\nc.redirect(&#39;/new-path&#39;) // 302 redirect\nc.redirect(&#39;/new-path&#39;, 301) // 301 redirect\nc.body(&#39;raw body&#39;, 200, headers) // raw response\nc.notFound() // 404 response\n</code></pre>\n<h4>Headers &amp; Status</h4>\n<pre><code class=\"language-ts\">c.status(201)\nc.header(&#39;X-Custom&#39;, &#39;value&#39;)\nc.header(&#39;Cache-Control&#39;, &#39;no-store&#39;)\n</code></pre>\n<h4>Variables (request-scoped data)</h4>\n<pre><code class=\"language-ts\">// In middleware\nc.set(&#39;user&#39;, { id: 1, name: &#39;Alice&#39; })\n\n// In handler\nconst user = c.get(&#39;user&#39;)\n// or\nconst user = c.var.user\n</code></pre>\n<h4>Environment (Cloudflare Workers)</h4>\n<pre><code class=\"language-ts\">const value = await c.env.KV.get(&#39;key&#39;)\nconst db = c.env.DATABASE\nc.executionCtx.waitUntil(promise)\n</code></pre>\n<h4>Renderer</h4>\n<pre><code class=\"language-ts\">app.use(async (c, next) =&gt; {\n  c.setRenderer((content) =&gt;\n    c.html(\n      &lt;html&gt;&lt;body&gt;{content}&lt;/body&gt;&lt;/html&gt;\n    )\n  )\n  await next()\n})\n\napp.get(&#39;/&#39;, (c) =&gt; c.render(&lt;h1&gt;Hello&lt;/h1&gt;))\n</code></pre>\n<hr>\n<h3>HonoRequest (c.req)</h3>\n<pre><code class=\"language-ts\">c.req.param(&#39;id&#39;) // path parameter\nc.req.param() // all path params as object\nc.req.query(&#39;page&#39;) // query string parameter\nc.req.query() // all query params as object\nc.req.queries(&#39;tags&#39;) // multiple values: ?tags=A&amp;tags=B → [&#39;A&#39;, &#39;B&#39;]\nc.req.header(&#39;Authorization&#39;) // request header\nc.req.header() // all headers (keys are lowercase)\n\n// Body parsing\nawait c.req.json() // parse JSON body\nawait c.req.text() // parse text body\nawait c.req.formData() // parse as FormData\nawait c.req.parseBody() // parse multipart/form-data or urlencoded\nawait c.req.arrayBuffer() // parse as ArrayBuffer\nawait c.req.blob() // parse as Blob\n\n// Validated data (used with validator middleware)\nc.req.valid(&#39;json&#39;)\nc.req.valid(&#39;query&#39;)\nc.req.valid(&#39;form&#39;)\nc.req.valid(&#39;param&#39;)\n\n// Properties\nc.req.url // full URL string\nc.req.path // pathname\nc.req.method // HTTP method\nc.req.raw // underlying Request object\n</code></pre>\n<hr>\n<h3>Middleware</h3>\n<h4>Using Built-in Middleware</h4>\n<pre><code class=\"language-ts\">import { cors } from &#39;hono/cors&#39;\nimport { logger } from &#39;hono/logger&#39;\nimport { basicAuth } from &#39;hono/basic-auth&#39;\nimport { prettyJSON } from &#39;hono/pretty-json&#39;\nimport { secureHeaders } from &#39;hono/secure-headers&#39;\nimport { etag } from &#39;hono/etag&#39;\nimport { compress } from &#39;hono/compress&#39;\nimport { poweredBy } from &#39;hono/powered-by&#39;\nimport { timing } from &#39;hono/timing&#39;\nimport { cache } from &#39;hono/cache&#39;\nimport { bearerAuth } from &#39;hono/bearer-auth&#39;\nimport { jwt } from &#39;hono/jwt&#39;\nimport { csrf } from &#39;hono/csrf&#39;\nimport { ipRestriction } from &#39;hono/ip-restriction&#39;\nimport { bodyLimit } from &#39;hono/body-limit&#39;\nimport { requestId } from &#39;hono/request-id&#39;\nimport { methodOverride } from &#39;hono/method-override&#39;\nimport { trailingSlash, trimTrailingSlash } from &#39;hono/trailing-slash&#39;\n\n// Registration\napp.use(logger()) // all routes\napp.use(&#39;/api/*&#39;, cors()) // specific path\napp.post(&#39;/api/*&#39;, basicAuth({ username: &#39;admin&#39;, password: &#39;secret&#39; }))\n</code></pre>\n<h4>Custom Middleware</h4>\n<pre><code class=\"language-ts\">// Inline\napp.use(async (c, next) =&gt; {\n  const start = Date.now()\n  await next()\n  const elapsed = Date.now() - start\n  c.res.headers.set(&#39;X-Response-Time&#39;, `${elapsed}ms`)\n})\n\n// Reusable with createMiddleware\nimport { createMiddleware } from &#39;hono/factory&#39;\n\nconst auth = createMiddleware(async (c, next) =&gt; {\n  const token = c.req.header(&#39;Authorization&#39;)\n  if (!token) return c.json({ error: &#39;Unauthorized&#39; }, 401)\n  await next()\n})\n\napp.use(&#39;/api/*&#39;, auth)\n</code></pre>\n<h4>Middleware Execution Order</h4>\n<p>Middleware executes in registration order. <code>await next()</code> calls the next middleware/handler, and code after <code>next()</code> runs on the way back:</p>\n<pre><code>Request → mw1 before → mw2 before → handler → mw2 after → mw1 after → Response\n</code></pre>\n<pre><code class=\"language-ts\">app.use(async (c, next) =&gt; {\n  // before handler\n  await next()\n  // after handler\n})\n</code></pre>\n<hr>\n<h3>Validation</h3>\n<p>Validation targets: <code>json</code>, <code>form</code>, <code>query</code>, <code>header</code>, <code>param</code>, <code>cookie</code>.</p>\n<h4>Zod Validator</h4>\n<pre><code class=\"language-ts\">import { zValidator } from &#39;@hono/zod-validator&#39;\nimport { z } from &#39;zod&#39;\n\nconst schema = z.object({\n  title: z.string().min(1),\n  body: z.string()\n})\n\napp.post(&#39;/posts&#39;, zValidator(&#39;json&#39;, schema), (c) =&gt; {\n  const data = c.req.valid(&#39;json&#39;) // fully typed\n  return c.json(data, 201)\n})\n</code></pre>\n<h4>Valibot / Standard Schema Validator</h4>\n<pre><code class=\"language-ts\">import { sValidator } from &#39;@hono/standard-validator&#39;\nimport * as v from &#39;valibot&#39;\n\nconst schema = v.object({ name: v.string(), age: v.number() })\n\napp.post(&#39;/users&#39;, sValidator(&#39;json&#39;, schema), (c) =&gt; {\n  const data = c.req.valid(&#39;json&#39;)\n  return c.json(data, 201)\n})\n</code></pre>\n<hr>\n<h3>JSX</h3>\n<h4>Setup</h4>\n<p>In <code>tsconfig.json</code>:</p>\n<pre><code class=\"language-json\">{\n  &quot;compilerOptions&quot;: {\n    &quot;jsx&quot;: &quot;react-jsx&quot;,\n    &quot;jsxImportSource&quot;: &quot;hono/jsx&quot;\n  }\n}\n</code></pre>\n<p>Or use pragma: <code>/** @jsxImportSource hono/jsx */</code></p>\n<p><strong>Important:</strong> Files using JSX must have a <code>.tsx</code> extension. Rename <code>.ts</code> to <code>.tsx</code> or the compiler will fail.</p>\n<h4>Components</h4>\n<pre><code class=\"language-tsx\">import type { PropsWithChildren } from &#39;hono/jsx&#39;\n\nconst Layout = (props: PropsWithChildren) =&gt; (\n  &lt;html&gt;\n    &lt;head&gt;\n      &lt;title&gt;My App&lt;/title&gt;\n    &lt;/head&gt;\n    &lt;body&gt;{props.children}&lt;/body&gt;\n  &lt;/html&gt;\n)\n\nconst UserCard = ({ name }: { name: string }) =&gt; (\n  &lt;div class=&quot;card&quot;&gt;\n    &lt;h2&gt;{name}&lt;/h2&gt;\n  &lt;/div&gt;\n)\n\napp.get(&#39;/&#39;, (c) =&gt; {\n  return c.html(\n    &lt;Layout&gt;\n      &lt;UserCard name=&quot;Alice&quot; /&gt;\n    &lt;/Layout&gt;\n  )\n})\n</code></pre>\n<h4>jsxRenderer Middleware</h4>\n<p>Use <code>jsxRenderer</code> middleware for layouts. See <code>npx hono docs /docs/middleware/builtin/jsx-renderer</code> for details.</p>\n<h4>Async Components</h4>\n<pre><code class=\"language-tsx\">const UserList = async () =&gt; {\n  const users = await fetchUsers()\n  return (\n    &lt;ul&gt;\n      {users.map((u) =&gt; (\n        &lt;li&gt;{u.name}&lt;/li&gt;\n      ))}\n    &lt;/ul&gt;\n  )\n}\n</code></pre>\n<h4>Fragments</h4>\n<pre><code class=\"language-tsx\">const Items = () =&gt; (\n  &lt;&gt;\n    &lt;li&gt;Item 1&lt;/li&gt;\n    &lt;li&gt;Item 2&lt;/li&gt;\n  &lt;/&gt;\n)\n</code></pre>\n<hr>\n<h3>Streaming</h3>\n<pre><code class=\"language-ts\">import { stream, streamText, streamSSE } from &#39;hono/streaming&#39;\n\n// Basic stream\napp.get(&#39;/stream&#39;, (c) =&gt; {\n  return stream(c, async (stream) =&gt; {\n    stream.onAbort(() =&gt; console.log(&#39;Aborted&#39;))\n    await stream.write(new Uint8Array([0x48, 0x65]))\n    await stream.pipe(readableStream)\n  })\n})\n\n// Text stream\napp.get(&#39;/stream-text&#39;, (c) =&gt; {\n  return streamText(c, async (stream) =&gt; {\n    await stream.writeln(&#39;Hello&#39;)\n    await stream.sleep(1000)\n    await stream.write(&#39;World&#39;)\n  })\n})\n\n// Server-Sent Events\napp.get(&#39;/sse&#39;, (c) =&gt; {\n  return streamSSE(c, async (stream) =&gt; {\n    let id = 0\n    while (true) {\n      await stream.writeSSE({\n        data: JSON.stringify({ time: new Date().toISOString() }),\n        event: &#39;time-update&#39;,\n        id: String(id++)\n      })\n      await stream.sleep(1000)\n    }\n  })\n})\n</code></pre>\n<hr>\n<h3>Testing with app.request()</h3>\n<p>Test endpoints without starting an HTTP server:</p>\n<pre><code class=\"language-ts\">// GET\nconst res = await app.request(&#39;/posts&#39;)\nexpect(res.status).toBe(200)\nexpect(await res.json()).toEqual({ posts: [] })\n\n// POST with JSON\nconst res = await app.request(&#39;/posts&#39;, {\n  method: &#39;POST&#39;,\n  body: JSON.stringify({ title: &#39;Hello&#39; }),\n  headers: { &#39;Content-Type&#39;: &#39;application/json&#39; }\n})\n\n// POST with FormData\nconst formData = new FormData()\nformData.append(&#39;name&#39;, &#39;Alice&#39;)\nconst res = await app.request(&#39;/users&#39;, { method: &#39;POST&#39;, body: formData })\n\n// With mock env (Cloudflare Workers bindings)\nconst res = await app.request(&#39;/api/data&#39;, {}, { KV: mockKV, DATABASE: mockDB })\n\n// Using Request object\nconst req = new Request(&#39;http://localhost/api&#39;, { method: &#39;DELETE&#39; })\nconst res = await app.request(req)\n</code></pre>\n<hr>\n<h3>Hono Client (RPC)</h3>\n<p>Type-safe API client using shared types between server and client.</p>\n<p><strong>IMPORTANT: Routes MUST be chained for type inference to work. Without chaining, the client cannot infer route types.</strong></p>\n<pre><code class=\"language-ts\">// Server: routes MUST be chained to preserve types\nconst route = app\n  .post(&#39;/posts&#39;, zValidator(&#39;json&#39;, schema), (c) =&gt; {\n    return c.json({ ok: true }, 201)\n  })\n  .get(&#39;/posts&#39;, (c) =&gt; {\n    return c.json({ posts: [] })\n  })\nexport type AppType = typeof route\n\n// Client: use hc() with the exported type\nimport { hc } from &#39;hono/client&#39;\nimport type { AppType } from &#39;./server&#39;\n\nconst client = hc&lt;AppType&gt;(&#39;http://localhost:8787/&#39;)\nconst res = await client.posts.$post({ json: { title: &#39;Hello&#39; } })\nconst data = await res.json() // fully typed\n</code></pre>\n<p>Type utilities:</p>\n<pre><code class=\"language-ts\">import type { InferRequestType, InferResponseType } from &#39;hono/client&#39;\n\ntype ReqType = InferRequestType&lt;typeof client.posts.$post&gt;\ntype ResType = InferResponseType&lt;typeof client.posts.$post, 200&gt;\n</code></pre>\n<hr>\n<h3>Helpers</h3>\n<p>Helpers are utility functions imported from <code>hono/&lt;helper-name&gt;</code>:</p>\n<pre><code class=\"language-ts\">import { getConnInfo } from &#39;hono/conninfo&#39;\nimport { getCookie, setCookie, deleteCookie } from &#39;hono/cookie&#39;\nimport { css, Style } from &#39;hono/css&#39;\nimport { createFactory } from &#39;hono/factory&#39;\nimport { html, raw } from &#39;hono/html&#39;\nimport { stream, streamText, streamSSE } from &#39;hono/streaming&#39;\nimport { testClient } from &#39;hono/testing&#39;\nimport { upgradeWebSocket } from &#39;hono/cloudflare-workers&#39; // or other adapter\n</code></pre>\n<p>Available helpers: Accepts, Adapter, ConnInfo, Cookie, css, Dev, Factory, html, JWT, Proxy, Route, SSG, Streaming, Testing, WebSocket.</p>\n<p>For details, use <code>npx hono docs /docs/helpers/&lt;helper-name&gt;</code>.</p>\n<h4>Factory</h4>\n<p>Use <code>createFactory</code> to define <code>Env</code> once and share it across app, middleware, and handlers:</p>\n<pre><code class=\"language-ts\">import { createFactory } from &#39;hono/factory&#39;\n\nconst factory = createFactory&lt;Env&gt;()\n\n// Create app (Env type is inherited)\nconst app = factory.createApp()\n\n// Create middleware (Env type is inherited, no need to pass generics)\nconst mw = factory.createMiddleware(async (c, next) =&gt; {\n  await next()\n})\n\n// Create handlers separately (preserves type inference)\nconst handlers = factory.createHandlers(logger(), (c) =&gt; c.json({ message: &#39;Hello&#39; }))\napp.get(&#39;/api&#39;, ...handlers)\n</code></pre>\n<hr>\n<h3>Best Practices</h3>\n<ul>\n<li>Write handlers inline in route definitions for proper type inference of path params.</li>\n<li>Use <code>app.route()</code> to organize large apps by feature, not Rails-style controllers.</li>\n<li>Use <code>createFactory()</code> to share Env type across app, middleware, and handlers.</li>\n<li>Use <code>c.set()</code>/<code>c.get()</code> to pass data between middleware and handlers.</li>\n<li>Chain validators for multiple request parts (param + query + json).</li>\n<li>Export app type for RPC: <code>export type AppType = typeof routes</code></li>\n<li>Use <code>app.request()</code> for testing — no server startup needed.</li>\n</ul>\n<h3>Adapters</h3>\n<p>Hono runs on multiple runtimes. The default export works for Cloudflare Workers, Deno, and Bun. For Node.js, use the Node adapter:</p>\n<pre><code class=\"language-ts\">// Cloudflare Workers / Deno / Bun\nexport default app\n\n// Node.js\nimport { serve } from &#39;@hono/node-server&#39;\nserve(app)\n</code></pre>\n",
  "klip-writing": "<h2>KLIP Writing Skill</h2>\n<p>Write structured technical design documents following the KLIP format conventions established in the Fin-Agent project.</p>\n<h3>What is a KLIP</h3>\n<p>KLIP (Kevin&#39;s Lightweight Improvement Proposal) is a technical document format used for feature design, architecture evaluation, migration assessment, codebase review, and protocol specification. Each KLIP is a self-contained Markdown file that captures the full lifecycle of a technical decision: from background and motivation through design details to acceptance criteria.</p>\n<h3>When to Read Reference</h3>\n<p>Before writing any KLIP, read the reference document for structural patterns and field definitions:</p>\n<pre><code>Read: references/klip-conventions.md\n</code></pre>\n<p>This reference contains the canonical section catalog, KLIP category taxonomy, naming rules, frontmatter fields, and writing constraints extracted from real KLIPs.</p>\n<h3>Core Workflow</h3>\n<ol>\n<li><strong>Identify KLIP category</strong> from user intent (see reference for taxonomy).</li>\n<li><strong>Select applicable sections</strong> from the section catalog based on category.</li>\n<li><strong>Gather inputs</strong> from user: background context, codebase facts, constraints, decisions already made.</li>\n<li><strong>Write the KLIP</strong> following structural and writing rules.</li>\n<li><strong>Output</strong> as a Markdown file named <code>klip-{number}-{slug}.md</code>.</li>\n</ol>\n<h3>Writing Principles</h3>\n<p>These principles govern all KLIP writing. They are non-negotiable.</p>\n<h4>Grounded in code, not imagination</h4>\n<p>Every claim about current system behavior must cite a real file path, function name, or data structure. If the author has not verified a fact against the codebase, the KLIP must say &quot;待确认&quot; or leave a placeholder, never fabricate.</p>\n<h4>Honest about what is decided vs. what is not</h4>\n<p>Sections that record conclusions use definitive language. Sections that record open questions use &quot;待讨论&quot;, &quot;待确认&quot;, or &quot;建议&quot;. The two must never be mixed within the same paragraph.</p>\n<h4>Minimal viable scope per document</h4>\n<p>Each KLIP covers one coherent decision boundary. If scope creep is detected during writing, the overflow should be called out as a future KLIP reference (e.g., &quot;该策略在后续 klip 中补充&quot;).</p>\n<h4>No motivational padding</h4>\n<p>No sentences whose only purpose is to reassure the reader that the proposal is good. Every sentence must carry information or a decision.</p>\n<h4>Frontmatter is mandatory</h4>\n<pre><code class=\"language-yaml\">---\nAuthor: &quot;@handle&quot; or &quot;AgentName&quot;\nUpdated: YYYY-MM-DD\nStatus: Draft | Almost Complete | Complete | Completed\n---\n</code></pre>\n<p>Optional frontmatter fields for completed KLIPs:</p>\n<ul>\n<li><code>Reviewer</code>, <code>ReviewDate</code>, <code>ClosedDate</code></li>\n<li><code>Origin</code> (if derived from another KLIP)</li>\n</ul>\n<h3>Section Selection Guide</h3>\n<p>Not every KLIP needs every section. Choose based on category:</p>\n<table>\n<thead>\n<tr>\n<th>Category</th>\n<th>Required Sections</th>\n<th>Common Optional Sections</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Feature Design</td>\n<td>背景, 目标, 非目标, 设计概览, 验收标准</td>\n<td>前置依赖, 术语表, 组件设计, 数据存储, 实施阶段, 待讨论</td>\n</tr>\n<tr>\n<td>Architecture Evaluation</td>\n<td>现状结论, 背景, 目标, 非目标, 评估维度, 评估结果, 最终建议</td>\n<td>成本与风险, 目标态设计, 迁移计划, 回滚策略</td>\n</tr>\n<tr>\n<td>Codebase Review</td>\n<td>背景, 现状, 目标, 非目标, 发现与方案(P0/P1/P2), 建议落地顺序</td>\n<td>关键参考位置</td>\n</tr>\n<tr>\n<td>Protocol/Streaming Design</td>\n<td>现状结论, 背景, 目标, 非目标, 协议设计, 服务端设计, 前端设计, 兼容性要求</td>\n<td>测试矩阵, 实施阶段, 决策摘要</td>\n</tr>\n<tr>\n<td>State Migration</td>\n<td>现状结论, 目标, 非目标, 状态边界, 阶段进展, 验收标准</td>\n<td>关键决策与约定, 测试矩阵, 实施后检查清单</td>\n</tr>\n<tr>\n<td>Runtime Optimization</td>\n<td>背景, 目标, 非目标, 设计方案, 测试矩阵, 验收标准</td>\n<td>实施后检查清单</td>\n</tr>\n</tbody></table>\n<h3>Output Format</h3>\n<ul>\n<li>File: <code>klip-{N}-{english-slug}.md</code></li>\n<li>Language: 中文为主体，技术术语保留英文原文，代码/类型/字段名不翻译</li>\n<li>Heading style: <code>#</code> for title (must match filename slug), <code>##</code> for top-level sections, <code>###</code> for subsections</li>\n<li>Code blocks: use fenced code with language tag (<code>json, </code>typescript, ```mermaid, etc.)</li>\n<li>Tables: Markdown pipe tables, keep columns aligned</li>\n<li>Checklists: use <code>- [ ]</code> for pending, <code>- [x]</code> for done, <code>- [~]</code> for moved/deferred</li>\n</ul>\n<h3>Quick Start Example</h3>\n<p>User: &quot;我想写一个 klip，关于把 fin-echarts 的 kline 图表从 replace 模式升级为支持 append 流式追加&quot;</p>\n<p>This maps to <strong>Protocol/Streaming Design</strong> category. The KLIP would include:</p>\n<ul>\n<li>现状结论（code references to current kline rendering）</li>\n<li>背景（why replace-only is limiting）</li>\n<li>目标 / 非目标</li>\n<li>协议补充（new append command shape with candles array）</li>\n<li>对外契约补充（type definitions, skill constraints, completion payload）</li>\n<li>实现落点（server parser, frontend runtime, render layer）</li>\n<li>测试计划</li>\n<li>Phase 建议</li>\n</ul>\n",
  "modular-go": "<h2>modular-go</h2>\n<p>Concise guidance for designing Go packages that stay small, focused, and easy to evolve.</p>\n<h3>Purpose and Triggers</h3>\n<ul>\n<li>Use for Go package design, refactoring, and code review.</li>\n<li>Focus on API boundaries, state modeling, and flow decomposition.</li>\n<li>Use when deciding the right abstraction level: local helper, utility package, manager, or builder.</li>\n<li>Prefer explicit boundaries over convenience exports.</li>\n</ul>\n<h3>Design Principles</h3>\n<ol>\n<li>Every export is a promise — keep the public surface minimal and intentional.</li>\n<li>One package, one responsibility you can explain in one sentence.</li>\n<li>Depth over breadth — narrow interfaces that hide rich implementations outlast wide, shallow ones.</li>\n<li>Stateless by default — treat mutable state as liability that must justify its lifecycle cost.</li>\n<li>Split along responsibility seams, not file size — every new boundary must earn its indirection cost.</li>\n<li>Orchestration tells the story; capability methods do the work.</li>\n<li>Boundaries are translation layers — convert errors, types, and protocols at the edges, not in core logic.</li>\n<li>Choose the smallest abstraction that solves the real problem; resist premature generalization.</li>\n<li>Lifecycle is a first-class design concern — design shutdown paths alongside startup paths.</li>\n</ol>\n<h3>Workflow</h3>\n<ol>\n<li>Define one package responsibility.</li>\n<li>Expose one obvious primary entry point (type, interface, or function).</li>\n<li>Keep helpers local by default; extract to <code>xxxutil</code> only for real cross-package reuse.</li>\n<li>Keep transport handlers focused on protocol mapping and delegate behavior to injected dependencies.</li>\n<li>Compose orchestration from focused functions, with short stage-intent comments.</li>\n<li>Re-evaluate boundaries when a package can no longer be explained in one sentence.</li>\n<li>Re-check against the reference checklists before merge.</li>\n</ol>\n<h3>Topics</h3>\n<table>\n<thead>\n<tr>\n<th>Topic</th>\n<th>Guidance</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Module Boundary</td>\n<td>Expose minimal API and separate deep vs wide interfaces</td>\n<td><a href=\"references/module-boundary.md\">references/module-boundary.md</a></td>\n</tr>\n<tr>\n<td>State Flow</td>\n<td>Use stateless functions and one-shot state objects</td>\n<td><a href=\"references/state-flow.md\">references/state-flow.md</a></td>\n</tr>\n<tr>\n<td>Orchestration</td>\n<td>Use a single public executor and internal helpers</td>\n<td><a href=\"references/orchestration.md\">references/orchestration.md</a></td>\n</tr>\n<tr>\n<td>gRPC Practices</td>\n<td>Keep handlers as thin translators; isolate transport from domain</td>\n<td><a href=\"references/grpc-practices.md\">references/grpc-practices.md</a></td>\n</tr>\n<tr>\n<td>Review Checklist</td>\n<td>Run a fast architecture sanity check before merge</td>\n<td><a href=\"references/review-checklist.md\">references/review-checklist.md</a></td>\n</tr>\n</tbody></table>\n<h3>References</h3>\n<ul>\n<li>Reference files are intentionally short and task-focused.</li>\n<li>Source links are listed in each reference file frontmatter <code>urls</code>.</li>\n</ul>\n",
  "piglet": "<h2>piglet</h2>\n<p>Concise guidance for writing and reviewing Python code using patterns from One Python Craftsman.</p>\n<h3>Purpose and Triggers</h3>\n<ul>\n<li>Use for Python (.py) code creation, refactoring, or code review.</li>\n<li>Use when code quality issues involve naming, control flow, data handling, error handling, loops, decorators, imports, file I/O, edge cases, or the walrus operator.</li>\n<li>Prefer clarity and maintainability. Optimize performance only when it is a real constraint.</li>\n<li>If $friendly-python is available, suggest pairing it for a broader Python style and review checklist.</li>\n</ul>\n<h3>Decision Order</h3>\n<ol>\n<li>Correctness and explicit behavior</li>\n<li>Readability and maintainability</li>\n<li>Extension cost and change isolation</li>\n<li>Performance and micro-optimizations</li>\n</ol>\n<h3>Workflow</h3>\n<ol>\n<li>Identify the topic in the table below.</li>\n<li>Apply the guidance and compare against Bad and Good examples.</li>\n<li>If $friendly-python is available, recommend using it alongside this skill.</li>\n<li>Re-check for new edge cases and readability regressions.</li>\n</ol>\n<h3>Topics</h3>\n<table>\n<thead>\n<tr>\n<th>Topic</th>\n<th>Guidance</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Variables and Naming</td>\n<td>Descriptive names, avoid implicit magic, keep variable scope close</td>\n<td><a href=\"references/variables-and-naming.md\">references/variables-and-naming.md</a></td>\n</tr>\n<tr>\n<td>Branching and Conditions</td>\n<td>Avoid deep nesting, encapsulate complex conditions</td>\n<td><a href=\"references/if-else-and-branches.md\">references/if-else-and-branches.md</a></td>\n</tr>\n<tr>\n<td>Numbers, Strings, Containers</td>\n<td>Replace magic literals, pick the right container</td>\n<td><a href=\"references/values-and-containers.md\">references/values-and-containers.md</a></td>\n</tr>\n<tr>\n<td>Functions and Returns</td>\n<td>Stable return types, avoid error tuples</td>\n<td><a href=\"references/functions-and-returns.md\">references/functions-and-returns.md</a></td>\n</tr>\n<tr>\n<td>Exception Handling</td>\n<td>Catch only what you can handle, keep scopes small</td>\n<td><a href=\"references/exceptions-handling.md\">references/exceptions-handling.md</a></td>\n</tr>\n<tr>\n<td>Loops and Iteration</td>\n<td>Prefer iterator helpers over nested loops</td>\n<td><a href=\"references/loops-and-iteration.md\">references/loops-and-iteration.md</a></td>\n</tr>\n<tr>\n<td>Decorators</td>\n<td>Preserve signatures and avoid decorator footguns</td>\n<td><a href=\"references/decorators.md\">references/decorators.md</a></td>\n</tr>\n<tr>\n<td>Imports and Dependencies</td>\n<td>Prevent cycles with local imports and boundaries</td>\n<td><a href=\"references/imports-and-structure.md\">references/imports-and-structure.md</a></td>\n</tr>\n<tr>\n<td>Rules and File I/O</td>\n<td>Use proper data structures and pathlib</td>\n<td><a href=\"references/rules-and-file-io.md\">references/rules-and-file-io.md</a></td>\n</tr>\n<tr>\n<td>SOLID in Python</td>\n<td>Keep inheritance substitutable and behavior explicit</td>\n<td><a href=\"references/solid-python.md\">references/solid-python.md</a></td>\n</tr>\n<tr>\n<td>Edge Cases</td>\n<td>Prefer EAFP when it keeps the main path clear</td>\n<td><a href=\"references/edge-cases.md\">references/edge-cases.md</a></td>\n</tr>\n<tr>\n<td>Walrus Operator</td>\n<td>Use assignment expressions to remove repetition</td>\n<td><a href=\"references/walrus-operator.md\">references/walrus-operator.md</a></td>\n</tr>\n</tbody></table>\n<h3>References</h3>\n<ul>\n<li>Each reference file lists source URLs in its frontmatter <code>urls</code>.</li>\n</ul>\n",
  "playwright-cli": "<h2>Browser Automation with playwright-cli</h2>\n<h3>Quick start</h3>\n<pre><code class=\"language-bash\"># open new browser\nplaywright-cli open\n# navigate to a page\nplaywright-cli goto https://playwright.dev\n# interact with the page using refs from the snapshot\nplaywright-cli click e15\nplaywright-cli type &quot;page.click&quot;\nplaywright-cli press Enter\n# take a screenshot (rarely used, as snapshot is more common)\nplaywright-cli screenshot\n# close the browser\nplaywright-cli close\n</code></pre>\n<h3>Commands</h3>\n<h4>Core</h4>\n<pre><code class=\"language-bash\">playwright-cli open\n# open and navigate right away\nplaywright-cli open https://example.com/\nplaywright-cli goto https://playwright.dev\nplaywright-cli type &quot;search query&quot;\nplaywright-cli click e3\nplaywright-cli dblclick e7\n# --submit presses Enter after filling the element\nplaywright-cli fill e5 &quot;user@example.com&quot;  --submit\nplaywright-cli drag e2 e8\n# drop files or data onto an element (from outside the page)\nplaywright-cli drop e4 --path=./image.png\nplaywright-cli drop e4 --data=&quot;text/plain=hello world&quot;\nplaywright-cli hover e4\nplaywright-cli select e9 &quot;option-value&quot;\nplaywright-cli upload ./document.pdf\nplaywright-cli check e12\nplaywright-cli uncheck e12\nplaywright-cli snapshot\nplaywright-cli eval &quot;document.title&quot;\nplaywright-cli eval &quot;el =&gt; el.textContent&quot; e5\n# get element id, class, or any attribute not visible in the snapshot\nplaywright-cli eval &quot;el =&gt; el.id&quot; e5\nplaywright-cli eval &quot;el =&gt; el.getAttribute(&#39;data-testid&#39;)&quot; e5\nplaywright-cli dialog-accept\nplaywright-cli dialog-accept &quot;confirmation text&quot;\nplaywright-cli dialog-dismiss\nplaywright-cli resize 1920 1080\nplaywright-cli close\n</code></pre>\n<h4>Navigation</h4>\n<pre><code class=\"language-bash\">playwright-cli go-back\nplaywright-cli go-forward\nplaywright-cli reload\n</code></pre>\n<h4>Keyboard</h4>\n<pre><code class=\"language-bash\">playwright-cli press Enter\nplaywright-cli press ArrowDown\nplaywright-cli keydown Shift\nplaywright-cli keyup Shift\n</code></pre>\n<h4>Mouse</h4>\n<pre><code class=\"language-bash\">playwright-cli mousemove 150 300\nplaywright-cli mousedown\nplaywright-cli mousedown right\nplaywright-cli mouseup\nplaywright-cli mouseup right\nplaywright-cli mousewheel 0 100\n</code></pre>\n<h4>Save as</h4>\n<pre><code class=\"language-bash\">playwright-cli screenshot\nplaywright-cli screenshot e5\nplaywright-cli screenshot --filename=page.png\nplaywright-cli pdf --filename=page.pdf\n</code></pre>\n<h4>Tabs</h4>\n<pre><code class=\"language-bash\">playwright-cli tab-list\nplaywright-cli tab-new\nplaywright-cli tab-new https://example.com/page\nplaywright-cli tab-close\nplaywright-cli tab-close 2\nplaywright-cli tab-select 0\n</code></pre>\n<h4>Storage</h4>\n<pre><code class=\"language-bash\">playwright-cli state-save\nplaywright-cli state-save auth.json\nplaywright-cli state-load auth.json\n\n# Cookies\nplaywright-cli cookie-list\nplaywright-cli cookie-list --domain=example.com\nplaywright-cli cookie-get session_id\nplaywright-cli cookie-set session_id abc123\nplaywright-cli cookie-set session_id abc123 --domain=example.com --httpOnly --secure\nplaywright-cli cookie-delete session_id\nplaywright-cli cookie-clear\n\n# LocalStorage\nplaywright-cli localstorage-list\nplaywright-cli localstorage-get theme\nplaywright-cli localstorage-set theme dark\nplaywright-cli localstorage-delete theme\nplaywright-cli localstorage-clear\n\n# SessionStorage\nplaywright-cli sessionstorage-list\nplaywright-cli sessionstorage-get step\nplaywright-cli sessionstorage-set step 3\nplaywright-cli sessionstorage-delete step\nplaywright-cli sessionstorage-clear\n</code></pre>\n<h4>Network</h4>\n<pre><code class=\"language-bash\">playwright-cli route &quot;**/*.jpg&quot; --status=404\nplaywright-cli route &quot;https://api.example.com/**&quot; --body=&#39;{&quot;mock&quot;: true}&#39;\nplaywright-cli route-list\nplaywright-cli unroute &quot;**/*.jpg&quot;\nplaywright-cli unroute\n</code></pre>\n<h4>DevTools</h4>\n<pre><code class=\"language-bash\">playwright-cli console\nplaywright-cli console warning\nplaywright-cli requests\nplaywright-cli request 5\nplaywright-cli run-code &quot;async page =&gt; await page.context().grantPermissions([&#39;geolocation&#39;])&quot;\nplaywright-cli run-code --filename=script.js\nplaywright-cli tracing-start\nplaywright-cli tracing-stop\nplaywright-cli video-start video.webm\nplaywright-cli video-chapter &quot;Chapter Title&quot; --description=&quot;Details&quot; --duration=2000\nplaywright-cli video-stop\n\n# annotate each subsequent action (click, type, ...) with a callout naming the action and highlighting the target\nplaywright-cli video-show-actions --duration=600 --position=top-right\nplaywright-cli video-hide-actions\n\n# launch the dashboard for UI review / design feedback — user annotates the page, you receive the annotated screenshot, snapshot, and notes\nplaywright-cli show --annotate\n\n# generate a Playwright locator for an element from its ref or selector\nplaywright-cli generate-locator e5 --raw\n\n# show a persistent highlight overlay for an element, optionally with a custom style\nplaywright-cli highlight e5\nplaywright-cli highlight e5 --style=&quot;outline: 3px dashed red&quot;\n# hide a single element highlight, or all page highlights when no target is given\nplaywright-cli highlight e5 --hide\nplaywright-cli highlight --hide\n</code></pre>\n<h3>Raw output</h3>\n<p>The global <code>--raw</code> option strips page status, generated code, and snapshot sections from the output, returning only the result value. Use it to pipe command output into other tools. Commands that don&#39;t produce output return nothing.</p>\n<pre><code class=\"language-bash\">playwright-cli --raw eval &quot;JSON.stringify(performance.timing)&quot; | jq &#39;.loadEventEnd - .navigationStart&#39;\nplaywright-cli --raw eval &quot;JSON.stringify([...document.querySelectorAll(&#39;a&#39;)].map(a =&gt; a.href))&quot; &gt; links.json\nplaywright-cli --raw snapshot &gt; before.yml\nplaywright-cli click e5\nplaywright-cli --raw snapshot &gt; after.yml\ndiff before.yml after.yml\nTOKEN=$(playwright-cli --raw cookie-get session_id)\nplaywright-cli --raw localstorage-get theme\n</code></pre>\n<p>For structured output wrapping every reply as JSON, pass --json</p>\n<pre><code class=\"language-bash\">playwright-cli list --json\n</code></pre>\n<h3>Open parameters</h3>\n<pre><code class=\"language-bash\"># Use specific browser when creating session\nplaywright-cli open --browser=chrome\nplaywright-cli open --browser=firefox\nplaywright-cli open --browser=webkit\nplaywright-cli open --browser=msedge\n\n# Use persistent profile (by default profile is in-memory)\nplaywright-cli open --persistent\n# Use persistent profile with custom directory\nplaywright-cli open --profile=/path/to/profile\n\n# Connect to browser via Playwright Extension\nplaywright-cli attach --extension=chrome\n\n# Connect to a running Chrome or Edge by channel name\nplaywright-cli attach --cdp=chrome\nplaywright-cli attach --cdp=msedge\n\n# Connect to a running browser via CDP endpoint\nplaywright-cli attach --cdp=http://localhost:9222\n\n# Start with config file\nplaywright-cli open --config=my-config.json\n\n# Close the browser\nplaywright-cli close\n# Detach from an attached browser (leaves the external browser running)\nplaywright-cli -s=msedge detach\n# Delete user data for the default session\nplaywright-cli delete-data\n</code></pre>\n<h3>URLs with <code>&amp;</code> on Windows</h3>\n<p>On Windows, <code>cmd.exe</code> and PowerShell treat <code>&amp;</code> as a command separator, so URLs with multiple query parameters get truncated before <code>playwright-cli</code> runs. Escape <code>&amp;</code> with <code>^&amp;</code> in <code>cmd.exe</code>, or use <code>--%</code> in PowerShell:</p>\n<pre><code class=\"language-batch\">playwright-cli goto &quot;https://example.com/?a=1^&amp;b=2&quot;\n</code></pre>\n<pre><code class=\"language-powershell\">playwright-cli --% goto &quot;https://example.com/?a=1&amp;b=2&quot;\n</code></pre>\n<h3>Snapshots</h3>\n<p>After each command, playwright-cli provides a snapshot of the current browser state.</p>\n<pre><code class=\"language-bash\">&gt; playwright-cli goto https://example.com\n### Page\n- Page URL: https://example.com/\n- Page Title: Example Domain\n### Snapshot\n[Snapshot](.playwright-cli/page-2026-02-14T19-22-42-679Z.yml)\n</code></pre>\n<p>You can also take a snapshot on demand using <code>playwright-cli snapshot</code> command. All the options below can be combined as needed.</p>\n<pre><code class=\"language-bash\"># default - save to a file with timestamp-based name\nplaywright-cli snapshot\n\n# save to file, use when snapshot is a part of the workflow result\nplaywright-cli snapshot --filename=after-click.yaml\n\n# snapshot an element instead of the whole page\nplaywright-cli snapshot &quot;#main&quot;\n\n# limit snapshot depth for efficiency, take a partial snapshot afterwards\nplaywright-cli snapshot --depth=4\nplaywright-cli snapshot e34\n\n# include each element&#39;s bounding box as [box=x,y,width,height]\nplaywright-cli snapshot --boxes\n</code></pre>\n<h3>Targeting elements</h3>\n<p>By default, use refs from the snapshot to interact with page elements.</p>\n<pre><code class=\"language-bash\"># get snapshot with refs\nplaywright-cli snapshot\n\n# interact using a ref\nplaywright-cli click e15\n</code></pre>\n<p>You can also use css selectors or Playwright locators.</p>\n<pre><code class=\"language-bash\"># css selector\nplaywright-cli click &quot;#main &gt; button.submit&quot;\n\n# role locator\nplaywright-cli click &quot;getByRole(&#39;button&#39;, { name: &#39;Submit&#39; })&quot;\n\n# test id\nplaywright-cli click &quot;getByTestId(&#39;submit-button&#39;)&quot;\n</code></pre>\n<h3>Browser Sessions</h3>\n<pre><code class=\"language-bash\"># create new browser session named &quot;mysession&quot; with persistent profile\nplaywright-cli -s=mysession open example.com --persistent\n# same with manually specified profile directory (use when requested explicitly)\nplaywright-cli -s=mysession open example.com --profile=/path/to/profile\nplaywright-cli -s=mysession click e6\nplaywright-cli -s=mysession close  # stop a named browser\nplaywright-cli -s=mysession delete-data  # delete user data for persistent session\n\nplaywright-cli list\n# Close all browsers\nplaywright-cli close-all\n# Forcefully kill all browser processes\nplaywright-cli kill-all\n</code></pre>\n<h3>Installation</h3>\n<p>If global <code>playwright-cli</code> command is not available, try a local version via <code>npx playwright-cli</code>:</p>\n<pre><code class=\"language-bash\">npx --no-install playwright-cli --version\n</code></pre>\n<p>When local version is available, use <code>npx playwright-cli</code> in all commands. Otherwise, install <code>playwright-cli</code> as a global command:</p>\n<pre><code class=\"language-bash\">npm install -g @playwright/cli@latest\n</code></pre>\n<h3>Example: Form submission</h3>\n<pre><code class=\"language-bash\">playwright-cli open https://example.com/form\nplaywright-cli snapshot\n\nplaywright-cli fill e1 &quot;user@example.com&quot;\nplaywright-cli fill e2 &quot;password123&quot;\nplaywright-cli click e3\nplaywright-cli snapshot\nplaywright-cli close\n</code></pre>\n<h3>Example: Multi-tab workflow</h3>\n<pre><code class=\"language-bash\">playwright-cli open https://example.com\nplaywright-cli tab-new https://example.com/other\nplaywright-cli tab-list\nplaywright-cli tab-select 0\nplaywright-cli snapshot\nplaywright-cli close\n</code></pre>\n<h3>Example: Debugging with DevTools</h3>\n<pre><code class=\"language-bash\">playwright-cli open https://example.com\nplaywright-cli click e4\nplaywright-cli fill e7 &quot;test&quot;\nplaywright-cli console\nplaywright-cli requests\nplaywright-cli close\n</code></pre>\n<pre><code class=\"language-bash\">playwright-cli open https://example.com\nplaywright-cli tracing-start\nplaywright-cli click e4\nplaywright-cli fill e7 &quot;test&quot;\nplaywright-cli tracing-stop\nplaywright-cli close\n</code></pre>\n<h3>Example: Interactive session</h3>\n<p>Ask the user for UI review or design feedback. The user draws boxes on the live page and types comments; you receive the annotated screenshot, the snapshot of the marked region, and the user&#39;s notes. Use this whenever the user asks for &quot;UI review&quot;, &quot;design feedback&quot;, or to &quot;ask the user what they think / want / mean&quot;:</p>\n<pre><code class=\"language-bash\">playwright-cli open https://example.com\nplaywright-cli show --annotate\n</code></pre>\n<h3>Specific tasks</h3>\n<ul>\n<li><strong>Running and Debugging Playwright tests</strong> <a href=\"references/playwright-tests.md\">references/playwright-tests.md</a></li>\n<li><strong>Request mocking</strong> <a href=\"references/request-mocking.md\">references/request-mocking.md</a></li>\n<li><strong>Running Playwright code</strong> <a href=\"references/running-code.md\">references/running-code.md</a></li>\n<li><strong>Browser session management</strong> <a href=\"references/session-management.md\">references/session-management.md</a></li>\n<li><strong>Spec-driven testing (plan / generate / heal)</strong> <a href=\"references/spec-driven-testing.md\">references/spec-driven-testing.md</a></li>\n<li><strong>Storage state (cookies, localStorage)</strong> <a href=\"references/storage-state.md\">references/storage-state.md</a></li>\n<li><strong>Test generation</strong> <a href=\"references/test-generation.md\">references/test-generation.md</a></li>\n<li><strong>Tracing</strong> <a href=\"references/tracing.md\">references/tracing.md</a></li>\n<li><strong>Video recording</strong> <a href=\"references/video-recording.md\">references/video-recording.md</a></li>\n<li><strong>Inspecting element attributes</strong> <a href=\"references/element-attributes.md\">references/element-attributes.md</a></li>\n</ul>\n",
  "react-best-practices": "<h2>Vercel React Best Practices</h2>\n<p>Comprehensive performance optimization guide for React and Next.js applications, maintained by Vercel. Contains 70 rules across 8 categories, prioritized by impact to guide automated refactoring and code generation.</p>\n<h3>When to Apply</h3>\n<p>Reference these guidelines when:</p>\n<ul>\n<li>Writing new React components or Next.js pages</li>\n<li>Implementing data fetching (client or server-side)</li>\n<li>Reviewing code for performance issues</li>\n<li>Refactoring existing React/Next.js code</li>\n<li>Optimizing bundle size or load times</li>\n</ul>\n<h3>Rule Categories by Priority</h3>\n<table>\n<thead>\n<tr>\n<th>Priority</th>\n<th>Category</th>\n<th>Impact</th>\n<th>Prefix</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>1</td>\n<td>Eliminating Waterfalls</td>\n<td>CRITICAL</td>\n<td><code>async-</code></td>\n</tr>\n<tr>\n<td>2</td>\n<td>Bundle Size Optimization</td>\n<td>CRITICAL</td>\n<td><code>bundle-</code></td>\n</tr>\n<tr>\n<td>3</td>\n<td>Server-Side Performance</td>\n<td>HIGH</td>\n<td><code>server-</code></td>\n</tr>\n<tr>\n<td>4</td>\n<td>Client-Side Data Fetching</td>\n<td>MEDIUM-HIGH</td>\n<td><code>client-</code></td>\n</tr>\n<tr>\n<td>5</td>\n<td>Re-render Optimization</td>\n<td>MEDIUM</td>\n<td><code>rerender-</code></td>\n</tr>\n<tr>\n<td>6</td>\n<td>Rendering Performance</td>\n<td>MEDIUM</td>\n<td><code>rendering-</code></td>\n</tr>\n<tr>\n<td>7</td>\n<td>JavaScript Performance</td>\n<td>LOW-MEDIUM</td>\n<td><code>js-</code></td>\n</tr>\n<tr>\n<td>8</td>\n<td>Advanced Patterns</td>\n<td>LOW</td>\n<td><code>advanced-</code></td>\n</tr>\n</tbody></table>\n<h3>Quick Reference</h3>\n<h4>1. Eliminating Waterfalls (CRITICAL)</h4>\n<ul>\n<li><code>async-cheap-condition-before-await</code> - Check cheap sync conditions before awaiting flags or remote values</li>\n<li><code>async-defer-await</code> - Move await into branches where actually used</li>\n<li><code>async-parallel</code> - Use Promise.all() for independent operations</li>\n<li><code>async-dependencies</code> - Use better-all for partial dependencies</li>\n<li><code>async-api-routes</code> - Start promises early, await late in API routes</li>\n<li><code>async-suspense-boundaries</code> - Use Suspense to stream content</li>\n</ul>\n<h4>2. Bundle Size Optimization (CRITICAL)</h4>\n<ul>\n<li><code>bundle-barrel-imports</code> - Import directly, avoid barrel files</li>\n<li><code>bundle-analyzable-paths</code> - Prefer statically analyzable import and file-system paths to avoid broad bundles and traces</li>\n<li><code>bundle-dynamic-imports</code> - Use next/dynamic for heavy components</li>\n<li><code>bundle-defer-third-party</code> - Load analytics/logging after hydration</li>\n<li><code>bundle-conditional</code> - Load modules only when feature is activated</li>\n<li><code>bundle-preload</code> - Preload on hover/focus for perceived speed</li>\n</ul>\n<h4>3. Server-Side Performance (HIGH)</h4>\n<ul>\n<li><code>server-auth-actions</code> - Authenticate server actions like API routes</li>\n<li><code>server-cache-react</code> - Use React.cache() for per-request deduplication</li>\n<li><code>server-cache-lru</code> - Use LRU cache for cross-request caching</li>\n<li><code>server-dedup-props</code> - Avoid duplicate serialization in RSC props</li>\n<li><code>server-hoist-static-io</code> - Hoist static I/O (fonts, logos) to module level</li>\n<li><code>server-no-shared-module-state</code> - Avoid module-level mutable request state in RSC/SSR</li>\n<li><code>server-serialization</code> - Minimize data passed to client components</li>\n<li><code>server-parallel-fetching</code> - Restructure components to parallelize fetches</li>\n<li><code>server-parallel-nested-fetching</code> - Chain nested fetches per item in Promise.all</li>\n<li><code>server-after-nonblocking</code> - Use after() for non-blocking operations</li>\n</ul>\n<h4>4. Client-Side Data Fetching (MEDIUM-HIGH)</h4>\n<ul>\n<li><code>client-swr-dedup</code> - Use SWR for automatic request deduplication</li>\n<li><code>client-event-listeners</code> - Deduplicate global event listeners</li>\n<li><code>client-passive-event-listeners</code> - Use passive listeners for scroll</li>\n<li><code>client-localstorage-schema</code> - Version and minimize localStorage data</li>\n</ul>\n<h4>5. Re-render Optimization (MEDIUM)</h4>\n<ul>\n<li><code>rerender-defer-reads</code> - Don&#39;t subscribe to state only used in callbacks</li>\n<li><code>rerender-memo</code> - Extract expensive work into memoized components</li>\n<li><code>rerender-memo-with-default-value</code> - Hoist default non-primitive props</li>\n<li><code>rerender-dependencies</code> - Use primitive dependencies in effects</li>\n<li><code>rerender-derived-state</code> - Subscribe to derived booleans, not raw values</li>\n<li><code>rerender-derived-state-no-effect</code> - Derive state during render, not effects</li>\n<li><code>rerender-functional-setstate</code> - Use functional setState for stable callbacks</li>\n<li><code>rerender-lazy-state-init</code> - Pass function to useState for expensive values</li>\n<li><code>rerender-simple-expression-in-memo</code> - Avoid memo for simple primitives</li>\n<li><code>rerender-split-combined-hooks</code> - Split hooks with independent dependencies</li>\n<li><code>rerender-move-effect-to-event</code> - Put interaction logic in event handlers</li>\n<li><code>rerender-transitions</code> - Use startTransition for non-urgent updates</li>\n<li><code>rerender-use-deferred-value</code> - Defer expensive renders to keep input responsive</li>\n<li><code>rerender-use-ref-transient-values</code> - Use refs for transient frequent values</li>\n<li><code>rerender-no-inline-components</code> - Don&#39;t define components inside components</li>\n</ul>\n<h4>6. Rendering Performance (MEDIUM)</h4>\n<ul>\n<li><code>rendering-animate-svg-wrapper</code> - Animate div wrapper, not SVG element</li>\n<li><code>rendering-content-visibility</code> - Use content-visibility for long lists</li>\n<li><code>rendering-hoist-jsx</code> - Extract static JSX outside components</li>\n<li><code>rendering-svg-precision</code> - Reduce SVG coordinate precision</li>\n<li><code>rendering-hydration-no-flicker</code> - Use inline script for client-only data</li>\n<li><code>rendering-hydration-suppress-warning</code> - Suppress expected mismatches</li>\n<li><code>rendering-activity</code> - Use Activity component for show/hide</li>\n<li><code>rendering-conditional-render</code> - Use ternary, not &amp;&amp; for conditionals</li>\n<li><code>rendering-usetransition-loading</code> - Prefer useTransition for loading state</li>\n<li><code>rendering-resource-hints</code> - Use React DOM resource hints for preloading</li>\n<li><code>rendering-script-defer-async</code> - Use defer or async on script tags</li>\n</ul>\n<h4>7. JavaScript Performance (LOW-MEDIUM)</h4>\n<ul>\n<li><code>js-batch-dom-css</code> - Group CSS changes via classes or cssText</li>\n<li><code>js-index-maps</code> - Build Map for repeated lookups</li>\n<li><code>js-cache-property-access</code> - Cache object properties in loops</li>\n<li><code>js-cache-function-results</code> - Cache function results in module-level Map</li>\n<li><code>js-cache-storage</code> - Cache localStorage/sessionStorage reads</li>\n<li><code>js-combine-iterations</code> - Combine multiple filter/map into one loop</li>\n<li><code>js-length-check-first</code> - Check array length before expensive comparison</li>\n<li><code>js-early-exit</code> - Return early from functions</li>\n<li><code>js-hoist-regexp</code> - Hoist RegExp creation outside loops</li>\n<li><code>js-min-max-loop</code> - Use loop for min/max instead of sort</li>\n<li><code>js-set-map-lookups</code> - Use Set/Map for O(1) lookups</li>\n<li><code>js-tosorted-immutable</code> - Use toSorted() for immutability</li>\n<li><code>js-flatmap-filter</code> - Use flatMap to map and filter in one pass</li>\n<li><code>js-request-idle-callback</code> - Defer non-critical work to browser idle time</li>\n</ul>\n<h4>8. Advanced Patterns (LOW)</h4>\n<ul>\n<li><code>advanced-effect-event-deps</code> - Don&#39;t put <code>useEffectEvent</code> results in effect deps</li>\n<li><code>advanced-event-handler-refs</code> - Store event handlers in refs</li>\n<li><code>advanced-init-once</code> - Initialize app once per app load</li>\n<li><code>advanced-use-latest</code> - useLatest for stable callback refs</li>\n</ul>\n<h3>How to Use</h3>\n<p>Read individual rule files for detailed explanations and code examples:</p>\n<pre><code>rules/async-parallel.md\nrules/bundle-barrel-imports.md\n</code></pre>\n<p>Each rule file contains:</p>\n<ul>\n<li>Brief explanation of why it matters</li>\n<li>Incorrect code example with explanation</li>\n<li>Correct code example with explanation</li>\n<li>Additional context and references</li>\n</ul>\n<h3>Full Compiled Document</h3>\n<p>For the complete guide with all rules expanded: <code>AGENTS.md</code></p>\n",
  "react-view-transitions": "<h2>React View Transitions</h2>\n<p>Animate between UI states using the browser&#39;s native <code>document.startViewTransition</code>. Declare <em>what</em> with <code>&lt;ViewTransition&gt;</code>, trigger <em>when</em> with <code>startTransition</code> / <code>useDeferredValue</code> / <code>Suspense</code>, control <em>how</em> with CSS classes. Unsupported browsers skip animations gracefully.</p>\n<h3>When to Animate</h3>\n<p>Every <code>&lt;ViewTransition&gt;</code> should communicate a spatial relationship or continuity. If you can&#39;t articulate what it communicates, don&#39;t add it.</p>\n<p>Implement <strong>all</strong> applicable patterns from this list, in this order:</p>\n<table>\n<thead>\n<tr>\n<th>Priority</th>\n<th>Pattern</th>\n<th>What it communicates</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>1</td>\n<td><strong>Shared element</strong> (<code>name</code>)</td>\n<td>&quot;Same thing — going deeper&quot;</td>\n</tr>\n<tr>\n<td>2</td>\n<td><strong>Suspense reveal</strong></td>\n<td>&quot;Data loaded&quot;</td>\n</tr>\n<tr>\n<td>3</td>\n<td><strong>List identity</strong> (per-item <code>key</code>)</td>\n<td>&quot;Same items, new arrangement&quot;</td>\n</tr>\n<tr>\n<td>4</td>\n<td><strong>State change</strong> (<code>enter</code>/<code>exit</code>)</td>\n<td>&quot;Something appeared/disappeared&quot;</td>\n</tr>\n<tr>\n<td>5</td>\n<td><strong>Route change</strong> (layout-level)</td>\n<td>&quot;Going to a new place&quot;</td>\n</tr>\n</tbody></table>\n<p>This is an implementation order, not a &quot;pick one&quot; list. Implement every pattern that fits the app. Only skip a pattern if the app has no use case for it.</p>\n<h4>Choosing Animation Style</h4>\n<table>\n<thead>\n<tr>\n<th>Context</th>\n<th>Animation</th>\n<th>Why</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Hierarchical navigation (list → detail)</td>\n<td>Type-keyed <code>nav-forward</code> / <code>nav-back</code></td>\n<td>Communicates spatial depth</td>\n</tr>\n<tr>\n<td>Lateral navigation (tab-to-tab)</td>\n<td>Bare <code>&lt;ViewTransition&gt;</code> (fade) or <code>default=&quot;none&quot;</code></td>\n<td>No depth to communicate</td>\n</tr>\n<tr>\n<td>Suspense reveal</td>\n<td><code>enter</code>/<code>exit</code> string props</td>\n<td>Content arriving</td>\n</tr>\n<tr>\n<td>Revalidation / background refresh</td>\n<td><code>default=&quot;none&quot;</code></td>\n<td>Silent — no animation needed</td>\n</tr>\n</tbody></table>\n<p>Reserve directional slides for hierarchical navigation (list → detail) and ordered sequences (prev/next photo, carousel, paginated results). For ordered sequences, the direction communicates position: &quot;next&quot; slides from right, &quot;previous&quot; from left. Lateral/unordered navigation (tab-to-tab) should not use directional slides — it falsely implies spatial depth.</p>\n<hr>\n<h3>Availability</h3>\n<ul>\n<li><strong>Next.js:</strong> Do <strong>not</strong> install <code>react@canary</code> — the App Router already bundles React canary internally. <code>ViewTransition</code> works out of the box. <code>npm ls react</code> may show a stable-looking version; this is expected.</li>\n<li><strong>Without Next.js:</strong> Install <code>react@canary react-dom@canary</code> (<code>ViewTransition</code> is not in stable React).</li>\n<li>Browser support: Chromium 111+, Firefox 144+, Safari 18.2+. Graceful degradation on unsupported browsers.</li>\n</ul>\n<hr>\n<h3>Implementation Workflow</h3>\n<p>When adding view transitions to an existing app, <strong>follow <code>references/implementation.md</code> step by step.</strong> Start with the audit — do not skip it. Copy the CSS recipes from <code>references/css-recipes.md</code> into the global stylesheet — do not write your own animation CSS.</p>\n<hr>\n<h3>Core Concepts</h3>\n<h4>The <code>&lt;ViewTransition&gt;</code> Component</h4>\n<pre><code class=\"language-jsx\">import { ViewTransition } from &#39;react&#39;;\n\n&lt;ViewTransition&gt;\n  &lt;Component /&gt;\n&lt;/ViewTransition&gt;\n</code></pre>\n<p>React auto-assigns a unique <code>view-transition-name</code> and calls <code>document.startViewTransition</code> behind the scenes. Never call <code>startViewTransition</code> yourself.</p>\n<h4>Animation Triggers</h4>\n<table>\n<thead>\n<tr>\n<th>Trigger</th>\n<th>When it fires</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><strong>enter</strong></td>\n<td><code>&lt;ViewTransition&gt;</code> first inserted during a Transition</td>\n</tr>\n<tr>\n<td><strong>exit</strong></td>\n<td><code>&lt;ViewTransition&gt;</code> first removed during a Transition</td>\n</tr>\n<tr>\n<td><strong>update</strong></td>\n<td>DOM mutations inside a <code>&lt;ViewTransition&gt;</code>. With nested VTs, mutation applies to the innermost one</td>\n</tr>\n<tr>\n<td><strong>share</strong></td>\n<td>Named VT unmounts and another with same <code>name</code> mounts in the same Transition</td>\n</tr>\n</tbody></table>\n<p>Only <code>startTransition</code>, <code>useDeferredValue</code>, or <code>Suspense</code> activate VTs. Regular <code>setState</code> does not animate.</p>\n<h4>Critical Placement Rule</h4>\n<p><code>&lt;ViewTransition&gt;</code> only activates enter/exit if it appears <strong>before any DOM nodes</strong>:</p>\n<pre><code class=\"language-jsx\">// Works\n&lt;ViewTransition enter=&quot;auto&quot; exit=&quot;auto&quot;&gt;\n  &lt;div&gt;Content&lt;/div&gt;\n&lt;/ViewTransition&gt;\n\n// Broken — div wraps the VT, suppressing enter/exit\n&lt;div&gt;\n  &lt;ViewTransition enter=&quot;auto&quot; exit=&quot;auto&quot;&gt;\n    &lt;div&gt;Content&lt;/div&gt;\n  &lt;/ViewTransition&gt;\n&lt;/div&gt;\n</code></pre>\n<hr>\n<h3>Styling with View Transition Classes</h3>\n<h4>Props</h4>\n<p>Values: <code>&quot;auto&quot;</code> (browser cross-fade), <code>&quot;none&quot;</code> (disabled), <code>&quot;class-name&quot;</code> (custom CSS), or <code>{ [type]: value }</code> for type-specific animations.</p>\n<pre><code class=\"language-jsx\">&lt;ViewTransition default=&quot;none&quot; enter=&quot;slide-in&quot; exit=&quot;slide-out&quot; share=&quot;morph&quot; /&gt;\n</code></pre>\n<p>If <code>default</code> is <code>&quot;none&quot;</code>, all triggers are off unless explicitly listed.</p>\n<h4>CSS Pseudo-Elements</h4>\n<ul>\n<li><code>::view-transition-old(.class)</code> — outgoing snapshot</li>\n<li><code>::view-transition-new(.class)</code> — incoming snapshot</li>\n<li><code>::view-transition-group(.class)</code> — container</li>\n<li><code>::view-transition-image-pair(.class)</code> — old + new pair</li>\n</ul>\n<p>See <code>references/css-recipes.md</code> for ready-to-use animation recipes.</p>\n<hr>\n<h3>Transition Types</h3>\n<p>Tag transitions with <code>addTransitionType</code> so VTs can pick different animations based on context. Call it multiple times to stack types — different VTs in the tree react to different types:</p>\n<pre><code class=\"language-jsx\">startTransition(() =&gt; {\n  addTransitionType(&#39;nav-forward&#39;);\n  addTransitionType(&#39;select-item&#39;);\n  router.push(&#39;/detail/1&#39;);\n});\n</code></pre>\n<p>Pass an object to map types to CSS classes. Works on <code>enter</code>, <code>exit</code>, <strong>and</strong> <code>share</code>:</p>\n<pre><code class=\"language-jsx\">&lt;ViewTransition\n  enter={{ &#39;nav-forward&#39;: &#39;slide-from-right&#39;, &#39;nav-back&#39;: &#39;slide-from-left&#39;, default: &#39;none&#39; }}\n  exit={{ &#39;nav-forward&#39;: &#39;slide-to-left&#39;, &#39;nav-back&#39;: &#39;slide-to-right&#39;, default: &#39;none&#39; }}\n  share={{ &#39;nav-forward&#39;: &#39;morph-forward&#39;, &#39;nav-back&#39;: &#39;morph-back&#39;, default: &#39;morph&#39; }}\n  default=&quot;none&quot;\n&gt;\n  &lt;Page /&gt;\n&lt;/ViewTransition&gt;\n</code></pre>\n<p><code>enter</code> and <code>exit</code> don&#39;t have to be symmetric. For example, fade in but slide out directionally:</p>\n<pre><code class=\"language-jsx\">&lt;ViewTransition\n  enter={{ &#39;nav-forward&#39;: &#39;fade-in&#39;, &#39;nav-back&#39;: &#39;fade-in&#39;, default: &#39;none&#39; }}\n  exit={{ &#39;nav-forward&#39;: &#39;nav-forward&#39;, &#39;nav-back&#39;: &#39;nav-back&#39;, default: &#39;none&#39; }}\n  default=&quot;none&quot;\n&gt;\n</code></pre>\n<p><strong>TypeScript:</strong> <code>ViewTransitionClassPerType</code> requires a <code>default</code> key in the object.</p>\n<p>For apps with multiple pages, extract the type-keyed VT into a reusable wrapper:</p>\n<pre><code class=\"language-jsx\">export function DirectionalTransition({ children }: { children: React.ReactNode }) {\n  return (\n    &lt;ViewTransition\n      enter={{ &#39;nav-forward&#39;: &#39;nav-forward&#39;, &#39;nav-back&#39;: &#39;nav-back&#39;, default: &#39;none&#39; }}\n      exit={{ &#39;nav-forward&#39;: &#39;nav-forward&#39;, &#39;nav-back&#39;: &#39;nav-back&#39;, default: &#39;none&#39; }}\n      default=&quot;none&quot;\n    &gt;\n      {children}\n    &lt;/ViewTransition&gt;\n  );\n}\n</code></pre>\n<h4><code>router.back()</code> and Browser Back Button</h4>\n<p><code>router.back()</code> and the browser&#39;s back/forward buttons do <strong>not</strong> trigger view transitions (<code>popstate</code> is synchronous, incompatible with <code>startViewTransition</code>). Use <code>router.push()</code> with an explicit URL instead.</p>\n<h4>Types and Suspense</h4>\n<p>Types are available during navigation but <strong>not</strong> during subsequent Suspense reveals (separate transitions, no type). Use type maps for page-level enter/exit; use simple string props for Suspense reveals.</p>\n<hr>\n<h3>Shared Element Transitions</h3>\n<p>Same <code>name</code> on two VTs — one unmounting, one mounting — creates a shared element morph:</p>\n<pre><code class=\"language-jsx\">&lt;ViewTransition name=&quot;hero-image&quot;&gt;\n  &lt;img src=&quot;/thumb.jpg&quot; onClick={() =&gt; startTransition(() =&gt; onSelect())} /&gt;\n&lt;/ViewTransition&gt;\n\n// On the other view — same name\n&lt;ViewTransition name=&quot;hero-image&quot;&gt;\n  &lt;img src=&quot;/full.jpg&quot; /&gt;\n&lt;/ViewTransition&gt;\n</code></pre>\n<ul>\n<li>Only one VT with a given <code>name</code> can be mounted at a time — use unique names (<code>photo-${id}</code>). Watch for reusable components: if a component with a named VT is rendered in both a modal/popover <em>and</em> a page, both mount simultaneously and break the morph. Either make the name conditional (via a prop) or move the named VT out of the shared component into the specific consumer.</li>\n<li><code>share</code> takes precedence over <code>enter</code>/<code>exit</code>. Think through each navigation path: when no matching pair forms (e.g., the target page doesn&#39;t have the same name), <code>enter</code>/<code>exit</code> fires instead. Consider whether the element needs a fallback animation for those paths.</li>\n<li>Never use a fade-out exit on pages with shared morphs — use a directional slide instead.</li>\n</ul>\n<hr>\n<h3>Common Patterns</h3>\n<h4>Enter/Exit</h4>\n<pre><code class=\"language-jsx\">{show &amp;&amp; (\n  &lt;ViewTransition enter=&quot;fade-in&quot; exit=&quot;fade-out&quot;&gt;&lt;Panel /&gt;&lt;/ViewTransition&gt;\n)}\n</code></pre>\n<h4>List Reorder</h4>\n<pre><code class=\"language-jsx\">{items.map(item =&gt; (\n  &lt;ViewTransition key={item.id}&gt;&lt;ItemCard item={item} /&gt;&lt;/ViewTransition&gt;\n))}\n</code></pre>\n<p>Trigger inside <code>startTransition</code>. Avoid wrapper <code>&lt;div&gt;</code>s between list and VT.</p>\n<h4>Composing Shared Elements with List Identity</h4>\n<p>Shared elements and list identity are independent concerns — don&#39;t confuse one for the other. When a list item contains a shared element (e.g., an image that morphs into a detail view), use two nested <code>&lt;ViewTransition&gt;</code> boundaries:</p>\n<pre><code class=\"language-jsx\">{items.map(item =&gt; (\n  &lt;ViewTransition key={item.id}&gt;                                      {/* list identity */}\n    &lt;Link href={`/items/${item.id}`}&gt;\n      &lt;ViewTransition name={`item-image-${item.id}`} share=&quot;morph&quot;&gt;   {/* shared element */}\n        &lt;Image src={item.image} /&gt;\n      &lt;/ViewTransition&gt;\n      &lt;p&gt;{item.name}&lt;/p&gt;\n    &lt;/Link&gt;\n  &lt;/ViewTransition&gt;\n))}\n</code></pre>\n<p>The outer VT handles list reorder/enter animations. The inner VT handles the cross-route shared element morph. Missing either layer means that animation silently doesn&#39;t happen.</p>\n<h4>Force Re-Enter with <code>key</code></h4>\n<pre><code class=\"language-jsx\">&lt;ViewTransition key={searchParams.toString()} enter=&quot;slide-up&quot; default=&quot;none&quot;&gt;\n  &lt;ResultsGrid /&gt;\n&lt;/ViewTransition&gt;\n</code></pre>\n<p><strong>Caution:</strong> If wrapping <code>&lt;Suspense&gt;</code>, changing <code>key</code> remounts the boundary and refetches.</p>\n<h4>Suspense Fallback to Content</h4>\n<p>Simple cross-fade:</p>\n<pre><code class=\"language-jsx\">&lt;ViewTransition&gt;\n  &lt;Suspense fallback={&lt;Skeleton /&gt;}&gt;&lt;Content /&gt;&lt;/Suspense&gt;\n&lt;/ViewTransition&gt;\n</code></pre>\n<p>Directional reveal:</p>\n<pre><code class=\"language-jsx\">&lt;Suspense fallback={&lt;ViewTransition exit=&quot;slide-down&quot;&gt;&lt;Skeleton /&gt;&lt;/ViewTransition&gt;}&gt;\n  &lt;ViewTransition enter=&quot;slide-up&quot; default=&quot;none&quot;&gt;&lt;Content /&gt;&lt;/ViewTransition&gt;\n&lt;/Suspense&gt;\n</code></pre>\n<p>For more patterns, see <code>references/patterns.md</code>.</p>\n<hr>\n<h3>How Multiple VTs Interact</h3>\n<p>Every VT matching the trigger fires simultaneously in a single <code>document.startViewTransition</code>. VTs in <strong>different</strong> transitions (navigation vs later Suspense resolve) don&#39;t compete.</p>\n<h4>Use <code>default=&quot;none&quot;</code> Liberally</h4>\n<p>Without it, every VT fires the browser cross-fade on <strong>every</strong> transition — Suspense resolves, <code>useDeferredValue</code> updates, background revalidations. Always use <code>default=&quot;none&quot;</code> and explicitly enable only desired triggers.</p>\n<h4>Two Patterns Coexist</h4>\n<p><strong>Pattern A — Directional slides:</strong> Type-keyed VT on each page, fires during navigation.\n<strong>Pattern B — Suspense reveals:</strong> Simple string props, fires when data loads (no type).</p>\n<p>They coexist because they fire at different moments. <code>default=&quot;none&quot;</code> on both prevents cross-interference. Always pair <code>enter</code> with <code>exit</code>. Place directional VTs in page components, not layouts.</p>\n<h4>Nested VT Limitation</h4>\n<p>When a parent VT exits, nested VTs inside it do <strong>not</strong> fire their own enter/exit — only the outermost VT animates. Per-item staggered animations during page navigation are not possible today. See <a href=\"https://github.com/facebook/react/pull/36135\">react#36135</a> for an experimental opt-in fix.</p>\n<hr>\n<h3>Next.js Integration</h3>\n<p>For Next.js setup (<code>experimental.viewTransition</code> flag, <code>transitionTypes</code> prop on <code>next/link</code>, App Router patterns, Server Components), see <code>references/nextjs.md</code>.</p>\n<hr>\n<h3>Accessibility</h3>\n<p>Always add the reduced motion CSS from <code>references/css-recipes.md</code> to your global stylesheet.</p>\n<hr>\n<h3>Reference Files</h3>\n<ul>\n<li><strong><code>references/implementation.md</code></strong> — Step-by-step implementation workflow.</li>\n<li><strong><code>references/patterns.md</code></strong> — Patterns, animation timing, events API, troubleshooting.</li>\n<li><strong><code>references/css-recipes.md</code></strong> — Ready-to-use CSS animation recipes.</li>\n<li><strong><code>references/nextjs.md</code></strong> — Next.js App Router patterns and Server Component details.</li>\n</ul>\n<h3>Full Compiled Document</h3>\n<p>For the complete guide with all reference files expanded: <code>AGENTS.md</code></p>\n",
  "save-the-cat-writing": "<h2>Save the Cat 写作自检</h2>\n<p>这是凯哥（Kevin）写 AI 辅助开发类公众号文章用的自检方法论。改编自 Blake Snyder 的 Save the Cat，去掉了讨好逻辑，保留结构技巧。</p>\n<h3>触发场景</h3>\n<p>两类场景触发，需要先判断：</p>\n<p><strong>写作前（选题/动笔阶段）</strong>：用户描述了一个想写的主题、分享了一个事件想写快评、或者在犹豫要不要写某个话题。关键词：想写、要不要写、选题、切入角度、有个想法。</p>\n<p>→ 走 §1 Logline 测试和 §2 标题测试，不要跳到后面的结构检查。</p>\n<p><strong>写作后（审稿/改稿阶段）</strong>：用户贴出一段草稿、一篇完整文章、或者说&quot;你看看这篇怎么样&quot;、&quot;哪里不够好&quot;、&quot;帮我看看开头&quot;。</p>\n<p>→ 走 §3-§7 完整清单。如果是快评（500-800 字），优先走 §7 而不是 §4 Beat Sheet。</p>\n<p>不确定是哪种场景时，优先问用户处在哪个阶段，不要两个都做。</p>\n<h3>默认交付物</h3>\n<p><strong>按清单逐项给出诊断意见，报告式输出</strong>。不要只说&quot;还不错&quot;或只给一两点建议。对每个适用的清单项，明确给出：</p>\n<ul>\n<li>这一项是否通过</li>\n<li>不通过的话，具体问题在哪（引用原文片段）</li>\n<li>怎么改（给出方向而不是代写）</li>\n</ul>\n<p>诊断要诚实，不要给万金油评语。如果某段确实写得好，说&quot;这段通过&quot;，不要硬挑毛病；如果某段平淡，直接指出来，不要用&quot;可以考虑进一步丰富&quot;这种废话。</p>\n<h3>§1 Logline 测试（动笔前）</h3>\n<p>一句话写出文章的&quot;讽刺性前提&quot;——读者看到这句应该产生认知冲突（&quot;我以为是 A，原来是 B&quot;）。</p>\n<p>检查点：</p>\n<ul>\n<li>这句话写不写得出来？写不出来说明切入角度不够锋利，劝退或让用户重想</li>\n<li>是否包含：谁会关心（受众）+ 反直觉的核心判断 + 具体的动作或场景</li>\n<li>非 AI 开发圈的人能不能听懂大意并且觉得有意思</li>\n</ul>\n<p><strong>通过示例</strong>：&quot;你以为在写 Spec，其实在绕路写代码。&quot;\n<strong>不通过示例</strong>：&quot;聊聊 Spec 驱动开发的几点思考。&quot;（没有反直觉判断，没有画面感）</p>\n<h3>§2 标题测试（动笔前或定稿前）</h3>\n<p>标题本身就是 pitch，不读正文光看标题就知道讲什么、为什么点。</p>\n<p>检查点：</p>\n<ul>\n<li>标题是否带态度或判断，不是中性主题描述</li>\n<li>是否有开发者能搜到的关键词（Spec、Agent、Code Review 等），兼顾搜一搜和推荐流</li>\n<li>如果是快评，光看标题能不能让人一眼判断&quot;我同不同意&quot;从而想点进来</li>\n</ul>\n<p><strong>通过示例</strong>：&quot;你以为在写 Spec，其实在绕路写代码&quot;\n<strong>不通过示例</strong>：&quot;聊聊 Spec 驱动开发的几点思考&quot;</p>\n<h3>§3 开场前两段：Save the Cat + 旧世界</h3>\n<p>检查点：</p>\n<ul>\n<li>前两段是否给了一个具体的、读者能代入的场景——不是泛泛背景介绍，而是有画面感的瞬间</li>\n<li>前三段内是否出现至少一个具体细节（报错信息、迭代次数、某个参数、某次失败），证明&quot;我真的自己干过这事&quot;</li>\n<li>开场是否展示了&quot;旧世界&quot;——读者正在经历的痛点或困境</li>\n</ul>\n<p><strong>通过示例</strong>：&quot;第 17 次让 Codex 改同一个函数的时候，我开始怀疑到底谁在给谁打工。&quot;\n<strong>不通过示例</strong>：&quot;最近 AI 编程工具越来越多了，今天来聊聊我的使用心得。&quot;</p>\n<h3>§4 Beat Sheet 结构检查（长文）</h3>\n<p>用五节点检查文章是否有推进感，而非平铺直叙：</p>\n<table>\n<thead>\n<tr>\n<th>节点</th>\n<th>对应内容</th>\n<th>自检问题</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>旧世界</td>\n<td>现有做法 / 主流认知 / 痛点</td>\n<td>是否足够具体，不是泛泛而谈</td>\n</tr>\n<tr>\n<td>触发事件</td>\n<td>我为什么要动手做 / 想明白这件事的契机</td>\n<td>是否有明确的时间点或事件</td>\n</tr>\n<tr>\n<td>尝试与挫败</td>\n<td>中间踩的坑、走过的弯路</td>\n<td>是否诚实，不是事后诸葛亮</td>\n</tr>\n<tr>\n<td>顿悟时刻</td>\n<td>真正管用的认知转变</td>\n<td>这个认知是不是只有亲手做过才能得出</td>\n</tr>\n<tr>\n<td>新世界</td>\n<td>现在我怎么做的 / 我的判断是什么</td>\n<td>是否给出明确的行动指引或立场</td>\n</tr>\n</tbody></table>\n<p>额外检查：</p>\n<ul>\n<li>中段是否有&quot;升高赌注&quot;的时刻——文章写到一半时，读者是否会觉得&quot;这事比我想的严重/有意思&quot;。只罗列要点说明缺少 midpoint 转折</li>\n<li>节点过渡是否自然，不是靠&quot;接下来我们聊聊……&quot;这种机械连接</li>\n</ul>\n<h3>§5 论点锋利度检查</h3>\n<p>检查点：</p>\n<ul>\n<li>是否有明确的、可以被反驳的判断。所有人都会同意的说法，说明观点不够锋利</li>\n<li>这个判断是一手经验还是转述别人观点</li>\n<li>是否避免了&quot;两边都有道理&quot;的万金油结尾——读者想听判断，不是平衡报道</li>\n</ul>\n<p>这一节是核心。如果文章在这一项上不通过，前面几项写得再好也救不回来，要直接告诉用户论点本身需要重构。</p>\n<h3>§6 结尾检查</h3>\n<p>检查点：</p>\n<ul>\n<li>是否回扣了开头的场景或问题，形成闭环</li>\n<li>是否有一句可以被单独摘出来转发的收束语（快评尤其重要）</li>\n<li>是在向前看（读者可以带走什么），而不是在总结全文（把前面说过的再说一遍）</li>\n</ul>\n<h3>§7 快评专项（500-800 字，替代 §4）</h3>\n<p>快评是&quot;一张电影海报&quot;：一眼看完，决定要不要转发。</p>\n<p>三要素必须同时满足：</p>\n<ul>\n<li>一个具体事件</li>\n<li>一个非显而易见的判断</li>\n<li>一句可传播的收束语</li>\n</ul>\n<p>检查点：</p>\n<ul>\n<li>事件描述是否克制，只给读者理解你判断所需的最少背景</li>\n<li>判断是否足够&quot;非共识&quot;——大多数人看到这个事件的第一反应和你一样，这篇快评就不值得写</li>\n<li>§3 开场、§5 锋利度、§6 结尾三项同样适用，但 §4 Beat Sheet 不适用</li>\n</ul>\n<h3>§8 发布前最后一遍</h3>\n<p>检查点：</p>\n<ul>\n<li>标记所有&quot;正确但无聊&quot;的段落——能删就删，能压缩就压缩</li>\n<li>是否有过度解释（读者是一线开发者，不需要解释什么是 CI/CD）</li>\n<li>和之前文章有主题重叠的部分，是否用&quot;一句带过 + 引导阅读&quot;代替了重复解释</li>\n<li>标题、首图、摘要三件套是否一致地传达了同一个信息</li>\n</ul>\n<h3>输出格式</h3>\n<p>报告式输出，建议结构：</p>\n<pre><code>## Logline / 标题（如适用）\n[通过 / 不通过 + 具体问题 + 改进方向]\n\n## 开场\n[引用原文开头 2-3 句] → [诊断] → [怎么改]\n\n## 结构（Beat Sheet 或快评三要素）\n[按节点逐项过]\n\n## 论点锋利度\n[关键节点，单独写一段]\n\n## 结尾\n[同样引用 + 诊断]\n\n## 发布前建议\n[具体哪些段落可以删/压缩]\n</code></pre>\n<p>不适用的节直接跳过，不要硬凑内容。比如用户只贴了开头，就只过 §3；只让看标题，就只过 §2。</p>\n<h3>几个写作时要坚守的原则</h3>\n<ul>\n<li>不要用&quot;可以考虑&quot;&quot;也许&quot;&quot;或许&quot;这类软化判断的词。要么通过要么不通过，含糊等于没说</li>\n<li>不要给两个以上并列建议让用户自己选——给一个你认为最该改的</li>\n<li>引用原文时用原话，不要转述后再点评，读者（凯哥）要自己对照</li>\n<li>如果整篇文章的问题在论点本身（§5 不通过），直接告诉用户&quot;建议重写而不是修改&quot;，不要在烂论点上堆改进意见</li>\n</ul>\n<hr>\n<p><strong>底层逻辑提醒</strong>：这套方法借鉴 Snyder 的结构技巧，不是他的讨好逻辑。文章值钱的地方在于敢下判断、基于一手经验、不怕得罪人。诊断时如果&quot;让文章更好看&quot;和&quot;说出真正的判断&quot;冲突了，支持后者。</p>\n",
  "shadcn": "<h2>shadcn/ui</h2>\n<p>A framework for building ui, components and design systems. Components are added as source code to the user&#39;s project via the CLI.</p>\n<blockquote>\n<p><strong>IMPORTANT:</strong> Run all CLI commands using the project&#39;s package runner: <code>npx shadcn@latest</code>, <code>pnpm dlx shadcn@latest</code>, or <code>bunx --bun shadcn@latest</code> — based on the project&#39;s <code>packageManager</code>. Examples below use <code>npx shadcn@latest</code> but substitute the correct runner for the project.</p>\n</blockquote>\n<h3>Current Project Context</h3>\n<pre><code class=\"language-json\">!`npx shadcn@latest info --json`\n</code></pre>\n<p>The JSON above contains the project config and installed components. Use <code>npx shadcn@latest docs &lt;component&gt;</code> to get documentation and example URLs for any component.</p>\n<h3>Principles</h3>\n<ol>\n<li><strong>Use existing components first.</strong> Use <code>npx shadcn@latest search</code> to check registries before writing custom UI. Check community registries too.</li>\n<li><strong>Compose, don&#39;t reinvent.</strong> Settings page = Tabs + Card + form controls. Dashboard = Sidebar + Card + Chart + Table.</li>\n<li><strong>Use built-in variants before custom styles.</strong> <code>variant=&quot;outline&quot;</code>, <code>size=&quot;sm&quot;</code>, etc.</li>\n<li><strong>Use semantic colors.</strong> <code>bg-primary</code>, <code>text-muted-foreground</code> — never raw values like <code>bg-blue-500</code>.</li>\n</ol>\n<h3>Critical Rules</h3>\n<p>These rules are <strong>always enforced</strong>. Each links to a file with Incorrect/Correct code pairs.</p>\n<h4>Styling &amp; Tailwind → <a href=\"./rules/styling.md\">styling.md</a></h4>\n<ul>\n<li><strong><code>className</code> for layout, not styling.</strong> Never override component colors or typography.</li>\n<li><strong>No <code>space-x-*</code> or <code>space-y-*</code>.</strong> Use <code>flex</code> with <code>gap-*</code>. For vertical stacks, <code>flex flex-col gap-*</code>.</li>\n<li><strong>Use <code>size-*</code> when width and height are equal.</strong> <code>size-10</code> not <code>w-10 h-10</code>.</li>\n<li><strong>Use <code>truncate</code> shorthand.</strong> Not <code>overflow-hidden text-ellipsis whitespace-nowrap</code>.</li>\n<li><strong>No manual <code>dark:</code> color overrides.</strong> Use semantic tokens (<code>bg-background</code>, <code>text-muted-foreground</code>).</li>\n<li><strong>Use <code>cn()</code> for conditional classes.</strong> Don&#39;t write manual template literal ternaries.</li>\n<li><strong>No manual <code>z-index</code> on overlay components.</strong> Dialog, Sheet, Popover, etc. handle their own stacking.</li>\n</ul>\n<h4>Forms &amp; Inputs → <a href=\"./rules/forms.md\">forms.md</a></h4>\n<ul>\n<li><strong>Forms use <code>FieldGroup</code> + <code>Field</code>.</strong> Never use raw <code>div</code> with <code>space-y-*</code> or <code>grid gap-*</code> for form layout.</li>\n<li><strong><code>InputGroup</code> uses <code>InputGroupInput</code>/<code>InputGroupTextarea</code>.</strong> Never raw <code>Input</code>/<code>Textarea</code> inside <code>InputGroup</code>.</li>\n<li><strong>Buttons inside inputs use <code>InputGroup</code> + <code>InputGroupAddon</code>.</strong></li>\n<li><strong>Option sets (2–7 choices) use <code>ToggleGroup</code>.</strong> Don&#39;t loop <code>Button</code> with manual active state.</li>\n<li><strong><code>FieldSet</code> + <code>FieldLegend</code> for grouping related checkboxes/radios.</strong> Don&#39;t use a <code>div</code> with a heading.</li>\n<li><strong>Field validation uses <code>data-invalid</code> + <code>aria-invalid</code>.</strong> <code>data-invalid</code> on <code>Field</code>, <code>aria-invalid</code> on the control. For disabled: <code>data-disabled</code> on <code>Field</code>, <code>disabled</code> on the control.</li>\n</ul>\n<h4>Component Structure → <a href=\"./rules/composition.md\">composition.md</a></h4>\n<ul>\n<li><strong>Items always inside their Group.</strong> <code>SelectItem</code> → <code>SelectGroup</code>. <code>DropdownMenuItem</code> → <code>DropdownMenuGroup</code>. <code>CommandItem</code> → <code>CommandGroup</code>.</li>\n<li><strong>Use <code>asChild</code> (radix) or <code>render</code> (base) for custom triggers.</strong> Check <code>base</code> field from <code>npx shadcn@latest info</code>. → <a href=\"./rules/base-vs-radix.md\">base-vs-radix.md</a></li>\n<li><strong>Dialog, Sheet, and Drawer always need a Title.</strong> <code>DialogTitle</code>, <code>SheetTitle</code>, <code>DrawerTitle</code> required for accessibility. Use <code>className=&quot;sr-only&quot;</code> if visually hidden.</li>\n<li><strong>Use full Card composition.</strong> <code>CardHeader</code>/<code>CardTitle</code>/<code>CardDescription</code>/<code>CardContent</code>/<code>CardFooter</code>. Don&#39;t dump everything in <code>CardContent</code>.</li>\n<li><strong>Button has no <code>isPending</code>/<code>isLoading</code>.</strong> Compose with <code>Spinner</code> + <code>data-icon</code> + <code>disabled</code>.</li>\n<li><strong><code>TabsTrigger</code> must be inside <code>TabsList</code>.</strong> Never render triggers directly in <code>Tabs</code>.</li>\n<li><strong><code>Avatar</code> always needs <code>AvatarFallback</code>.</strong> For when the image fails to load.</li>\n</ul>\n<h4>Use Components, Not Custom Markup → <a href=\"./rules/composition.md\">composition.md</a></h4>\n<ul>\n<li><strong>Use existing components before custom markup.</strong> Check if a component exists before writing a styled <code>div</code>.</li>\n<li><strong>Callouts use <code>Alert</code>.</strong> Don&#39;t build custom styled divs.</li>\n<li><strong>Empty states use <code>Empty</code>.</strong> Don&#39;t build custom empty state markup.</li>\n<li><strong>Toast via <code>sonner</code>.</strong> Use <code>toast()</code> from <code>sonner</code>.</li>\n<li><strong>Use <code>Separator</code></strong> instead of <code>&lt;hr&gt;</code> or <code>&lt;div className=&quot;border-t&quot;&gt;</code>.</li>\n<li><strong>Use <code>Skeleton</code></strong> for loading placeholders. No custom <code>animate-pulse</code> divs.</li>\n<li><strong>Use <code>Badge</code></strong> instead of custom styled spans.</li>\n</ul>\n<h4>Icons → <a href=\"./rules/icons.md\">icons.md</a></h4>\n<ul>\n<li><strong>Icons in <code>Button</code> use <code>data-icon</code>.</strong> <code>data-icon=&quot;inline-start&quot;</code> or <code>data-icon=&quot;inline-end&quot;</code> on the icon.</li>\n<li><strong>No sizing classes on icons inside components.</strong> Components handle icon sizing via CSS. No <code>size-4</code> or <code>w-4 h-4</code>.</li>\n<li><strong>Pass icons as objects, not string keys.</strong> <code>icon={CheckIcon}</code>, not a string lookup.</li>\n</ul>\n<h4>CLI</h4>\n<ul>\n<li><strong>Never decode preset codes or build preset URLs manually.</strong> Use <code>npx shadcn@latest preset decode &lt;code&gt;</code>, <code>preset url &lt;code&gt;</code>, or <code>preset open &lt;code&gt;</code>. For project-aware preset detection, use <code>npx shadcn@latest preset resolve</code>.</li>\n<li><strong>Apply preset codes directly with the CLI.</strong> Use <code>npx shadcn@latest apply &lt;code&gt;</code> for existing projects, or <code>npx shadcn@latest init --preset &lt;code&gt;</code> when initializing.</li>\n</ul>\n<h3>Key Patterns</h3>\n<p>These are the most common patterns that differentiate correct shadcn/ui code. For edge cases, see the linked rule files above.</p>\n<pre><code class=\"language-tsx\">// Form layout: FieldGroup + Field, not div + Label.\n&lt;FieldGroup&gt;\n  &lt;Field&gt;\n    &lt;FieldLabel htmlFor=&quot;email&quot;&gt;Email&lt;/FieldLabel&gt;\n    &lt;Input id=&quot;email&quot; /&gt;\n  &lt;/Field&gt;\n&lt;/FieldGroup&gt;\n\n// Validation: data-invalid on Field, aria-invalid on the control.\n&lt;Field data-invalid&gt;\n  &lt;FieldLabel&gt;Email&lt;/FieldLabel&gt;\n  &lt;Input aria-invalid /&gt;\n  &lt;FieldDescription&gt;Invalid email.&lt;/FieldDescription&gt;\n&lt;/Field&gt;\n\n// Icons in buttons: data-icon, no sizing classes.\n&lt;Button&gt;\n  &lt;SearchIcon data-icon=&quot;inline-start&quot; /&gt;\n  Search\n&lt;/Button&gt;\n\n// Spacing: gap-*, not space-y-*.\n&lt;div className=&quot;flex flex-col gap-4&quot;&gt;  // correct\n&lt;div className=&quot;space-y-4&quot;&gt;           // wrong\n\n// Equal dimensions: size-*, not w-* h-*.\n&lt;Avatar className=&quot;size-10&quot;&gt;   // correct\n&lt;Avatar className=&quot;w-10 h-10&quot;&gt; // wrong\n\n// Status colors: Badge variants or semantic tokens, not raw colors.\n&lt;Badge variant=&quot;secondary&quot;&gt;+20.1%&lt;/Badge&gt;    // correct\n&lt;span className=&quot;text-emerald-600&quot;&gt;+20.1%&lt;/span&gt; // wrong\n</code></pre>\n<h3>Component Selection</h3>\n<table>\n<thead>\n<tr>\n<th>Need</th>\n<th>Use</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Button/action</td>\n<td><code>Button</code> with appropriate variant</td>\n</tr>\n<tr>\n<td>Form inputs</td>\n<td><code>Input</code>, <code>Select</code>, <code>Combobox</code>, <code>Switch</code>, <code>Checkbox</code>, <code>RadioGroup</code>, <code>Textarea</code>, <code>InputOTP</code>, <code>Slider</code></td>\n</tr>\n<tr>\n<td>Toggle between 2–5 options</td>\n<td><code>ToggleGroup</code> + <code>ToggleGroupItem</code></td>\n</tr>\n<tr>\n<td>Data display</td>\n<td><code>Table</code>, <code>Card</code>, <code>Badge</code>, <code>Avatar</code></td>\n</tr>\n<tr>\n<td>Navigation</td>\n<td><code>Sidebar</code>, <code>NavigationMenu</code>, <code>Breadcrumb</code>, <code>Tabs</code>, <code>Pagination</code></td>\n</tr>\n<tr>\n<td>Overlays</td>\n<td><code>Dialog</code> (modal), <code>Sheet</code> (side panel), <code>Drawer</code> (bottom sheet), <code>AlertDialog</code> (confirmation)</td>\n</tr>\n<tr>\n<td>Feedback</td>\n<td><code>sonner</code> (toast), <code>Alert</code>, <code>Progress</code>, <code>Skeleton</code>, <code>Spinner</code></td>\n</tr>\n<tr>\n<td>Command palette</td>\n<td><code>Command</code> inside <code>Dialog</code></td>\n</tr>\n<tr>\n<td>Charts</td>\n<td><code>Chart</code> (wraps Recharts)</td>\n</tr>\n<tr>\n<td>Layout</td>\n<td><code>Card</code>, <code>Separator</code>, <code>Resizable</code>, <code>ScrollArea</code>, <code>Accordion</code>, <code>Collapsible</code></td>\n</tr>\n<tr>\n<td>Empty states</td>\n<td><code>Empty</code></td>\n</tr>\n<tr>\n<td>Menus</td>\n<td><code>DropdownMenu</code>, <code>ContextMenu</code>, <code>Menubar</code></td>\n</tr>\n<tr>\n<td>Tooltips/info</td>\n<td><code>Tooltip</code>, <code>HoverCard</code>, <code>Popover</code></td>\n</tr>\n</tbody></table>\n<h3>Key Fields</h3>\n<p>The injected project context contains these key fields:</p>\n<ul>\n<li><strong><code>aliases</code></strong> → use the actual alias prefix for imports (e.g. <code>@/</code>, <code>~/</code>), never hardcode.</li>\n<li><strong><code>isRSC</code></strong> → when <code>true</code>, components using <code>useState</code>, <code>useEffect</code>, event handlers, or browser APIs need <code>&quot;use client&quot;</code> at the top of the file. Always reference this field when advising on the directive.</li>\n<li><strong><code>tailwindVersion</code></strong> → <code>&quot;v4&quot;</code> uses <code>@theme inline</code> blocks; <code>&quot;v3&quot;</code> uses <code>tailwind.config.js</code>.</li>\n<li><strong><code>tailwindCssFile</code></strong> → the global CSS file where custom CSS variables are defined. Always edit this file, never create a new one.</li>\n<li><strong><code>style</code></strong> → component visual treatment (e.g. <code>nova</code>, <code>vega</code>).</li>\n<li><strong><code>base</code></strong> → primitive library (<code>radix</code> or <code>base</code>). Affects component APIs and available props.</li>\n<li><strong><code>iconLibrary</code></strong> → determines icon imports. Use <code>lucide-react</code> for <code>lucide</code>, <code>@tabler/icons-react</code> for <code>tabler</code>, etc. Never assume <code>lucide-react</code>.</li>\n<li><strong><code>resolvedPaths</code></strong> → exact file-system destinations for components, utils, hooks, etc.</li>\n<li><strong><code>framework</code></strong> → routing and file conventions (e.g. Next.js App Router vs Vite SPA).</li>\n<li><strong><code>packageManager</code></strong> → use this for any non-shadcn dependency installs (e.g. <code>pnpm add date-fns</code> vs <code>npm install date-fns</code>).</li>\n<li><strong><code>preset</code></strong> → resolved preset code and values for the current project. Use <code>npx shadcn@latest preset resolve --json</code> when you only need preset information.</li>\n</ul>\n<p>See <a href=\"./cli.md\">cli.md — <code>info</code> command</a> for the full field reference.</p>\n<h3>Component Docs, Examples, and Usage</h3>\n<p>Run <code>npx shadcn@latest docs &lt;component&gt;</code> to get the URLs for a component&#39;s documentation, examples, and API reference. Fetch these URLs to get the actual content.</p>\n<pre><code class=\"language-bash\">npx shadcn@latest docs button dialog select\n</code></pre>\n<p><strong>When creating, fixing, debugging, or using a component, always run <code>npx shadcn@latest docs</code> and fetch the URLs first.</strong> This ensures you&#39;re working with the correct API and usage patterns rather than guessing.</p>\n<h3>Workflow</h3>\n<ol>\n<li><strong>Get project context</strong> — already injected above. Run <code>npx shadcn@latest info</code> again if you need to refresh.</li>\n<li><strong>Check installed components first</strong> — before running <code>add</code>, always check the <code>components</code> list from project context or list the <code>resolvedPaths.ui</code> directory. Don&#39;t import components that haven&#39;t been added, and don&#39;t re-add ones already installed.</li>\n<li><strong>Find components</strong> — <code>npx shadcn@latest search</code>.</li>\n<li><strong>Get docs and examples</strong> — run <code>npx shadcn@latest docs &lt;component&gt;</code> to get URLs, then fetch them. Use <code>npx shadcn@latest view</code> to browse registry items you haven&#39;t installed. To preview changes to installed components, use <code>npx shadcn@latest add --diff</code>.</li>\n<li><strong>Install or update</strong> — <code>npx shadcn@latest add</code>. When updating existing components, use <code>--dry-run</code> and <code>--diff</code> to preview changes first (see <a href=\"#updating-components\">Updating Components</a> below).</li>\n<li><strong>Fix imports in third-party components</strong> — After adding components from community registries (e.g. <code>@bundui</code>, <code>@magicui</code>), check the added non-UI files for hardcoded import paths like <code>@/components/ui/...</code>. These won&#39;t match the project&#39;s actual aliases. Use <code>npx shadcn@latest info</code> to get the correct <code>ui</code> alias (e.g. <code>@workspace/ui/components</code>) and rewrite the imports accordingly. The CLI rewrites imports for its own UI files, but third-party registry components may use default paths that don&#39;t match the project.</li>\n<li><strong>Review added components</strong> — After adding a component or block from any registry, <strong>always read the added files and verify they are correct</strong>. Check for missing sub-components (e.g. <code>SelectItem</code> without <code>SelectGroup</code>), missing imports, incorrect composition, or violations of the <a href=\"#critical-rules\">Critical Rules</a>. Also replace any icon imports with the project&#39;s <code>iconLibrary</code> from the project context (e.g. if the registry item uses <code>lucide-react</code> but the project uses <code>hugeicons</code>, swap the imports and icon names accordingly). Fix all issues before moving on.</li>\n<li><strong>Registry must be explicit</strong> — When the user asks to add a block or component, <strong>do not guess the registry</strong>. If no registry is specified (e.g. user says &quot;add a login block&quot; without specifying <code>@shadcn</code>, <code>@tailark</code>, <code>owner/repo</code>, etc.), ask which registry to use. Never default to a registry on behalf of the user.</li>\n<li><strong>Switching presets</strong> — Ask the user first: <strong>overwrite</strong>, <strong>partial</strong>, <strong>merge</strong>, or <strong>skip</strong>?<ul>\n<li><strong>Inspect current preset</strong>: <code>npx shadcn@latest preset resolve</code>. Use <code>--json</code> when you need structured values.</li>\n<li><strong>Inspect incoming preset</strong>: <code>npx shadcn@latest preset decode &lt;code&gt;</code>. Use <code>preset url &lt;code&gt;</code> or <code>preset open &lt;code&gt;</code> to share or open the preset builder.</li>\n<li><strong>Overwrite</strong>: <code>npx shadcn@latest apply &lt;code&gt;</code>. Overwrites detected components, fonts, and CSS variables.</li>\n<li><strong>Partial</strong>: <code>npx shadcn@latest apply &lt;code&gt; --only theme,font</code>. Updates only the selected preset parts without reinstalling UI components. Supported values are <code>theme</code> and <code>font</code>; comma-separated combinations are allowed. <code>icon</code> is intentionally not supported, because icon changes may require full component reinstall and transforms.</li>\n<li><strong>Merge</strong>: <code>npx shadcn@latest init --preset &lt;code&gt; --force --no-reinstall</code>, then run <code>npx shadcn@latest info</code> to list installed components, then for each installed component use <code>--dry-run</code> and <code>--diff</code> to <a href=\"#updating-components\">smart merge</a> it individually.</li>\n<li><strong>Skip</strong>: <code>npx shadcn@latest init --preset &lt;code&gt; --force --no-reinstall</code>. Only updates config and CSS, leaves components as-is.</li>\n<li><strong>Important</strong>: Always run preset commands inside the user&#39;s project directory. <code>apply</code> only works in an existing project with a <code>components.json</code> file. The CLI automatically preserves the current base (<code>base</code> vs <code>radix</code>) from <code>components.json</code>. If you must use a scratch/temp directory (e.g. for <code>--dry-run</code> comparisons), pass <code>--base &lt;current-base&gt;</code> explicitly — preset codes do not encode the base.</li>\n</ul>\n</li>\n</ol>\n<h3>Updating Components</h3>\n<p>When the user asks to update a component from upstream while keeping their local changes, use <code>--dry-run</code> and <code>--diff</code> to intelligently merge. <strong>NEVER fetch raw files from GitHub manually — always use the CLI.</strong></p>\n<ol>\n<li>Run <code>npx shadcn@latest add &lt;component&gt; --dry-run</code> to see all files that would be affected.</li>\n<li>For each file, run <code>npx shadcn@latest add &lt;component&gt; --diff &lt;file&gt;</code> to see what changed upstream vs local.</li>\n<li>Decide per file based on the diff:<ul>\n<li>No local changes → safe to overwrite.</li>\n<li>Has local changes → read the local file, analyze the diff, and apply upstream updates while preserving local modifications.</li>\n<li>User says &quot;just update everything&quot; → use <code>--overwrite</code>, but confirm first.</li>\n</ul>\n</li>\n<li><strong>Never use <code>--overwrite</code> without the user&#39;s explicit approval.</strong></li>\n</ol>\n<h3>Quick Reference</h3>\n<pre><code class=\"language-bash\"># Create a new project.\nnpx shadcn@latest init --name my-app --preset base-nova\nnpx shadcn@latest init --name my-app --preset a2r6bw --template vite\n\n# Create a monorepo project.\nnpx shadcn@latest init --name my-app --preset base-nova --monorepo\nnpx shadcn@latest init --name my-app --preset base-nova --template next --monorepo\n\n# Initialize existing project.\nnpx shadcn@latest init --preset base-nova\nnpx shadcn@latest init --defaults  # shortcut: --template=next --preset=nova (base style implied)\n\n# Apply a preset to an existing project.\nnpx shadcn@latest apply a2r6bw\nnpx shadcn@latest apply a2r6bw --only theme\nnpx shadcn@latest apply a2r6bw --only font\nnpx shadcn@latest apply a2r6bw --only theme,font\n\n# Inspect preset codes and project preset state.\nnpx shadcn@latest preset decode a2r6bw\nnpx shadcn@latest preset url a2r6bw\nnpx shadcn@latest preset open a2r6bw\nnpx shadcn@latest preset resolve\nnpx shadcn@latest preset resolve --json\n\n# Add components.\nnpx shadcn@latest add button card dialog\nnpx shadcn@latest add @magicui/shimmer-button\nnpx shadcn@latest add owner/repo/item\nnpx shadcn@latest add --all\n\n# Preview changes before adding/updating.\nnpx shadcn@latest add button --dry-run\nnpx shadcn@latest add button --diff button.tsx\nnpx shadcn@latest add @acme/form --view button.tsx\nnpx shadcn@latest add owner/repo/item --dry-run\n\n# Search registries.\nnpx shadcn@latest search @shadcn -q &quot;sidebar&quot;\nnpx shadcn@latest search @tailark -q &quot;stats&quot;\nnpx shadcn@latest search owner/repo -q &quot;login&quot;\nnpx shadcn@latest search                          # all configured registries\nnpx shadcn@latest search @shadcn -q &quot;menu&quot; -t ui  # filter by item type\n\n# Get component docs and example URLs.\nnpx shadcn@latest docs button dialog select\n\n# View registry item details (for items not yet installed).\nnpx shadcn@latest view @shadcn/button\nnpx shadcn@latest view owner/repo/item\n</code></pre>\n<p><strong>Named presets:</strong> <code>nova</code>, <code>vega</code>, <code>maia</code>, <code>lyra</code>, <code>mira</code>, <code>luma</code>\n<strong>Templates:</strong> <code>next</code>, <code>vite</code>, <code>start</code>, <code>react-router</code>, <code>astro</code> (all support <code>--monorepo</code>) and <code>laravel</code> (not supported for monorepo)\n<strong>Preset codes:</strong> Version-prefixed base62 strings (e.g. <code>a2r6bw</code> or <code>b0</code>), from <a href=\"https://ui.shadcn.com\">ui.shadcn.com</a>.</p>\n<h3>Detailed References</h3>\n<ul>\n<li><a href=\"./rules/forms.md\">rules/forms.md</a> — FieldGroup, Field, InputGroup, ToggleGroup, FieldSet, validation states</li>\n<li><a href=\"./rules/composition.md\">rules/composition.md</a> — Groups, overlays, Card, Tabs, Avatar, Alert, Empty, Toast, Separator, Skeleton, Badge, Button loading</li>\n<li><a href=\"./rules/icons.md\">rules/icons.md</a> — data-icon, icon sizing, passing icons as objects</li>\n<li><a href=\"./rules/styling.md\">rules/styling.md</a> — Semantic colors, variants, className, spacing, size, truncate, dark mode, cn(), z-index</li>\n<li><a href=\"./rules/base-vs-radix.md\">rules/base-vs-radix.md</a> — asChild vs render, Select, ToggleGroup, Slider, Accordion</li>\n<li><a href=\"./cli.md\">cli.md</a> — Commands, flags, presets, templates</li>\n<li><a href=\"./registry.md\">registry.md</a> — Authoring source registries, <code>include</code>, item definitions, dependencies, GitHub registry rules</li>\n<li><a href=\"./customization.md\">customization.md</a> — Theming, CSS variables, extending components</li>\n</ul>\n",
  "slidev": "<h2>Slidev - Presentation Slides for Developers</h2>\n<p>Web-based slides maker built on Vite, Vue, and Markdown.</p>\n<h3>When to Use</h3>\n<ul>\n<li>Technical presentations or slidedecks with live code examples</li>\n<li>Syntax-highlighted code snippets with animations</li>\n<li>Interactive demos (Monaco editor, runnable code)</li>\n<li>Mathematical equations (LaTeX) or diagrams (Mermaid, PlantUML)</li>\n<li>Record presentations with presenter notes</li>\n<li>Export to PDF, PPTX, or host as SPA</li>\n<li>Code walkthroughs for developer talks or workshops</li>\n</ul>\n<h3>Quick Start</h3>\n<pre><code class=\"language-bash\">pnpm create slidev    # Create project\npnpm run dev          # Start dev server (opens http://localhost:3030)\npnpm run build        # Build static SPA\npnpm run export       # Export to PDF (requires playwright-chromium)\n</code></pre>\n<p><strong>Verify</strong>: After <code>pnpm run dev</code>, confirm slides load at <code>http://localhost:3030</code>. After <code>pnpm run export</code>, check the output PDF exists in the project root.</p>\n<h3>Basic Syntax</h3>\n<pre><code class=\"language-md\">---\ntheme: default\ntitle: My Presentation\n---\n\n# First Slide\n\nContent here\n\n---\n\n# Second Slide\n\nMore content\n\n&lt;!--\nPresenter notes go here\n--&gt;\n</code></pre>\n<ul>\n<li><code>---</code> separates slides</li>\n<li>First frontmatter = headmatter (deck config)</li>\n<li>HTML comments = presenter notes</li>\n</ul>\n<h3>Core References</h3>\n<table>\n<thead>\n<tr>\n<th>Topic</th>\n<th>Description</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Markdown Syntax</td>\n<td>Slide separators, frontmatter, notes, code blocks</td>\n<td><a href=\"references/core-syntax.md\">core-syntax</a></td>\n</tr>\n<tr>\n<td>Animations</td>\n<td>v-click, v-clicks, motion, transitions</td>\n<td><a href=\"references/core-animations.md\">core-animations</a></td>\n</tr>\n<tr>\n<td>Headmatter</td>\n<td>Deck-wide configuration options</td>\n<td><a href=\"references/core-headmatter.md\">core-headmatter</a></td>\n</tr>\n<tr>\n<td>Frontmatter</td>\n<td>Per-slide configuration options</td>\n<td><a href=\"references/core-frontmatter.md\">core-frontmatter</a></td>\n</tr>\n<tr>\n<td>CLI Commands</td>\n<td>Dev, build, export, theme commands</td>\n<td><a href=\"references/core-cli.md\">core-cli</a></td>\n</tr>\n<tr>\n<td>Components</td>\n<td>Built-in Vue components</td>\n<td><a href=\"references/core-components.md\">core-components</a></td>\n</tr>\n<tr>\n<td>Layouts</td>\n<td>Built-in slide layouts</td>\n<td><a href=\"references/core-layouts.md\">core-layouts</a></td>\n</tr>\n<tr>\n<td>Exporting</td>\n<td>PDF, PPTX, PNG export options</td>\n<td><a href=\"references/core-exporting.md\">core-exporting</a></td>\n</tr>\n<tr>\n<td>Hosting</td>\n<td>Build and deploy to various platforms</td>\n<td><a href=\"references/core-hosting.md\">core-hosting</a></td>\n</tr>\n<tr>\n<td>Global Context</td>\n<td>$nav, $slidev, composables API</td>\n<td><a href=\"references/core-global-context.md\">core-global-context</a></td>\n</tr>\n</tbody></table>\n<h3>Feature Reference</h3>\n<h4>Code &amp; Editor</h4>\n<table>\n<thead>\n<tr>\n<th>Feature</th>\n<th>Usage</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Line highlighting</td>\n<td><code>```ts {2,3}</code></td>\n<td><a href=\"references/code-line-highlighting.md\">code-line-highlighting</a></td>\n</tr>\n<tr>\n<td>Click-based highlighting</td>\n<td><code>```ts {1|2-3|all}</code></td>\n<td><a href=\"references/code-line-highlighting.md\">code-line-highlighting</a></td>\n</tr>\n<tr>\n<td>Line numbers</td>\n<td><code>lineNumbers: true</code> or <code>{lines:true}</code></td>\n<td><a href=\"references/code-line-numbers.md\">code-line-numbers</a></td>\n</tr>\n<tr>\n<td>Scrollable code</td>\n<td><code>{maxHeight:&#39;100px&#39;}</code></td>\n<td><a href=\"references/code-max-height.md\">code-max-height</a></td>\n</tr>\n<tr>\n<td>Code tabs</td>\n<td><code>::code-group</code> (requires <code>comark: true</code>)</td>\n<td><a href=\"references/code-groups.md\">code-groups</a></td>\n</tr>\n<tr>\n<td>Monaco editor</td>\n<td><code>```ts {monaco}</code></td>\n<td><a href=\"references/editor-monaco.md\">editor-monaco</a></td>\n</tr>\n<tr>\n<td>Run code</td>\n<td><code>```ts {monaco-run}</code></td>\n<td><a href=\"references/editor-monaco-run.md\">editor-monaco-run</a></td>\n</tr>\n<tr>\n<td>Edit files</td>\n<td><code>&lt;&lt;&lt; ./file.ts {monaco-write}</code></td>\n<td><a href=\"references/editor-monaco-write.md\">editor-monaco-write</a></td>\n</tr>\n<tr>\n<td>Code animations</td>\n<td><code>````md magic-move</code></td>\n<td><a href=\"references/code-magic-move.md\">code-magic-move</a></td>\n</tr>\n<tr>\n<td>TypeScript types</td>\n<td><code>```ts twoslash</code></td>\n<td><a href=\"references/code-twoslash.md\">code-twoslash</a></td>\n</tr>\n<tr>\n<td>Import code</td>\n<td><code>&lt;&lt;&lt; @/snippets/file.js</code></td>\n<td><a href=\"references/code-import-snippet.md\">code-import-snippet</a></td>\n</tr>\n</tbody></table>\n<h4>Diagrams &amp; Math</h4>\n<table>\n<thead>\n<tr>\n<th>Feature</th>\n<th>Usage</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Mermaid diagrams</td>\n<td><code>```mermaid</code></td>\n<td><a href=\"references/diagram-mermaid.md\">diagram-mermaid</a></td>\n</tr>\n<tr>\n<td>PlantUML diagrams</td>\n<td><code>```plantuml</code></td>\n<td><a href=\"references/diagram-plantuml.md\">diagram-plantuml</a></td>\n</tr>\n<tr>\n<td>LaTeX math</td>\n<td><code>$inline$</code> or <code>$$block$$</code></td>\n<td><a href=\"references/diagram-latex.md\">diagram-latex</a></td>\n</tr>\n</tbody></table>\n<h4>Layout &amp; Styling</h4>\n<table>\n<thead>\n<tr>\n<th>Feature</th>\n<th>Usage</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Canvas size</td>\n<td><code>canvasWidth</code>, <code>aspectRatio</code></td>\n<td><a href=\"references/layout-canvas-size.md\">layout-canvas-size</a></td>\n</tr>\n<tr>\n<td>Zoom slide</td>\n<td><code>zoom: 0.8</code></td>\n<td><a href=\"references/layout-zoom.md\">layout-zoom</a></td>\n</tr>\n<tr>\n<td>Scale elements</td>\n<td><code>&lt;Transform :scale=&quot;0.5&quot;&gt;</code></td>\n<td><a href=\"references/layout-transform.md\">layout-transform</a></td>\n</tr>\n<tr>\n<td>Layout slots</td>\n<td><code>::right::</code>, <code>::default::</code></td>\n<td><a href=\"references/layout-slots.md\">layout-slots</a></td>\n</tr>\n<tr>\n<td>Scoped CSS</td>\n<td><code>&lt;style&gt;</code> in slide</td>\n<td><a href=\"references/style-scoped.md\">style-scoped</a></td>\n</tr>\n<tr>\n<td>Global layers</td>\n<td><code>global-top.vue</code>, <code>global-bottom.vue</code></td>\n<td><a href=\"references/layout-global-layers.md\">layout-global-layers</a></td>\n</tr>\n<tr>\n<td>Draggable elements</td>\n<td><code>v-drag</code>, <code>&lt;v-drag&gt;</code></td>\n<td><a href=\"references/layout-draggable.md\">layout-draggable</a></td>\n</tr>\n<tr>\n<td>Icons</td>\n<td><code>&lt;mdi-icon-name /&gt;</code></td>\n<td><a href=\"references/style-icons.md\">style-icons</a></td>\n</tr>\n</tbody></table>\n<h4>Animation &amp; Interaction</h4>\n<table>\n<thead>\n<tr>\n<th>Feature</th>\n<th>Usage</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Click animations</td>\n<td><code>v-click</code>, <code>&lt;v-clicks&gt;</code></td>\n<td><a href=\"references/core-animations.md\">core-animations</a></td>\n</tr>\n<tr>\n<td>Rough markers</td>\n<td><code>v-mark.underline</code>, <code>v-mark.circle</code></td>\n<td><a href=\"references/animation-rough-marker.md\">animation-rough-marker</a></td>\n</tr>\n<tr>\n<td>Drawing mode</td>\n<td>Press <code>C</code> or config <code>drawings:</code></td>\n<td><a href=\"references/animation-drawing.md\">animation-drawing</a></td>\n</tr>\n<tr>\n<td>Direction styles</td>\n<td><code>forward:delay-300</code></td>\n<td><a href=\"references/style-direction.md\">style-direction</a></td>\n</tr>\n<tr>\n<td>Note highlighting</td>\n<td><code>[click]</code> in notes</td>\n<td><a href=\"references/animation-click-marker.md\">animation-click-marker</a></td>\n</tr>\n</tbody></table>\n<h4>Syntax Extensions</h4>\n<table>\n<thead>\n<tr>\n<th>Feature</th>\n<th>Usage</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Comark syntax</td>\n<td><code>comark: true</code> + <code>{style=&quot;color:red&quot;}</code></td>\n<td><a href=\"references/syntax-comark.md\">syntax-comark</a></td>\n</tr>\n<tr>\n<td>Block frontmatter</td>\n<td><code>```yaml</code> instead of <code>---</code></td>\n<td><a href=\"references/syntax-block-frontmatter.md\">syntax-block-frontmatter</a></td>\n</tr>\n<tr>\n<td>Import slides</td>\n<td><code>src: ./other.md</code></td>\n<td><a href=\"references/syntax-importing-slides.md\">syntax-importing-slides</a></td>\n</tr>\n<tr>\n<td>Merge frontmatter</td>\n<td>Main entry wins</td>\n<td><a href=\"references/syntax-frontmatter-merging.md\">syntax-frontmatter-merging</a></td>\n</tr>\n</tbody></table>\n<h4>Presenter &amp; Recording</h4>\n<table>\n<thead>\n<tr>\n<th>Feature</th>\n<th>Usage</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Recording</td>\n<td>Press <code>G</code> for camera</td>\n<td><a href=\"references/presenter-recording.md\">presenter-recording</a></td>\n</tr>\n<tr>\n<td>Timer</td>\n<td><code>duration: 30min</code>, <code>timer: countdown</code></td>\n<td><a href=\"references/presenter-timer.md\">presenter-timer</a></td>\n</tr>\n<tr>\n<td>Remote control</td>\n<td><code>slidev --remote</code></td>\n<td><a href=\"references/presenter-remote.md\">presenter-remote</a></td>\n</tr>\n<tr>\n<td>Ruby text</td>\n<td><code>notesAutoRuby:</code></td>\n<td><a href=\"references/presenter-notes-ruby.md\">presenter-notes-ruby</a></td>\n</tr>\n</tbody></table>\n<h4>Export &amp; Build</h4>\n<table>\n<thead>\n<tr>\n<th>Feature</th>\n<th>Usage</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Export options</td>\n<td><code>slidev export</code></td>\n<td><a href=\"references/core-exporting.md\">core-exporting</a></td>\n</tr>\n<tr>\n<td>Build &amp; deploy</td>\n<td><code>slidev build</code></td>\n<td><a href=\"references/core-hosting.md\">core-hosting</a></td>\n</tr>\n<tr>\n<td>Build with PDF</td>\n<td><code>download: true</code></td>\n<td><a href=\"references/build-pdf.md\">build-pdf</a></td>\n</tr>\n<tr>\n<td>Cache images</td>\n<td>Automatic for remote URLs</td>\n<td><a href=\"references/build-remote-assets.md\">build-remote-assets</a></td>\n</tr>\n<tr>\n<td>OG image</td>\n<td><code>seoMeta.ogImage</code> or <code>og-image.png</code></td>\n<td><a href=\"references/build-og-image.md\">build-og-image</a></td>\n</tr>\n<tr>\n<td>SEO tags</td>\n<td><code>seoMeta:</code></td>\n<td><a href=\"references/build-seo-meta.md\">build-seo-meta</a></td>\n</tr>\n</tbody></table>\n<p><strong>Export prerequisite</strong>: <code>pnpm add -D playwright-chromium</code> is required for PDF/PPTX/PNG export. If export fails with a browser error, install this dependency first.</p>\n<h4>Editor &amp; Tools</h4>\n<table>\n<thead>\n<tr>\n<th>Feature</th>\n<th>Usage</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Side editor</td>\n<td>Click edit icon</td>\n<td><a href=\"references/editor-side.md\">editor-side</a></td>\n</tr>\n<tr>\n<td>VS Code extension</td>\n<td>Install <code>antfu.slidev</code></td>\n<td><a href=\"references/editor-vscode.md\">editor-vscode</a></td>\n</tr>\n<tr>\n<td>Prettier</td>\n<td><code>prettier-plugin-slidev</code></td>\n<td><a href=\"references/editor-prettier.md\">editor-prettier</a></td>\n</tr>\n<tr>\n<td>Eject theme</td>\n<td><code>slidev theme eject</code></td>\n<td><a href=\"references/tool-eject-theme.md\">tool-eject-theme</a></td>\n</tr>\n</tbody></table>\n<h4>Lifecycle &amp; API</h4>\n<table>\n<thead>\n<tr>\n<th>Feature</th>\n<th>Usage</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Slide hooks</td>\n<td><code>onSlideEnter()</code>, <code>onSlideLeave()</code></td>\n<td><a href=\"references/api-slide-hooks.md\">api-slide-hooks</a></td>\n</tr>\n<tr>\n<td>Navigation API</td>\n<td><code>$nav</code>, <code>useNav()</code></td>\n<td><a href=\"references/core-global-context.md\">core-global-context</a></td>\n</tr>\n</tbody></table>\n<h3>Common Layouts</h3>\n<table>\n<thead>\n<tr>\n<th>Layout</th>\n<th>Purpose</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>cover</code></td>\n<td>Title/cover slide</td>\n</tr>\n<tr>\n<td><code>center</code></td>\n<td>Centered content</td>\n</tr>\n<tr>\n<td><code>default</code></td>\n<td>Standard slide</td>\n</tr>\n<tr>\n<td><code>two-cols</code></td>\n<td>Two columns (use <code>::right::</code>)</td>\n</tr>\n<tr>\n<td><code>two-cols-header</code></td>\n<td>Header + two columns</td>\n</tr>\n<tr>\n<td><code>image</code> / <code>image-left</code> / <code>image-right</code></td>\n<td>Image layouts</td>\n</tr>\n<tr>\n<td><code>iframe</code> / <code>iframe-left</code> / <code>iframe-right</code></td>\n<td>Embed URLs</td>\n</tr>\n<tr>\n<td><code>quote</code></td>\n<td>Quotation</td>\n</tr>\n<tr>\n<td><code>section</code></td>\n<td>Section divider</td>\n</tr>\n<tr>\n<td><code>fact</code> / <code>statement</code></td>\n<td>Data/statement display</td>\n</tr>\n<tr>\n<td><code>intro</code> / <code>end</code></td>\n<td>Intro/end slides</td>\n</tr>\n</tbody></table>\n<h3>Resources</h3>\n<ul>\n<li>Documentation: <a href=\"https://sli.dev\">https://sli.dev</a></li>\n<li>Theme Gallery: <a href=\"https://sli.dev/resources/theme-gallery\">https://sli.dev/resources/theme-gallery</a></li>\n<li>Showcases: <a href=\"https://sli.dev/resources/showcases\">https://sli.dev/resources/showcases</a></li>\n</ul>\n",
  "stock-report": "<h2>Stock Report</h2>\n<p>这个 skill 的目标很窄：<strong>给定一个 A 股标的名称或代码，用本仓库固定的 DS 数据采集链路拉数，并生成统一版式的 HTML 报告</strong>。<br>它不是泛化的股票分析 skill，也不是 MCP skill。这里的真源是：</p>\n<ul>\n<li><code>./cli-data-fetch-guide.md</code></li>\n<li><code>./scripts/fetch_and_generate_stock_report.py</code></li>\n<li><code>./scripts/generate_ds_report.py</code></li>\n</ul>\n<h3>何时使用</h3>\n<p>出现以下任一情况时，直接使用本 skill：</p>\n<ul>\n<li>用户说“生成某只股票的报告”</li>\n<li>用户给出股票名称或股票代码，希望直接出本仓库这套 HTML 报告</li>\n<li>用户要复跑现有报告、验证生成链路是否稳定</li>\n<li>用户要在批量化之前先单标的验证 DS 拉数 + 报告生成</li>\n</ul>\n<p>如果用户要的是：</p>\n<ul>\n<li>改报告样式/章节/图表逻辑：先用本 skill 找到真源脚本，再修改脚本</li>\n<li>改 DS CLI 本身：回到代码仓库，不要把 skill 当主场</li>\n<li>用 MCP 或其他数据源：不要用这个 skill</li>\n</ul>\n<h3>输入约定</h3>\n<p>支持两种输入：</p>\n<ul>\n<li>股票代码：如 <code>000728.SZ</code></li>\n<li>股票名称：如 <code>国元证券</code></li>\n</ul>\n<p>如果用户给的是中文名称，脚本会先执行：</p>\n<pre><code class=\"language-bash\">ds iid Stk search &quot;&lt;名称&gt;&quot; --output json\n</code></pre>\n<p>并先按 A 股主证券做精确匹配。<br>如果无法唯一确认标的，应该明确报错并要求用户提供 <code>000728.SZ</code> 这类准确 IID，不要猜测代码或直接取第一条。</p>\n<h3>环境前提</h3>\n<p>执行前默认检查：</p>\n<pre><code class=\"language-bash\">ds status\n</code></pre>\n<p>只有在以下条件满足时才继续：</p>\n<ul>\n<li><code>ds</code> 命令存在</li>\n<li>用户已登录，token 可用</li>\n<li><code>python3</code> 可执行</li>\n</ul>\n<p>如果 <code>ds status</code> 失败，先告诉用户是环境/登录问题，不要继续生成半成品。</p>\n<h3>标准执行步骤</h3>\n<h4>1. 识别标的</h4>\n<p>用 <code>ds iid Stk search &lt;标的名称&gt;</code> 确认标的的IID代码</p>\n<p>运行：</p>\n<pre><code class=\"language-bash\">python3 &lt;skill_path&gt;/scripts/fetch_and_generate_stock_report.py &quot;&lt;标的IID代码&gt;&quot;\n</code></pre>\n<p>这个脚本会自动做以下事情：</p>\n<ul>\n<li>创建仓库根目录下的 <code>data/&lt;股票代码&gt;/raw/</code></li>\n<li>按 skill 内 <code>cli-data-fetch-guide.md</code> 的固定专题清单抓取原始 JSON</li>\n<li>对“允许为空”的专题写空文件，而不是报错退出</li>\n<li>调用 skill 内 <code>scripts/generate_ds_report.py</code> 生成结构化 JSON 和 HTML 报告</li>\n<li>写出仓库根目录下的 <code>data/&lt;股票代码&gt;/run_summary.json</code></li>\n</ul>\n<h4>2. 固定查询范围</h4>\n<p>不要临场删改这套查询清单。当前固定覆盖：</p>\n<ul>\n<li>基本信息 <code>1000933</code></li>\n<li>实控人 <code>1000998</code></li>\n<li>高管薪酬 <code>1001034</code></li>\n<li>股本结构 <code>1000987</code></li>\n<li>解禁 <code>1001006</code></li>\n<li>十大股东 <code>1000991</code></li>\n<li>十大流通股东 <code>1000996</code></li>\n<li>股东户数 <code>1000183</code></li>\n<li>大股东持股比例 <code>1000989</code></li>\n<li>分红 <code>1000978</code></li>\n<li>年度资产负债表 <code>1000964</code></li>\n<li>年度利润表 <code>1000965</code></li>\n<li>年度现金流量表 <code>1000966</code></li>\n<li>季度利润表 <code>1000970</code></li>\n<li>季度现金流量表 <code>1000971</code></li>\n<li>主营业务构成 <code>1000961</code></li>\n<li>一致评级 <code>1001348/1001352/1001351/1001353</code></li>\n</ul>\n<p>其中以下专题允许无数据：</p>\n<ul>\n<li>实控人 <code>1000998</code></li>\n<li>解禁 <code>1001006</code></li>\n<li>分红 <code>1000978</code></li>\n<li>一致评级四个专题</li>\n</ul>\n<p>无数据时应保留空结果，并让最终报告明确显示“该标的暂无此类数据”，不要表述成抓取异常。</p>\n<h4>3. 生成结果</h4>\n<p>成功后，目标目录应至少包含：</p>\n<pre><code class=\"language-text\">data/&lt;股票代码&gt;/\n├── raw/\n├── basic_info.json\n├── financial_data.json\n├── shareholders.json\n├── data_sources.md\n├── run_summary.json\n└── report/\n    └── report.html\n</code></pre>\n<p>其中 <code>report.html</code> 是用户主要关心的产物。</p>\n<h3>报告契约</h3>\n<p>当前报告是固定 5 章结构：</p>\n<ol>\n<li>公司简介</li>\n<li>股本和股东</li>\n<li>财务数据</li>\n<li>主营业务行业数据</li>\n<li>一致评级</li>\n</ol>\n<p>关键约束：</p>\n<ul>\n<li>样式对齐 <code>data/601377/report/report.html</code> 和 <code>stock-analysis-report/template/report_template.html</code></li>\n<li>页面中不显示数据来源区块</li>\n<li>利润表、现金流量表支持年度/季度页内 Tab</li>\n<li>资产负债表只展示年度口径</li>\n<li>解禁/一致评级无数据时显示明确空状态</li>\n<li>分红有数据则展示图表，无数据则显示空状态</li>\n<li>“主营业务行业数据”里的业务观察与论证逻辑，不通过代码模板生成；应在报告文件生成完成后，由执行该 skill 的 agent 基于当次标的数据单独输出。</li>\n</ul>\n<h3>输出给用户时怎么说</h3>\n<p>默认简洁交付：</p>\n<ul>\n<li>报告路径</li>\n<li>关键生成文件路径</li>\n<li>是否存在“该标的暂无此类数据”的专题（如实控人/解禁/分红/一致评级）</li>\n<li>是否真的完成了脚本执行验证</li>\n</ul>\n<p>如果你没有实际运行生成，不要暗示已经生成成功。</p>\n<h3>故障处理</h3>\n<h4>1. <code>ds status</code> 失败</h4>\n<p>优先判断为环境或登录问题，提示用户先确认：</p>\n<ul>\n<li><code>ds</code> 是否安装</li>\n<li>是否已登录</li>\n<li>token 是否有效</li>\n</ul>\n<h4>2. <code>iid search</code> 没结果</h4>\n<p>直接报“未识别到标的”，让用户提供更准确名称或代码。</p>\n<h4>3. 单个专题返回“缺少数据集”</h4>\n<p>如果该专题属于允许为空的范围：</p>\n<ul>\n<li>写空文件</li>\n<li>继续后续流程</li>\n<li>最终报告显示空状态</li>\n</ul>\n<p>如果不属于允许为空范围：</p>\n<ul>\n<li>中止流程</li>\n<li>明确告诉用户是哪条专题失败</li>\n</ul>\n<h4>4. 生成脚本失败</h4>\n<p>先检查：</p>\n<ul>\n<li>raw 文件是否存在空文件以外的损坏内容</li>\n<li>标的目录是否创建成功</li>\n<li>Python 是否可执行</li>\n</ul>\n<p>不要手工改 HTML 兜底，优先修脚本真源。</p>\n<h3>真源文件</h3>\n<p>需要修改或排查时，优先看：</p>\n<ul>\n<li><code>./scripts/fetch_and_generate_stock_report.py</code>：一键采集入口</li>\n<li><code>./scripts/generate_ds_report.py</code>：HTML/JSON 生成逻辑</li>\n<li><code>./cli-data-fetch-guide.md</code>：DS 查询专题清单</li>\n</ul>\n<h3>示例</h3>\n<p><strong>示例 1：直接生成报告</strong></p>\n<p>输入：</p>\n<pre><code class=\"language-text\">给我生成国元证券的报告\n</code></pre>\n<p>执行：</p>\n<pre><code class=\"language-bash\">python3 &lt;skill_path&gt;/scripts/fetch_and_generate_stock_report.py &quot;国元证券&quot;\n</code></pre>\n<p><strong>示例 2：按代码重跑</strong></p>\n<p>输入：</p>\n<pre><code class=\"language-text\">重跑 000728.SZ 的报告\n</code></pre>\n<p>执行：</p>\n<pre><code class=\"language-bash\">python3 &lt;skill_path&gt;/scripts/fetch_and_generate_stock_report.py &quot;000728.SZ&quot;\n</code></pre>\n<h3>边界</h3>\n<ul>\n<li>不要把这个 skill 扩展成批量任务编排器；批量化另做</li>\n<li>不要自动切换到 MCP</li>\n<li>不要擅自改章节结构或报告样式</li>\n<li>不要跳过 DS 原始数据落盘直接生成报告</li>\n</ul>\n",
  "streamdown": "<h2>Streamdown</h2>\n<p>Streaming-optimized React Markdown renderer. Drop-in replacement for <code>react-markdown</code> with built-in streaming support, security, and interactive controls.</p>\n<h3>Quick Setup</h3>\n<h4>1. Install</h4>\n<pre><code class=\"language-bash\">npm install streamdown\n</code></pre>\n<p>Optional plugins (install only what&#39;s needed):</p>\n<pre><code class=\"language-bash\">npm install @streamdown/code @streamdown/mermaid @streamdown/math @streamdown/cjk\n</code></pre>\n<h4>2. Configure Tailwind CSS (Required)</h4>\n<p><strong>This is the most commonly missed step.</strong> Streamdown uses Tailwind for styling and the dist files must be scanned.</p>\n<p><strong>Tailwind v4</strong> — add to <code>globals.css</code>:</p>\n<pre><code class=\"language-css\">@source &quot;../node_modules/streamdown/dist/*.js&quot;;\n</code></pre>\n<p>Add plugin <code>@source</code> lines <strong>only for packages you have installed</strong> (omitting uninstalled plugins avoids Tailwind errors). See plugin pages for exact paths:</p>\n<ul>\n<li>Code: <code>@source &quot;../node_modules/@streamdown/code/dist/*.js&quot;;</code></li>\n<li>CJK: <code>@source &quot;../node_modules/@streamdown/cjk/dist/*.js&quot;;</code></li>\n<li>Math: <code>@source &quot;../node_modules/@streamdown/math/dist/*.js&quot;;</code></li>\n<li>Mermaid: <code>@source &quot;../node_modules/@streamdown/mermaid/dist/*.js&quot;;</code></li>\n</ul>\n<p><strong>Tailwind v3</strong> — add to <code>tailwind.config.js</code>:</p>\n<pre><code class=\"language-js\">module.exports = {\n  content: [\n    &quot;./app/**/*.{js,ts,jsx,tsx,mdx}&quot;,\n    &quot;./node_modules/streamdown/dist/*.js&quot;,\n  ],\n};\n</code></pre>\n<h4>3. Basic Usage</h4>\n<pre><code class=\"language-tsx\">import { Streamdown } from &#39;streamdown&#39;;\n\n&lt;Streamdown&gt;{markdown}&lt;/Streamdown&gt;\n</code></pre>\n<h4>4. With AI Streaming (Vercel AI SDK)</h4>\n<pre><code class=\"language-tsx\">&#39;use client&#39;;\nimport { useChat } from &#39;@ai-sdk/react&#39;;\nimport { Streamdown } from &#39;streamdown&#39;;\nimport { code } from &#39;@streamdown/code&#39;;\n\nexport default function Chat() {\n  const { messages, input, handleInputChange, handleSubmit, isLoading } = useChat();\n\n  return (\n    &lt;&gt;\n      {messages.map((msg, i) =&gt; (\n        &lt;Streamdown\n          key={msg.id}\n          plugins={{ code }}\n          caret=&quot;block&quot;\n          isAnimating={isLoading &amp;&amp; i === messages.length - 1 &amp;&amp; msg.role === &#39;assistant&#39;}\n        &gt;\n          {msg.content}\n        &lt;/Streamdown&gt;\n      ))}\n      &lt;form onSubmit={handleSubmit}&gt;\n        &lt;input value={input} onChange={handleInputChange} disabled={isLoading} /&gt;\n      &lt;/form&gt;\n    &lt;/&gt;\n  );\n}\n</code></pre>\n<h4>5. Static Mode (Blogs, Docs)</h4>\n<pre><code class=\"language-tsx\">&lt;Streamdown mode=&quot;static&quot; plugins={{ code }}&gt;\n  {content}\n&lt;/Streamdown&gt;\n</code></pre>\n<h3>Key Props</h3>\n<table>\n<thead>\n<tr>\n<th>Prop</th>\n<th>Type</th>\n<th>Default</th>\n<th>Purpose</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>children</code></td>\n<td><code>string</code></td>\n<td>—</td>\n<td>Markdown content</td>\n</tr>\n<tr>\n<td><code>mode</code></td>\n<td><code>&quot;streaming&quot; | &quot;static&quot;</code></td>\n<td><code>&quot;streaming&quot;</code></td>\n<td>Rendering mode</td>\n</tr>\n<tr>\n<td><code>plugins</code></td>\n<td><code>{ code?, mermaid?, math?, cjk? }</code></td>\n<td>—</td>\n<td>Feature plugins</td>\n</tr>\n<tr>\n<td><code>isAnimating</code></td>\n<td><code>boolean</code></td>\n<td><code>false</code></td>\n<td>Streaming indicator</td>\n</tr>\n<tr>\n<td><code>caret</code></td>\n<td><code>&quot;block&quot; | &quot;circle&quot;</code></td>\n<td>—</td>\n<td>Cursor style</td>\n</tr>\n<tr>\n<td><code>components</code></td>\n<td><code>Components</code></td>\n<td>—</td>\n<td>Custom element overrides</td>\n</tr>\n<tr>\n<td><code>controls</code></td>\n<td><code>boolean | object</code></td>\n<td><code>true</code></td>\n<td>Interactive buttons</td>\n</tr>\n<tr>\n<td><code>linkSafety</code></td>\n<td><code>LinkSafetyConfig</code></td>\n<td><code>{ enabled: true }</code></td>\n<td>Link confirmation modal</td>\n</tr>\n<tr>\n<td><code>shikiTheme</code></td>\n<td><code>[light, dark]</code></td>\n<td><code>[&#39;github-light&#39;, &#39;github-dark&#39;]</code></td>\n<td>Code themes</td>\n</tr>\n<tr>\n<td><code>className</code></td>\n<td><code>string</code></td>\n<td>—</td>\n<td>Container class</td>\n</tr>\n<tr>\n<td><code>allowedElements</code></td>\n<td><code>string[]</code></td>\n<td>all</td>\n<td>Tag names to allow</td>\n</tr>\n<tr>\n<td><code>disallowedElements</code></td>\n<td><code>string[]</code></td>\n<td><code>[]</code></td>\n<td>Tag names to disallow</td>\n</tr>\n<tr>\n<td><code>allowElement</code></td>\n<td><code>AllowElement</code></td>\n<td>—</td>\n<td>Custom element filter</td>\n</tr>\n<tr>\n<td><code>unwrapDisallowed</code></td>\n<td><code>boolean</code></td>\n<td><code>false</code></td>\n<td>Keep children of disallowed elements</td>\n</tr>\n<tr>\n<td><code>skipHtml</code></td>\n<td><code>boolean</code></td>\n<td><code>false</code></td>\n<td>Ignore raw HTML</td>\n</tr>\n<tr>\n<td><code>urlTransform</code></td>\n<td><code>UrlTransform</code></td>\n<td><code>defaultUrlTransform</code></td>\n<td>Transform/sanitize URLs</td>\n</tr>\n</tbody></table>\n<p>For full API reference, see <a href=\"references/api.md\">references/api.md</a>.</p>\n<h3>Plugin Quick Reference</h3>\n<table>\n<thead>\n<tr>\n<th>Plugin</th>\n<th>Package</th>\n<th>Purpose</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Code</td>\n<td><code>@streamdown/code</code></td>\n<td>Syntax highlighting (Shiki, 200+ languages)</td>\n</tr>\n<tr>\n<td>Mermaid</td>\n<td><code>@streamdown/mermaid</code></td>\n<td>Diagrams (flowcharts, sequence, etc.)</td>\n</tr>\n<tr>\n<td>Math</td>\n<td><code>@streamdown/math</code></td>\n<td>LaTeX via KaTeX (requires CSS import)</td>\n</tr>\n<tr>\n<td>CJK</td>\n<td><code>@streamdown/cjk</code></td>\n<td>Chinese/Japanese/Korean text support</td>\n</tr>\n</tbody></table>\n<p><strong>Math requires CSS:</strong></p>\n<pre><code class=\"language-tsx\">import &#39;katex/dist/katex.min.css&#39;;\n</code></pre>\n<p>For plugin configuration details, see <a href=\"references/plugins.md\">references/plugins.md</a>.</p>\n<h3>References</h3>\n<p>Use these for deeper implementation details:</p>\n<ul>\n<li><strong><a href=\"references/api.md\">references/api.md</a></strong> — Complete props, types, and interfaces</li>\n<li><strong><a href=\"references/plugins.md\">references/plugins.md</a></strong> — Plugin setup, configuration, and customization</li>\n<li><strong><a href=\"references/styling.md\">references/styling.md</a></strong> — CSS variables, data attributes, custom components, theme examples</li>\n<li><strong><a href=\"references/security.md\">references/security.md</a></strong> — Hardening, link safety, custom HTML tags, production config</li>\n<li><strong><a href=\"references/features.md\">references/features.md</a></strong> — Carets, remend, static mode, controls, GFM, memoization, troubleshooting</li>\n</ul>\n<h3>Example Configurations</h3>\n<p>Copy and adapt from <code>assets/examples/</code>:</p>\n<ul>\n<li><strong><a href=\"assets/examples/basic-streaming.tsx\">basic-streaming.tsx</a></strong> — Minimal AI chat with Vercel AI SDK</li>\n<li><strong><a href=\"assets/examples/with-caret.tsx\">with-caret.tsx</a></strong> — Streaming with block caret cursor</li>\n<li><strong><a href=\"assets/examples/full-featured.tsx\">full-featured.tsx</a></strong> — All plugins, carets, link safety, controls</li>\n<li><strong><a href=\"assets/examples/static-mode.tsx\">static-mode.tsx</a></strong> — Blog/docs rendering</li>\n<li><strong><a href=\"assets/examples/custom-security.tsx\">custom-security.tsx</a></strong> — Strict security for AI content</li>\n</ul>\n<h3>Common Gotchas</h3>\n<ol>\n<li><strong>Tailwind styles missing</strong> — Add <code>@source</code> directive or <code>content</code> entry for <code>node_modules/streamdown/dist/*.js</code></li>\n<li><strong>Math not rendering</strong> — Import <code>katex/dist/katex.min.css</code></li>\n<li><strong>Caret not showing</strong> — Both <code>caret</code> prop AND <code>isAnimating={true}</code> are required</li>\n<li><strong>Copy buttons during streaming</strong> — Disabled automatically when <code>isAnimating={true}</code></li>\n<li><strong>Link safety modal appearing</strong> — Enabled by default; disable with <code>linkSafety={{ enabled: false }}</code></li>\n<li><strong>Shiki warning in Next.js</strong> — Install <code>shiki</code> explicitly, add to <code>transpilePackages</code></li>\n<li><strong><code>allowedTags</code> not working</strong> — Only works with default rehype plugins</li>\n<li><strong>Math uses <code>$$</code> not <code>$</code></strong> — Single dollar is disabled by default to avoid currency conflicts</li>\n</ol>\n",
  "use-modern-go": "<h2>Modern Go Guidelines</h2>\n<h3>Detected Go Version</h3>\n<p>!<code>grep -rh &quot;^go &quot; --include=&quot;go.mod&quot; . 2&gt;/dev/null | cut -d&#39; &#39; -f2 | sort | uniq -c | sort -nr | head -1 | xargs | cut -d&#39; &#39; -f2 | grep . || echo unknown</code></p>\n<h3>How to Use This Skill</h3>\n<p>DO NOT search for go.mod files or try to detect the version yourself. Use ONLY the version shown above.</p>\n<p><strong>If version detected (not &quot;unknown&quot;):</strong></p>\n<ul>\n<li>Say: &quot;This project is using Go X.XX, so I’ll stick to modern Go best practices and freely use language features up to and including this version. If you’d prefer a different target version, just let me know.&quot;</li>\n<li>Do NOT list features, do NOT ask for confirmation</li>\n</ul>\n<p><strong>If version is &quot;unknown&quot;:</strong></p>\n<ul>\n<li>Say: &quot;Could not detect Go version in this repository&quot;</li>\n<li>Use AskUserQuestion: &quot;Which Go version should I target?&quot; → [1.23] / [1.24] / [1.25] / [1.26]</li>\n</ul>\n<p><strong>When writing Go code</strong>, use ALL features from this document up to the target version:</p>\n<ul>\n<li>Prefer modern built-ins and packages (<code>slices</code>, <code>maps</code>, <code>cmp</code>) over legacy patterns</li>\n<li>Never use features from newer Go versions than the target</li>\n<li>Never use outdated patterns when a modern alternative is available</li>\n</ul>\n<hr>\n<h3>Features by Go Version</h3>\n<h4>Go 1.0+</h4>\n<ul>\n<li><code>time.Since</code>: <code>time.Since(start)</code> instead of <code>time.Now().Sub(start)</code></li>\n</ul>\n<h4>Go 1.8+</h4>\n<ul>\n<li><code>time.Until</code>: <code>time.Until(deadline)</code> instead of <code>deadline.Sub(time.Now())</code></li>\n</ul>\n<h4>Go 1.13+</h4>\n<ul>\n<li><code>errors.Is</code>: <code>errors.Is(err, target)</code> instead of <code>err == target</code> (works with wrapped errors)</li>\n</ul>\n<h4>Go 1.18+</h4>\n<ul>\n<li><code>any</code>: Use <code>any</code> instead of <code>interface{}</code></li>\n<li><code>bytes.Cut</code>: <code>before, after, found := bytes.Cut(b, sep)</code> instead of Index+slice</li>\n<li><code>strings.Cut</code>: <code>before, after, found := strings.Cut(s, sep)</code></li>\n</ul>\n<h4>Go 1.19+</h4>\n<ul>\n<li><code>fmt.Appendf</code>: <code>buf = fmt.Appendf(buf, &quot;x=%d&quot;, x)</code> instead of <code>[]byte(fmt.Sprintf(...))</code></li>\n<li><code>atomic.Bool</code>/<code>atomic.Int64</code>/<code>atomic.Pointer[T]</code>: Type-safe atomics instead of <code>atomic.StoreInt32</code></li>\n</ul>\n<pre><code class=\"language-go\">var flag atomic.Bool\nflag.Store(true)\nif flag.Load() { ... }\n\nvar ptr atomic.Pointer[Config]\nptr.Store(cfg)\n</code></pre>\n<h4>Go 1.20+</h4>\n<ul>\n<li><code>strings.Clone</code>: <code>strings.Clone(s)</code> to copy string without sharing memory</li>\n<li><code>bytes.Clone</code>: <code>bytes.Clone(b)</code> to copy byte slice</li>\n<li><code>strings.CutPrefix/CutSuffix</code>: <code>if rest, ok := strings.CutPrefix(s, &quot;pre:&quot;); ok { ... }</code></li>\n<li><code>errors.Join</code>: <code>errors.Join(err1, err2)</code> to combine multiple errors</li>\n<li><code>context.WithCancelCause</code>: <code>ctx, cancel := context.WithCancelCause(parent)</code> then <code>cancel(err)</code></li>\n<li><code>context.Cause</code>: <code>context.Cause(ctx)</code> to get the error that caused cancellation</li>\n</ul>\n<h4>Go 1.21+</h4>\n<p><strong>Built-ins:</strong></p>\n<ul>\n<li><code>min</code>/<code>max</code>: <code>max(a, b)</code> instead of if/else comparisons</li>\n<li><code>clear</code>: <code>clear(m)</code> to delete all map entries, <code>clear(s)</code> to zero slice elements</li>\n</ul>\n<p><strong>slices package:</strong></p>\n<ul>\n<li><code>slices.Contains</code>: <code>slices.Contains(items, x)</code> instead of manual loops</li>\n<li><code>slices.Index</code>: <code>slices.Index(items, x)</code> returns index (-1 if not found)</li>\n<li><code>slices.IndexFunc</code>: <code>slices.IndexFunc(items, func(item T) bool { return item.ID == id })</code></li>\n<li><code>slices.SortFunc</code>: <code>slices.SortFunc(items, func(a, b T) int { return cmp.Compare(a.X, b.X) })</code></li>\n<li><code>slices.Sort</code>: <code>slices.Sort(items)</code> for ordered types</li>\n<li><code>slices.Max</code>/<code>slices.Min</code>: <code>slices.Max(items)</code> instead of manual loop</li>\n<li><code>slices.Reverse</code>: <code>slices.Reverse(items)</code> instead of manual swap loop</li>\n<li><code>slices.Compact</code>: <code>slices.Compact(items)</code> removes consecutive duplicates in-place</li>\n<li><code>slices.Clip</code>: <code>slices.Clip(s)</code> removes unused capacity</li>\n<li><code>slices.Clone</code>: <code>slices.Clone(s)</code> creates a copy</li>\n</ul>\n<p><strong>maps package:</strong></p>\n<ul>\n<li><code>maps.Clone</code>: <code>maps.Clone(m)</code> instead of manual map iteration</li>\n<li><code>maps.Copy</code>: <code>maps.Copy(dst, src)</code> copies entries from src to dst</li>\n<li><code>maps.DeleteFunc</code>: <code>maps.DeleteFunc(m, func(k K, v V) bool { return condition })</code></li>\n</ul>\n<p><strong>sync package:</strong></p>\n<ul>\n<li><code>sync.OnceFunc</code>: <code>f := sync.OnceFunc(func() { ... })</code> instead of <code>sync.Once</code> + wrapper</li>\n<li><code>sync.OnceValue</code>: <code>getter := sync.OnceValue(func() T { return computeValue() })</code></li>\n</ul>\n<p><strong>context package:</strong></p>\n<ul>\n<li><code>context.AfterFunc</code>: <code>stop := context.AfterFunc(ctx, cleanup)</code> runs cleanup on cancellation</li>\n<li><code>context.WithTimeoutCause</code>: <code>ctx, cancel := context.WithTimeoutCause(parent, d, err)</code></li>\n<li><code>context.WithDeadlineCause</code>: Similar with deadline instead of duration</li>\n</ul>\n<h4>Go 1.22+</h4>\n<p><strong>Loops:</strong></p>\n<ul>\n<li><code>for i := range n</code>: <code>for i := range len(items)</code> instead of <code>for i := 0; i &lt; len(items); i++</code></li>\n<li>Loop variables are now safe to capture in goroutines (each iteration has its own copy)</li>\n</ul>\n<p><strong>cmp package:</strong></p>\n<ul>\n<li><code>cmp.Or</code>: <code>cmp.Or(flag, env, config, &quot;default&quot;)</code> returns first non-zero value</li>\n</ul>\n<pre><code class=\"language-go\">// Instead of:\nname := os.Getenv(&quot;NAME&quot;)\nif name == &quot;&quot; {\n    name = &quot;default&quot;\n}\n// Use:\nname := cmp.Or(os.Getenv(&quot;NAME&quot;), &quot;default&quot;)\n</code></pre>\n<p><strong>reflect package:</strong></p>\n<ul>\n<li><code>reflect.TypeFor</code>: <code>reflect.TypeFor[T]()</code> instead of <code>reflect.TypeOf((*T)(nil)).Elem()</code></li>\n</ul>\n<p><strong>net/http:</strong></p>\n<ul>\n<li>Enhanced <code>http.ServeMux</code> patterns: <code>mux.HandleFunc(&quot;GET /api/{id}&quot;, handler)</code> with method and path params</li>\n<li><code>r.PathValue(&quot;id&quot;)</code> to get path parameters</li>\n</ul>\n<h4>Go 1.23+</h4>\n<ul>\n<li><code>maps.Keys(m)</code> / <code>maps.Values(m)</code> return iterators</li>\n<li><code>slices.Collect(iter)</code> not manual loop to build slice from iterator</li>\n<li><code>slices.Sorted(iter)</code> to collect and sort in one step</li>\n</ul>\n<pre><code class=\"language-go\">keys := slices.Collect(maps.Keys(m))       // not: for k := range m { keys = append(keys, k) }\nsortedKeys := slices.Sorted(maps.Keys(m))  // collect + sort\nfor k := range maps.Keys(m) { process(k) } // iterate directly\n</code></pre>\n<p><strong>time package</strong></p>\n<ul>\n<li><code>time.Tick</code>: Use <code>time.Tick</code> freely — as of Go 1.23, the garbage collector can recover unreferenced tickers, even if they haven&#39;t been stopped. The Stop method is no longer necessary to help the garbage collector. There is no longer any reason to prefer NewTicker when Tick will do.</li>\n</ul>\n<h4>Go 1.24+</h4>\n<ul>\n<li><code>t.Context()</code> not <code>context.WithCancel(context.Background())</code> in tests.\nALWAYS use t.Context() when a test function needs a context.</li>\n</ul>\n<p>Before:</p>\n<pre><code class=\"language-go\">func TestFoo(t *testing.T) {\n    ctx, cancel := context.WithCancel(context.Background())\n    defer cancel()\n    result := doSomething(ctx)\n}\n</code></pre>\n<p>After:</p>\n<pre><code class=\"language-go\">func TestFoo(t *testing.T) {\n    ctx := t.Context()\n    result := doSomething(ctx)\n}\n</code></pre>\n<ul>\n<li><code>omitzero</code> not <code>omitempty</code> in JSON struct tags.\nALWAYS use omitzero for time.Duration, time.Time, structs, slices, maps.</li>\n</ul>\n<p>Before:</p>\n<pre><code class=\"language-go\">type Config struct {\n    Timeout time.Duration `json:&quot;timeout,omitempty&quot;` // doesn&#39;t work for Duration!\n}\n</code></pre>\n<p>After:</p>\n<pre><code class=\"language-go\">type Config struct {\n    Timeout time.Duration `json:&quot;timeout,omitzero&quot;`\n}\n</code></pre>\n<ul>\n<li><code>b.Loop()</code> not <code>for i := 0; i &lt; b.N; i++</code> in benchmarks.\nALWAYS use b.Loop() for the main loop in benchmark functions.</li>\n</ul>\n<p>Before:</p>\n<pre><code class=\"language-go\">func BenchmarkFoo(b *testing.B) {\n    for i := 0; i &lt; b.N; i++ {\n        doWork()\n    }\n}\n</code></pre>\n<p>After:</p>\n<pre><code class=\"language-go\">func BenchmarkFoo(b *testing.B) {\n    for b.Loop() {\n        doWork()\n    }\n}\n</code></pre>\n<ul>\n<li><code>strings.SplitSeq</code> not <code>strings.Split</code> when iterating.\nALWAYS use SplitSeq/FieldsSeq when iterating over split results in a for-range loop.</li>\n</ul>\n<p>Before:</p>\n<pre><code class=\"language-go\">for _, part := range strings.Split(s, &quot;,&quot;) {\n    process(part)\n}\n</code></pre>\n<p>After:</p>\n<pre><code class=\"language-go\">for part := range strings.SplitSeq(s, &quot;,&quot;) {\n    process(part)\n}\n</code></pre>\n<p>Also: <code>strings.FieldsSeq</code>, <code>bytes.SplitSeq</code>, <code>bytes.FieldsSeq</code>.</p>\n<h4>Go 1.25+</h4>\n<ul>\n<li><code>wg.Go(fn)</code> not <code>wg.Add(1)</code> + <code>go func() { defer wg.Done(); ... }()</code>.\nALWAYS use wg.Go() when spawning goroutines with sync.WaitGroup.</li>\n</ul>\n<p>Before:</p>\n<pre><code class=\"language-go\">var wg sync.WaitGroup\nfor _, item := range items {\n    wg.Add(1)\n    go func() {\n        defer wg.Done()\n        process(item)\n    }()\n}\nwg.Wait()\n</code></pre>\n<p>After:</p>\n<pre><code class=\"language-go\">var wg sync.WaitGroup\nfor _, item := range items {\n    wg.Go(func() {\n        process(item)\n    })\n}\nwg.Wait()\n</code></pre>\n<h4>Go 1.26+</h4>\n<ul>\n<li><code>new(val)</code> not <code>x := val; &amp;x</code> — returns pointer to any value.\nGo 1.26 extends new() to accept expressions, not just types.\nType is inferred: new(0) → *int, new(&quot;s&quot;) → *string, new(T{}) → *T.\nDO NOT use <code>x := val; &amp;x</code> pattern — always use new(val) directly.\nDO NOT use redundant casts like new(int(0)) — just write new(0).\nCommon use case: struct fields with pointer types.</li>\n</ul>\n<p>Before:</p>\n<pre><code class=\"language-go\">timeout := 30\ndebug := true\ncfg := Config{\n    Timeout: &amp;timeout,\n    Debug:   &amp;debug,\n}\n</code></pre>\n<p>After:</p>\n<pre><code class=\"language-go\">cfg := Config{\n    Timeout: new(30),   // *int\n    Debug:   new(true), // *bool\n}\n</code></pre>\n<ul>\n<li><code>errors.AsType[T](err)</code> not <code>errors.As(err, &amp;target)</code>.\nALWAYS use errors.AsType when checking if error matches a specific type.</li>\n</ul>\n<p>Before:</p>\n<pre><code class=\"language-go\">var pathErr *os.PathError\nif errors.As(err, &amp;pathErr) {\n    handle(pathErr)\n}\n</code></pre>\n<p>After:</p>\n<pre><code class=\"language-go\">if pathErr, ok := errors.AsType[*os.PathError](err); ok {\n    handle(pathErr)\n}\n</code></pre>\n",
  "vitest": "<p>Vitest is a next-generation testing framework powered by Vite. It provides a Jest-compatible API with native ESM, TypeScript, and JSX support out of the box. Vitest shares the same config, transformers, resolvers, and plugins with your Vite app.</p>\n<p><strong>Key Features:</strong></p>\n<ul>\n<li>Vite-native: Uses Vite&#39;s transformation pipeline for fast HMR-like test updates</li>\n<li>Jest-compatible: Drop-in replacement for most Jest test suites</li>\n<li>Smart watch mode: Only reruns affected tests based on module graph</li>\n<li>Native ESM, TypeScript, JSX support without configuration</li>\n<li>Multi-threaded workers for parallel test execution</li>\n<li>Built-in coverage via V8 or Istanbul</li>\n<li>Snapshot testing, mocking, and spy utilities</li>\n</ul>\n<blockquote>\n<p>The skill is based on Vitest 3.x, generated at 2026-01-28.</p>\n</blockquote>\n<h3>Core</h3>\n<table>\n<thead>\n<tr>\n<th>Topic</th>\n<th>Description</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Configuration</td>\n<td>Vitest and Vite config integration, defineConfig usage</td>\n<td><a href=\"references/core-config.md\">core-config</a></td>\n</tr>\n<tr>\n<td>CLI</td>\n<td>Command line interface, commands and options</td>\n<td><a href=\"references/core-cli.md\">core-cli</a></td>\n</tr>\n<tr>\n<td>Test API</td>\n<td>test/it function, modifiers like skip, only, concurrent</td>\n<td><a href=\"references/core-test-api.md\">core-test-api</a></td>\n</tr>\n<tr>\n<td>Describe API</td>\n<td>describe/suite for grouping tests and nested suites</td>\n<td><a href=\"references/core-describe.md\">core-describe</a></td>\n</tr>\n<tr>\n<td>Expect API</td>\n<td>Assertions with toBe, toEqual, matchers and asymmetric matchers</td>\n<td><a href=\"references/core-expect.md\">core-expect</a></td>\n</tr>\n<tr>\n<td>Hooks</td>\n<td>beforeEach, afterEach, beforeAll, afterAll, aroundEach</td>\n<td><a href=\"references/core-hooks.md\">core-hooks</a></td>\n</tr>\n</tbody></table>\n<h3>Features</h3>\n<table>\n<thead>\n<tr>\n<th>Topic</th>\n<th>Description</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Mocking</td>\n<td>Mock functions, modules, timers, dates with vi utilities</td>\n<td><a href=\"references/features-mocking.md\">features-mocking</a></td>\n</tr>\n<tr>\n<td>Snapshots</td>\n<td>Snapshot testing with toMatchSnapshot and inline snapshots</td>\n<td><a href=\"references/features-snapshots.md\">features-snapshots</a></td>\n</tr>\n<tr>\n<td>Coverage</td>\n<td>Code coverage with V8 or Istanbul providers</td>\n<td><a href=\"references/features-coverage.md\">features-coverage</a></td>\n</tr>\n<tr>\n<td>Test Context</td>\n<td>Test fixtures, context.expect, test.extend for custom fixtures</td>\n<td><a href=\"references/features-context.md\">features-context</a></td>\n</tr>\n<tr>\n<td>Concurrency</td>\n<td>Concurrent tests, parallel execution, sharding</td>\n<td><a href=\"references/features-concurrency.md\">features-concurrency</a></td>\n</tr>\n<tr>\n<td>Filtering</td>\n<td>Filter tests by name, file patterns, tags</td>\n<td><a href=\"references/features-filtering.md\">features-filtering</a></td>\n</tr>\n</tbody></table>\n<h3>Advanced</h3>\n<table>\n<thead>\n<tr>\n<th>Topic</th>\n<th>Description</th>\n<th>Reference</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Vi Utilities</td>\n<td>vi helper: mock, spyOn, fake timers, hoisted, waitFor</td>\n<td><a href=\"references/advanced-vi.md\">advanced-vi</a></td>\n</tr>\n<tr>\n<td>Environments</td>\n<td>Test environments: node, jsdom, happy-dom, custom</td>\n<td><a href=\"references/advanced-environments.md\">advanced-environments</a></td>\n</tr>\n<tr>\n<td>Type Testing</td>\n<td>Type-level testing with expectTypeOf and assertType</td>\n<td><a href=\"references/advanced-type-testing.md\">advanced-type-testing</a></td>\n</tr>\n<tr>\n<td>Projects</td>\n<td>Multi-project workspaces, different configs per project</td>\n<td><a href=\"references/advanced-projects.md\">advanced-projects</a></td>\n</tr>\n</tbody></table>\n",
  "web-design-guidelines": "<h2>Web Interface Guidelines</h2>\n<p>Review files for compliance with Web Interface Guidelines.</p>\n<h3>How It Works</h3>\n<ol>\n<li>Fetch the latest guidelines from the source URL below</li>\n<li>Read the specified files (or prompt user for files/pattern)</li>\n<li>Check against all rules in the fetched guidelines</li>\n<li>Output findings in the terse <code>file:line</code> format</li>\n</ol>\n<h3>Guidelines Source</h3>\n<p>Fetch fresh guidelines before each review:</p>\n<pre><code>https://raw.githubusercontent.com/vercel-labs/web-interface-guidelines/main/command.md\n</code></pre>\n<p>Use WebFetch to retrieve the latest rules. The fetched content contains all the rules and output format instructions.</p>\n<h3>Usage</h3>\n<p>When a user provides a file or pattern argument:</p>\n<ol>\n<li>Fetch guidelines from the source URL above</li>\n<li>Read the specified files</li>\n<li>Apply all rules from the fetched guidelines</li>\n<li>Output findings using the format specified in the guidelines</li>\n</ol>\n<p>If no files specified, ask the user which files to review.</p>\n"
};
